-- Poems batch 79
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e9ea694d-7c3e-46ba-a8e5-42ff04b83dff','偈頌二百零五首  其一九七','釋正覺','宋','宋诗','song-poetry','','[]','清白傳家雪月光，玉壺中有轉身方。',32,'全唐诗/poet.song.101000.json','["清白傳家雪月光，玉壺中有轉身方。", "情乾識盡功勳斷，不覺全身入帝鄉。"]'),
('ad4971c2-5c4e-46ff-9e31-90d47bbb4bf5','偈頌二百零五首  其一九八','釋正覺','宋','宋诗','song-poetry','','[]','一著能回一局棋，仙即妙處只些兒。',64,'全唐诗/poet.song.101000.json','["一著能回一局棋，仙即妙處只些兒。", "點開活眼分生殺，不作窮忙死馬醫。", "倒却門前剎竿著，一把推出誰藏縮。", "工夫磨琢老成人，圓陀陀地無稜角。"]'),
('9371e6b1-19d9-43fc-95df-1f71be1408d3','偈頌二百零五首  其一九九','釋正覺','宋','宋诗','song-poetry','','[]','一燈分耀百千燈，箇事宗家誰也曾。',32,'全唐诗/poet.song.101000.json','["一燈分耀百千燈，箇事宗家誰也曾。", "少室相傳斷臂可，黄梅分付墜腰能。"]'),
('79c9e39c-9805-467d-8c7f-238cabda07b1','偈頌二百零五首  其二○○','釋正覺','宋','宋诗','song-poetry','','[]','聞說英雄苦戰爭，四方歧路自難行。',32,'全唐诗/poet.song.101000.json','["聞說英雄苦戰爭，四方歧路自難行。", "而今踏著長安道，始信家邦久太平。"]'),
('ab94356d-0955-479c-afc8-5004cc0419fb','偈頌二百零五首  其二○一','釋正覺','宋','宋诗','song-poetry','','[]','曾到家山裏許看，星河濯月霽天寒。',32,'全唐诗/poet.song.101000.json','["曾到家山裏許看，星河濯月霽天寒。", "箇時失却娘生口，始信從來鼻孔寬。"]'),
('9ee46598-57f1-4908-afee-e80a675f9277','偈頌二百零五首  其二○二','釋正覺','宋','宋诗','song-poetry','','[]','演出一大藏，明明超過諸緣上。',34,'全唐诗/poet.song.101000.json','["演出一大藏，明明超過諸緣上。", "隨曲隨直也流水轉山，隨高隨下也虛舟駕浪。"]'),
('0683b57b-b38a-4d8e-823a-eec5e7172d9f','偈頌二百零五首  其二○三','釋正覺','宋','宋诗','song-poetry','','[]','靈雲悟桃華，玄沙旁不肯。',48,'全唐诗/poet.song.101000.json','["靈雲悟桃華，玄沙旁不肯。", "昭昭然此心分明，隱隱也放身未穩。", "放得穩，八兩元來是半斤，鈎頭秤尾能平等。"]'),
('19c223a7-c873-4b8f-89b0-b8202a988eea','偈頌二百零五首  其二○四','釋正覺','宋','宋诗','song-poetry','','[]','一物長靈，十方普應。',68,'全唐诗/poet.song.101000.json','["一物長靈，十方普應。", "騎聲跨色，超眺越聽。", "浩浩也能縱能橫，如如也能動能靜。", "參飽叢林箇樣人，取飯不問誰家甑。", "佛云常乞是清規，一切食中斯正命。"]'),
('bb52245c-3966-40d9-82ea-a475c2d5235d','偈頌二百零五首  其二○五','釋正覺','宋','宋诗','song-poetry','','[]','一雨霑濡，諸根萌動。',54,'全唐诗/poet.song.101000.json','["一雨霑濡，諸根萌動。", "青黄各成其姿，長短各隨其用。", "綿綿也妙有機絲，混混也廓無稜縫。", "若人問我如何，敢道不快漆桶。"]'),
('846a0126-7cda-4daa-a94a-be570409844c','偈頌二百零五首  其二○六','釋正覺','宋','宋诗','song-poetry','','[]','若於一切法上通，身去亦是有所得。',32,'全唐诗/poet.song.101000.json','["若於一切法上通，身去亦是有所得。", "若於一切用處豁，落去亦是有所得。"]'),
('722153c3-5c53-49b6-b6e3-6ed48a02678f','偈頌二百零五首  其二○七','釋正覺','宋','宋诗','song-poetry','','[]','心心智通，佛佛道同。',195,'全唐诗/poet.song.101000.json','["心心智通，佛佛道同。", "十方圓滿，八面玲瓏。", "施時也三乘教備，坐處也一切法空。", "應供而來有不受之受，度世而出得無功之功。", "動而常靜，用時彌沖。", "處處不乖兮水中夜月，物物斯應兮華上春風。", "因緣和合而生，生不可生生。", "影生於形，響生於聲。", "森羅萬像從崢嶸，虛空廓落無虧盈。", "杳杳冥冥，靈靈明明。", "是其中之精，非其外之情。", "見本家曠古之佛，得自己廣大之經。", "湛兮若存無迹像，善惡不我相隨行。", "物物現成觀自在，人人具足常不輕。"]'),
('db6aacac-7f87-4a4f-a7da-c0bebc4bf193','偈十首  其一','釋正覺','宋','宋诗','song-poetry','','[]','即此見聞非見聞，更無聲色可呈君。',32,'全唐诗/poet.song.101000.json','["即此見聞非見聞，更無聲色可呈君。", "箇中若了全無事，體用何妨分不分。"]'),
('a7f9876b-5820-4230-b252-f9cd02007cc7','偈十首  其二','釋正覺','宋','宋诗','song-poetry','','[]','萬法是心光，諸緣唯性曉。',34,'全唐诗/poet.song.101000.json','["萬法是心光，諸緣唯性曉。", "本無迷悟人，只要今日了。", "心無形影，對緣即照。"]'),
('e6df4212-f516-418f-bb77-f24f8c842df0','偈十首  其三','釋正覺','宋','宋诗','song-poetry','','[]','男子身中入正定，女子身中從定起。',44,'全唐诗/poet.song.101000.json','["男子身中入正定，女子身中從定起。", "一塵入正受，諸塵三昧起。", "展翅奔騰六合雲，摶風鼓蕩四溟水。"]'),
('4a299f2e-ce1d-4743-a7ad-4683d2c5f21e','偈十首  其四','釋正覺','宋','宋诗','song-poetry','','[]','心是根，法是塵，兩種猶如鏡上痕。',32,'全唐诗/poet.song.101000.json','["心是根，法是塵，兩種猶如鏡上痕。", "塵垢盡時光始現，心法雙忘性即真。"]'),
('9c74ba8b-0ac5-4410-9f04-323348364172','偈十首  其五','釋正覺','宋','宋诗','song-poetry','','[]','牢籠不肯住，呼喚不回頭。',24,'全唐诗/poet.song.101000.json','["牢籠不肯住，呼喚不回頭。", "古聖不安排，至今無處所。"]'),
('820ad6b5-06f8-4577-b05b-4e8e5993293a','偈十首  其六','釋正覺','宋','宋诗','song-poetry','','[]','萬像之中獨露身，唯人自肯乃方親。',32,'全唐诗/poet.song.101000.json','["萬像之中獨露身，唯人自肯乃方親。", "昔年謬向途中覓，今日觀來火裏冰。"]'),
('063afbad-f501-4980-ab39-d4f407af8e23','偈十首  其七','釋正覺','宋','宋诗','song-poetry','','[]','交互明中暗，功齊轉覺難。',24,'全唐诗/poet.song.101000.json','["交互明中暗，功齊轉覺難。", "力窮忘進退，金鎖網鞔鞔。"]'),
('6cacacf1-11ff-4c3d-b349-df680528aa74','偈十首  其八','釋正覺','宋','宋诗','song-poetry','','[]','觸目絕對待，萬法無不在。',48,'全唐诗/poet.song.101000.json','["觸目絕對待，萬法無不在。", "是汝心不知，非汝心不會。", "不會無不會，不知無不知。", "只箇不會知，殊特也大奇。"]'),
('8eea5398-455c-432e-99e1-a1da6cb2afcf','偈十首  其九','釋正覺','宋','宋诗','song-poetry','','[]','一段光明亘古今，有無照破脫情塵。',64,'全唐诗/poet.song.101000.json','["一段光明亘古今，有無照破脫情塵。", "當頭觸著彌天過，退步承當特地新。", "紫極宮中鳥抱卵，銀河浪裏兔推輪。", "是須妙手携來用，百億分身處處真。"]'),
('51b56071-4842-4218-a206-0645047c4fae','偈十首  其一○','釋正覺','宋','宋诗','song-poetry','','[]','衲僧巴鼻，圓明絕纇。',52,'全唐诗/poet.song.101000.json','["衲僧巴鼻，圓明絕纇。", "直須推倒，却要扶起。", "玉馬飲乾明月泉，泥牛耕破玻璃地。", "披毛戴角異中來，天上人間能幾幾。"]'),
('d9df1231-42ae-4b7d-b490-d98f151678c0','偈二首  其一','釋正覺','宋','宋诗','song-poetry','','[]','心地含諸種，普雨悉皆萌。',24,'全唐诗/poet.song.101000.json','["心地含諸種，普雨悉皆萌。", "既悟花情已，菩提果自成。"]'),
('fbc4c669-1c45-4c9b-8724-02e49a033516','偈二首  其二','釋正覺','宋','宋诗','song-poetry','','[]','妄息寂自生，寂生知則現。',24,'全唐诗/poet.song.101000.json','["妄息寂自生，寂生知則現。", "知生寂自滅，了了唯真見。"]'),
('2f24e9df-27f2-43f9-8208-258e6e2fa8db','吳傅朋郎中書來嘗得李伯時所畫震旦第一祖西歸像相需以贊說偈寄之','釋正覺','宋','宋诗','song-poetry','','[]','其來何求，其去無得。',88,'全唐诗/poet.song.101000.json','["其來何求，其去無得。", "寂漠度嶺兮萬里獨行，清白傳家兮九年一默。", "針芥投而妙不可名，毫釐差而敝不可塞。", "知過而改，知難而退。", "誰去誰來，自買自賣。", "當面諱却兮滿眼烏華，望涯贊之兮隔身鯨海。"]'),
('85c8e6ae-63c6-4308-a117-e7a1ec73d5e3','吳興辯長老以達磨畫像請贊','釋正覺','宋','宋诗','song-poetry','','[]','長蘆駕浪，隻履西歸。',92,'全唐诗/poet.song.101000.json','["長蘆駕浪，隻履西歸。", "求支那之法器，付屈眴之田衣。", "度九年之緘默，印二祖之靈知。", "海犀酣月而暈，寒烏带雪而飛。", "機前自得兮頂目四照，迷裏相逢兮鼻頭下垂。", "水著秋清兮湖光湛湛，山銜落日兮雲錦輝渾。"]'),
('c2743d7c-eb1e-4cd7-a570-9bd368d17912','寶峰照和尚真贊','釋正覺','宋','宋诗','song-poetry','','[]','山擁雲腴，水懷月晝。',54,'全唐诗/poet.song.101000.json','["山擁雲腴，水懷月晝。", "照徹體前，湛存身後。", "機頭梭路微分，針鼻線芒初透。", "靈涵萬象兮彼不遺餘，坐斷十方兮我無滲漏。"]'),
('b61b1b0e-d139-4ec2-93dc-977bdaa8b9f1','弟子薄堅仁以幅縑寫圓悟禪師像徑山裕虎丘隆二高弟侍焉紹興丙辰二月八日予乞食之蘇臺過其家且出以相示再三有請輒隨喜贊云','釋正覺','宋','宋诗','song-poetry','','[]','力世佛宗，心傳我公。',104,'全唐诗/poet.song.101000.json','["力世佛宗，心傳我公。", "一拳活計，一喝家風。", "影草呈機也三聖却瞎，精金出冶也百丈還聾。", "綽綽有裕，恢恢而隆。", "阿難迦葉之多聞抖擻，目連鶖子之智慧神通。", "真得不借之應，大同不宰之功。", "百川曲折兮自然到海，萬象森羅兮不可逃空。"]'),
('6b20275e-8a8b-4ff7-a00b-dd9e2d9ab66e','法澄上人出長蘆了師兄畫像求贊','釋正覺','宋','宋诗','song-poetry','','[]','傲雪松孤，懷雲石癯。',66,'全唐诗/poet.song.101000.json','["傲雪松孤，懷雲石癯。", "妙存而有也不有，獨照而無也非無。", "萬象勿能逃空王之印，衆色莫我染靈蛇之珠。", "金雞啼寒兮曉分夜戶，玉兔弄魄兮瑩徹冰壺。"]'),
('be8639fe-d04b-475f-961c-dfc670173032','從首座畫予於松石間求贊','釋正覺','宋','宋诗','song-poetry','','[]','孤坐默默，倚杖沉沉。',64,'全唐诗/poet.song.101000.json','["孤坐默默，倚杖沉沉。", "石懷雲而無像，松嘯風而有音。", "應兮珠盤不撥而自轉，湛兮玉井隨汲而彌深。", "諸塵不受兮十分清氣，三際無寄兮一片閒心。"]'),
('c58a2f57-30ec-4b62-9144-19beacb3a8ce','禪人寫真求贊  其一','釋正覺','宋','宋诗','song-poetry','','[]','默默傳真，如何指陳。',50,'全唐诗/poet.song.101000.json','["默默傳真，如何指陳。", "性月不夜，心華長春。", "凈有容兮海印，應無爽兮谷神。", "覿面相呈諱不得，煩君爲我洗清貧。"]'),
('f7a570dc-654b-4c4b-a076-c111406a422f','禪人寫真求贊  其二','釋正覺','宋','宋诗','song-poetry','','[]','古澗退潦，寒林著秋。',38,'全唐诗/poet.song.101000.json','["古澗退潦，寒林著秋。", "山空雲自在，水凈月相投。", "向道底心非世用，更嫌何處不風流。"]'),
('e5abc32b-619a-4d74-afe5-3e99629d8178','禪人寫真求贊  其三','釋正覺','宋','宋诗','song-poetry','','[]','阿儂是誰，恰恰相隨。',38,'全唐诗/poet.song.101000.json','["阿儂是誰，恰恰相隨。", "眉毛垂眼尾，鼻孔壓唇皮。", "默默機輪何處轉，玉人踏破吠瑠璃。"]'),
('3b4338fd-d923-41dd-989f-262824fa6ce4','禪人寫真求贊  其四','釋正覺','宋','宋诗','song-poetry','','[]','情閒口快，眼深鼻隆。',42,'全唐诗/poet.song.101000.json','["情閒口快，眼深鼻隆。", "有時對雲水，無可展家風。", "夢鶴卧寒兮月魂泣露，冥鴻望斷兮秋色摩空。"]'),
('68dba93d-13b1-4f25-86f1-aaa1024709af','禪人寫真求贊  其五','釋正覺','宋','宋诗','song-poetry','','[]','黄瘦厭厭，風規冷嚴。',52,'全唐诗/poet.song.101000.json','["黄瘦厭厭，風規冷嚴。", "萬機閒暇，一味清恬。", "心宗提簡默，手段掃廉纖。", "歲寒不變兮虛懷若竹，道妙難傳兮有口如鉗。"]'),
('ca2a1aa0-839c-4b00-9143-ad33975eebb0','禪人寫真求贊  其六','釋正覺','宋','宋诗','song-poetry','','[]','槁寒初不展家風，默默神遊透劫空。',32,'全唐诗/poet.song.101000.json','["槁寒初不展家風，默默神遊透劫空。", "百草頭邊興化事，自然秋色水天同。"]'),
('bcb2455b-80b6-4885-8d7a-d7b47a303dcc','禪人寫真求贊  其七','釋正覺','宋','宋诗','song-poetry','','[]','似與不似，毫釐千里。',52,'全唐诗/poet.song.101000.json','["似與不似，毫釐千里。", "真與不真，大方一塵。", "理無生兮如夢事，妙不死也如谷神。", "徹見淵源方是我，了知變態無別人。"]'),
('552a364f-8986-4540-9f78-9d6766b87904','禪人寫真求贊  其八','釋正覺','宋','宋诗','song-poetry','','[]','身心廓如，手段卷舒。',58,'全唐诗/poet.song.101000.json','["身心廓如，手段卷舒。", "似華作蜜，如井覷驢。", "外不痕兮空印普應，中無象兮道環常虛。", "亡機孤坐兮自不爲礙，把臂同行兮誰敢相疏。"]'),
('23eb59ee-5a75-4db4-a35a-07993b1915f9','禪人寫真求贊  其九','釋正覺','宋','宋诗','song-poetry','','[]','床倚杖蔾，權名住持。',52,'全唐诗/poet.song.101000.json','["床倚杖蔾，權名住持。", "久默鉗口，一笑伸眉。", "雲水誰相問，家風自不知。", "明白寧居兮河空月轉，寂寥無象兮雨霽天垂。"]'),
('dbb4013b-1d65-47aa-8820-47fe9aac1c3e','禪人寫真求贊  其一○','釋正覺','宋','宋诗','song-poetry','','[]','貌古骨癯，雲閒月孤。',36,'全唐诗/poet.song.101000.json','["貌古骨癯，雲閒月孤。", "相隨似有，認著還無。", "三千界內誰相外，雙六盤中不到輸。"]'),
('b4959ddc-2f53-4a04-8c66-6ffba69573ad','禪人寫真求贊  其一一','釋正覺','宋','宋诗','song-poetry','','[]','胡床寒，坐卓卓，只箇虛空唱兮萬象和。',34,'全唐诗/poet.song.101000.json','["胡床寒，坐卓卓，只箇虛空唱兮萬象和。", "道契環中有智遊，言滿天下無口過。"]'),
('0365fdcc-7afe-4a98-b0a1-dd1f82e4d66d','禪人寫真求贊  其一二','釋正覺','宋','宋诗','song-poetry','','[]','默默家風，雲摩霽空。',48,'全唐诗/poet.song.101000.json','["默默家風，雲摩霽空。", "露月夜爽，天水秋同。", "人傳眉目好，我道骨頭窮。", "華鬚凝粉蜂房蜜，桂轂流魂犀角通。"]'),
('68119f5a-48bb-487f-9cdd-f339ab878fe5','禪人寫真求贊  其一三','釋正覺','宋','宋诗','song-poetry','','[]','誰道物齊，俱亡品題。',48,'全唐诗/poet.song.101000.json','["誰道物齊，俱亡品題。", "欺唇一鼻直，蓋眼兩眉低。", "大千同入印，三世未分畦。", "斫額望之不及，擬心思也還迷。"]'),
('01f05d5a-788f-42ec-8963-db0d5794bbea','禪人寫真求贊  其一四','釋正覺','宋','宋诗','song-poetry','','[]','枯坐清嚴，真宗劇談。',52,'全唐诗/poet.song.101000.json','["枯坐清嚴，真宗劇談。", "一明無異相，萬化是同參。", "牛頭轉覺病懶，鳥喙不用華銜。", "甘分住山三束篾，等閑對客七斤衫。"]'),
('65671c13-149f-436b-a403-6d7c1ab1b8d5','禪人寫真求贊  其一五','釋正覺','宋','宋诗','song-poetry','','[]','畫得似誰，胡床黲衣。',48,'全唐诗/poet.song.101000.json','["畫得似誰，胡床黲衣。", "默遊彷彿，去就依稀。", "洞山錦開縫，雲巖絹下機。", "功亡妙盡看消息，野水磨秋白鳥飛。"]'),
('f8898978-f807-4aab-a2b1-e4af81622a13','禪人寫真求贊  其一六','釋正覺','宋','宋诗','song-poetry','','[]','面瘦頰凸，眉棱眼深。',46,'全唐诗/poet.song.101000.json','["面瘦頰凸，眉棱眼深。", "默亡所住，妙在而今。", "鱗潛寒水，鶴夢月林。", "應聲應色分身也，拍手家家觀世音。"]'),
('223a03ef-f352-47e5-bc7f-8b8405fb9e17','禪人寫真求贊  其一七','釋正覺','宋','宋诗','song-poetry','','[]','寫出夢中身，你道真不真。',54,'全唐诗/poet.song.101000.json','["寫出夢中身，你道真不真。", "槁寒秋在眼，淵默醭生唇。", "道環誰謂無象，空谷自來有神。", "父子不傳些子妙，白首儂家老斲輪。"]'),
('d35d9882-3795-4424-836b-07fa56973e83','禪人寫真求贊  其一八','釋正覺','宋','宋诗','song-poetry','','[]','畫手未相識，默心誰與知。',56,'全唐诗/poet.song.101000.json','["畫手未相識，默心誰與知。", "千峯斂雲脚，一月濯風漪。", "牆面袖雙手，對緣橫兩眉。", "驚龜之縮兮愧有其兆，逸鳥之翔兮情亡所羈。"]'),
('3202e965-0928-4684-9c72-4497f6c8eaee','禪人寫真求贊  其一九','釋正覺','宋','宋诗','song-poetry','','[]','瘦削而黄，慣窮不忙。',52,'全唐诗/poet.song.101000.json','["瘦削而黄，慣窮不忙。", "閑情許淡，默味能長。", "靈犀之通一點暈，老蚌之藴千年光。", "而今到處相隨去，頭頭的的露堂堂。"]'),
('15c1273a-d3aa-4375-93bd-01de29bcf6f6','禪人寫真求贊  其二○','釋正覺','宋','宋诗','song-poetry','','[]','大一無外，小一無內。',66,'全唐诗/poet.song.101000.json','["大一無外，小一無內。", "一兮一兮，靡所不在。", "心地凈亡塵，肉山閑弗礙。", "道環中，絕端倪。", "空印裏，何文彩。", "風凄凄兮秋落遠山，波爛爛兮月浮滄海。"]'),
('143350ca-3dbd-48a7-b0c9-18cf78be795f','禪人寫真求贊  其二一','釋正覺','宋','宋诗','song-poetry','','[]','默默蒲禪，空空世緣。',56,'全唐诗/poet.song.101000.json','["默默蒲禪，空空世緣。", "誰賡白雪，我得青氈。", "萬法之機開兩拳，千僧之檐著一肩。", "戲蝶栩栩兮物齊春夢，飛鴻冥冥兮字沒秋煙。"]'),
('0dc9c6bf-f0ea-4ec9-9a7c-155584e9672c','禪人寫真求贊  其二二','釋正覺','宋','宋诗','song-poetry','','[]','不是恁麽形像，剛地起模畫樣。',62,'全唐诗/poet.song.101000.json','["不是恁麽形像，剛地起模畫樣。", "從來萬法同根，究竟虛空等量。", "可中二浙說禪，分外三河口强。", "深藏那裏也煙蓑卧雲，大用現前也風舟駕浪。"]'),
('b0950174-7b84-4bef-8245-3c8526ee7352','禪人寫真求贊  其二三','釋正覺','宋','宋诗','song-poetry','','[]','畫得幾成，精神許清。',48,'全唐诗/poet.song.101000.json','["畫得幾成，精神許清。", "秋高月轉，天淡河橫。", "出家如有以，處世似無情。", "而今鬧裏相將去，撥動眉毛眼更明。"]'),
('61729088-9eb0-49c5-b375-66d914d6bedf','禪人寫真求贊  其二四','釋正覺','宋','宋诗','song-poetry','','[]','喬喬楚楚，叢林規矩。',88,'全唐诗/poet.song.101000.json','["喬喬楚楚，叢林規矩。", "萎萎羸羸，枯木風姿。", "宗乘壁挂口，師友雪生眉。", "住山事拙束三篾，對月機鳴度一絲。", "顛毛間白髮，眉睫裹青瞳。", "食指一肩重，門風四壁空。", "諸根亡偶宗家妙，萬慮不摇心匠工。"]'),
('fa14f9b7-cef6-4841-98ab-4a4ab6ab3fbb','禪人寫真求贊  其二五','釋正覺','宋','宋诗','song-poetry','','[]','野水秋自瘦，枯山春復肥。',45,'全唐诗/poet.song.101000.json','["野水秋自瘦，枯山春復肥。", "胡床放得穩，默默坐亡機。", "電流柄拂，雲入田衣。", "位分偏正兮，道出離微。"]'),
('028eedb4-b320-43c0-ac63-ffd017a3d556','禪人寫真求贊  其二六','釋正覺','宋','宋诗','song-poetry','','[]','骨氣能樸，精神愈憨。',42,'全唐诗/poet.song.101000.json','["骨氣能樸，精神愈憨。", "閑身無所系，冷眼莫相瞞。", "遠霽摩秋兮天河斗轉，清霜結夜兮月窟蟾寒。"]'),
('3664b3f7-763e-40cd-893c-236fb90d6077','禪人寫真求贊  其二七','釋正覺','宋','宋诗','song-poetry','','[]','雙奮拳空，一擔肩重。',46,'全唐诗/poet.song.101000.json','["雙奮拳空，一擔肩重。", "材本不堪，心元無用。", "鶯院華香，蜂房蜜凍。", "喝時耳朵三日聾，扭處鼻頭連歲痛。"]'),
('63c4b178-9092-4787-8c48-7e6decb8d54f','禪人寫真求贊  其二八','釋正覺','宋','宋诗','song-poetry','','[]','口方鼻直，眉棱眼深。',52,'全唐诗/poet.song.101000.json','["口方鼻直，眉棱眼深。", "未填溝壑，還礙叢林。", "萬象無得剩法，三世不見閒心。", "字雁沒而寒煙淡淡，華鱗潛而秋水沈沈。"]'),
('cb7ec7af-87f9-4a94-9e93-f3f178120dc4','禪人寫真求贊  其二九','釋正覺','宋','宋诗','song-poetry','','[]','只箇家風，窮而却通。',61,'全唐诗/poet.song.101000.json','["只箇家風，窮而却通。", "於其間內紹外紹，在裏許轉功借功。", "至遊而默，妙用而沖。", "氣溫溫而春活，心湛湛而秋空。", "相隨來也兮，頭頭契同。"]'),
('b918e02b-23a4-4da7-8bfd-338894142e86','禪人寫真求贊  其三○','釋正覺','宋','宋诗','song-poetry','','[]','髮長带雪，骨瘦橫山。',40,'全唐诗/poet.song.101000.json','["髮長带雪，骨瘦橫山。", "身心冷淡，雲月高閒。", "三條篾束兮道情自槁，五葉華開兮春信那慳。"]'),
('66466aa8-16b9-4e64-a953-8971cdd8fb97','禪人寫真求贊  其三一','釋正覺','宋','宋诗','song-poetry','','[]','曲木床頭，心空默遊。',40,'全唐诗/poet.song.101000.json','["曲木床頭，心空默遊。", "沙寒黄葦雪，風細白蘋秋。", "靜可久兮山瘠樹老，動無羈兮雲行水流。"]'),
('9f3e5451-8bc4-4bfc-b3a3-637a254c305b','禪人寫真求贊  其三二','釋正覺','宋','宋诗','song-poetry','','[]','雙眉低垂，兩目清冷。',38,'全唐诗/poet.song.101000.json','["雙眉低垂，兩目清冷。", "著於萬象森羅，更沒一絲欠剩。", "秋霜鶴老夢寒，霽月夜摩松頂。"]'),
('190df9f6-d471-4d4c-8c56-a7b4e9a47fdc','禪人寫真求贊  其三三','釋正覺','宋','宋诗','song-poetry','','[]','虛空借得作身，萬象相隨爲伴。',56,'全唐诗/poet.song.101000.json','["虛空借得作身，萬象相隨爲伴。", "縱橫人道十成，點檢誰知一半。", "看看青山崢嶸，白雲零亂。", "裏許牧童歸未歸，鐵牛一掣金繩斷。"]'),
('0dfb055c-30e4-4b26-ad03-6b4c0fc60d0e','禪人寫真求贊  其三四','釋正覺','宋','宋诗','song-poetry','','[]','秋生木老，水退沙隆。',58,'全唐诗/poet.song.101000.json','["秋生木老，水退沙隆。", "眉骨陰晴輕重，鼻筒子丑疏通。", "身心霽月，蹤跡流蓬。", "默坐胡床兮不欲說黑道白，閑倚柱杖兮誰能畫西指東。"]'),
('373b8c9f-de91-45cb-9e8f-1211ebaf446b','禪人寫真求贊  其三五','釋正覺','宋','宋诗','song-poetry','','[]','髮將雪白，面作茶黄。',52,'全唐诗/poet.song.101000.json','["髮將雪白，面作茶黄。", "觸動眼三角，忘言口四方。", "明月松頭鶴夢，香風蓮底龜藏。", "凈極發光光自照，虛空鳥印不成章。"]'),
('bd15f7c2-3af9-40c8-8510-bfbc2309805f','禪人寫真求贊  其三六','釋正覺','宋','宋诗','song-poetry','','[]','恬然正觀，山空水寒。',44,'全唐诗/poet.song.101000.json','["恬然正觀，山空水寒。", "河漢橫而斗潤，雲霧斂而秋寬。", "如仇學子兮怒眼三角，無位真人兮赤肉一團。"]'),
('694edad8-76fd-434f-9ba4-1a6675226dd5','禪人寫真求贊  其三七','釋正覺','宋','宋诗','song-poetry','','[]','老覺雪入鬢，凈若秋摩心。',44,'全唐诗/poet.song.101000.json','["老覺雪入鬢，凈若秋摩心。", "寒枯坐曲木，緘默飽叢林。", "氣韻寥寥兮風清山瘠，性靈湛湛兮月落潭深。"]'),
('3b8defa4-08ab-467d-91a9-84cfea653c21','禪人寫真求贊  其三八','釋正覺','宋','宋诗','song-poetry','','[]','太虛之心，萬象之身。',38,'全唐诗/poet.song.101000.json','["太虛之心，萬象之身。", "濯濯水中月，英英華上春。", "而今到處相逢也，眼裏無筋一世貧。"]'),
('a53110d8-a030-431e-9a0f-56c733d94e00','禪人寫真求贊  其三九','釋正覺','宋','宋诗','song-poetry','','[]','淵默之得，不可文墨。',40,'全唐诗/poet.song.101000.json','["淵默之得，不可文墨。", "流應之功，不可形容。", "秋入野水，月行霽空。", "影像名字，且喚天童。"]'),
('9436a112-7f39-41a9-9720-edf4a0b6e917','禪人寫真求贊  其四○','釋正覺','宋','宋诗','song-poetry','','[]','風日面皮，秋山眉目。',78,'全唐诗/poet.song.101000.json','["風日面皮，秋山眉目。", "閑情肖水雲，野性從麋鹿。", "憨憨少室九年，草草曹溪一宿。", "窮根徹源，出髓敲骨。", "明回老兔宮，冷下蒼龍窟。", "諸人名邈兮摇手未然，萬象森羅兮點頭具足。"]'),
('f092668a-1f0c-4f3f-833e-b1a721ed5ade','禪人寫真求贊  其四一','釋正覺','宋','宋诗','song-poetry','','[]','伎倆俱無，身心淡如。',46,'全唐诗/poet.song.101000.json','["伎倆俱無，身心淡如。", "霽月自分照，閒雲從卷舒。", "疋上不足，疋下有餘。", "少室謾傳衣鉢，曹溪不識文書。"]'),
('e4b85134-b041-48f7-b7b8-9647071e672b','禪人寫真求贊  其四二','釋正覺','宋','宋诗','song-poetry','','[]','一色功回，雷雲凍開。',40,'全唐诗/poet.song.101000.json','["一色功回，雷雲凍開。", "萬機俱罷，風月轉夜。", "空空谷有神，欣欣木有春，而今何處不分身。"]'),
('aff14258-8b13-4e7c-9b55-72ca64124b67','禪人寫真求贊  其四三','釋正覺','宋','宋诗','song-poetry','','[]','說時不借口，用處不依身。',40,'全唐诗/poet.song.101000.json','["說時不借口，用處不依身。", "天寒絕飛鳥，潭凈無遊鱗。", "點活眼，著精神，野草閑華自在春。"]'),
('58ca4992-c010-4fe7-b019-fb725515bc26','禪人寫真求贊  其四四','釋正覺','宋','宋诗','song-poetry','','[]','雨霽雲收，山寒水秋。',50,'全唐诗/poet.song.101000.json','["雨霽雲收，山寒水秋。", "心目自照，言象俱休。", "滿十方而智應，廓三世以神遊。", "虛空那礙東西壁，明月解隨南北舟。"]'),
('1e9b6609-de53-425e-88f0-925d95788ebe','禪人寫真求贊  其四五','釋正覺','宋','宋诗','song-poetry','','[]','面孔風埃，身心冷灰。',43,'全唐诗/poet.song.101000.json','["面孔風埃，身心冷灰。", "鯨飲海乾而珊瑚露，龜藏泥暖而芙蓉開。", "向去却來，其間變態也掣電轟雷。"]'),
('e575b547-c7e1-4d8e-a881-e9594a2c3411','禪人寫真求贊  其四六','釋正覺','宋','宋诗','song-poetry','','[]','忒煞覺老，寒而且槁。',38,'全唐诗/poet.song.101000.json','["忒煞覺老，寒而且槁。", "古巖春遲，澄潭秋早。", "心無象也月影未回，物不爭也風吹便倒。"]'),
('da439a9d-1e62-4b87-8d45-954518b95e84','禪人寫真求贊  其四七','釋正覺','宋','宋诗','song-poetry','','[]','只者赤肉一塊，說甚清奇古怪。',62,'全唐诗/poet.song.101000.json','["只者赤肉一塊，說甚清奇古怪。", "平生懶似牛頭，度世憨如布袋。", "不空而空，無在而在。", "法法唯心，塵塵三昧。", "問渠是假是真，兩彩而今一賽。"]'),
('ef2c1130-b883-4ebc-b9ef-de44f39abc06','禪人寫真求贊  其四八','釋正覺','宋','宋诗','song-poetry','','[]','眉低不愁，眼深非惡。',54,'全唐诗/poet.song.101000.json','["眉低不愁，眼深非惡。", "鼻孔纍垂，口唇齷齪。", "月明破夜兮野水懷秋，霽色摩霜兮閒雲投壑。", "能錯落縱橫十字兮，妙提一著。"]'),
('73378434-14ba-44a2-9f5a-0d6255a97854','禪人寫真求贊  其四九','釋正覺','宋','宋诗','song-poetry','','[]','誰能目眴眉揚，每笑手亂脚忙。',56,'全唐诗/poet.song.101000.json','["誰能目眴眉揚，每笑手亂脚忙。", "守魯祖之簡默，得南泉之平常。", "明心秋月，活物春陽。", "鑄機器也模範大小，據叢林也規矩圓方。"]'),
('6f5f5df6-057b-474d-a59e-79e6f4878c71','禪人寫真求贊  其五○','釋正覺','宋','宋诗','song-poetry','','[]','畫工出脫它，精神較得些。',56,'全唐诗/poet.song.101000.json','["畫工出脫它，精神較得些。", "草不萌，藏香象。", "匣無縫，吼青蛇。", "春雷開衆蟄，暖律發千華。", "想是平江人見笑，去年纔去又來耶。"]'),
('b4af8410-0730-4a82-8a1e-9706547c2929','禪人寫真求贊  其五一','釋正覺','宋','宋诗','song-poetry','','[]','雲樹蒼蒼，泉石鑿鑿。',50,'全唐诗/poet.song.101000.json','["雲樹蒼蒼，泉石鑿鑿。", "倚杖坐其間，此心自空廓。", "秋月濯滄溟，春風在林薄。", "遊魚下藻玉溪寒，字雁沒煙天宇闊。"]'),
('d2f5e6de-03be-4731-986b-1dd370070de2','禪人寫真求贊  其五二','釋正覺','宋','宋诗','song-poetry','','[]','眼空毛芥不立，心空海嶽可容。',56,'全唐诗/poet.song.101000.json','["眼空毛芥不立，心空海嶽可容。", "便與打成一片，尚猶笑道疏蹤。", "虛空那挂劍，死水不藏龍。", "轉色轉功家法子，蘆華明月後相逢。"]'),
('8a16b407-6eec-45e2-936f-bf1f18b064c3','禪人寫真求贊  其五三','釋正覺','宋','宋诗','song-poetry','','[]','怒眉嗔目，枯腸空腹。',50,'全唐诗/poet.song.101000.json','["怒眉嗔目，枯腸空腹。", "面冷莫觸，氣清可掬。", "乘仙槎而棹星河，握玉斧而修月轂。", "真見法以唯心，妙契神於即物。"]'),
('8b5b30d4-55db-48ab-840e-1a6e120c653b','禪人寫真求贊  其五四','釋正覺','宋','宋诗','song-poetry','','[]','鼻孔脩直，眉毛低垂。',46,'全唐诗/poet.song.101000.json','["鼻孔脩直，眉毛低垂。", "閒來一默，凈掃餘思。", "秋水連天摩霽色，春風著木見遊絲，撒開捏聚兮只箇些兒。"]'),
('3de8dd36-f611-45d1-b8ec-2667e29a1207','禪人寫真求贊  其五五','釋正覺','宋','宋诗','song-poetry','','[]','頭雪老曬，面肉肥些。',62,'全唐诗/poet.song.101000.json','["頭雪老曬，面肉肥些。", "骨寒窮鬼子，情淡道人家。", "謗佛謗祖，撒土撒沙。", "明月犀玩兮暈通其角，迅雷象驚兮文理其牙，未把家風兮草草傳耶。"]'),
('c8ceabad-0ce3-410b-817b-1f2bfc749dbe','禪人寫真求贊  其五六','釋正覺','宋','宋诗','song-poetry','','[]','氣韻能清，眉目似笑。',61,'全唐诗/poet.song.101000.json','["氣韻能清，眉目似笑。", "深深入大道之環，默默守羣機之要。", "鬧裏隨緣，虛中分照。", "用作家之鉗鎚，與本分之草料。", "千毳相從兮，俱求參飽。"]'),
('fd3f1c3a-9c97-40f8-9306-63f3ec80880a','禪人寫真求贊  其五七','釋正覺','宋','宋诗','song-poetry','','[]','胡床小小身，握麈默而神。',52,'全唐诗/poet.song.101000.json','["胡床小小身，握麈默而神。", "喚醒曠劫之夢，瀝乾滄海之津。", "霽空摩塵，風月重輪。", "羣機活活物中眼，一點英英華上春。"]'),
('e54cda0d-5f7d-40f1-be4d-6c8f13079d31','禪人寫真求贊  其五八','釋正覺','宋','宋诗','song-poetry','','[]','覺之微妙，未痕朕兆。',54,'全唐诗/poet.song.101000.json','["覺之微妙，未痕朕兆。", "徹造化之源，據生殺之要。", "至虛而獨存，當明而隱照。", "築築磕磕兮鼻孔纍垂，哆哆和和兮舌頭狤獠。"]'),
('7af9ba8c-001b-4045-a4e7-234c12af1d83','禪人寫真求贊  其五九','釋正覺','宋','宋诗','song-poetry','','[]','眉棱棱，眼烱烱。',46,'全唐诗/poet.song.101000.json','["眉棱棱，眼烱烱。", "自愛情閒，人嫌面冷。", "片雲出岫之心，孤月濯潭之影。", "絕憐百億分身，恰滿三千化境。"]'),
('d5f06548-60f6-4ad7-a244-ce61118cc4f0','禪人寫真求贊  其六○','釋正覺','宋','宋诗','song-poetry','','[]','赤肉穿多孔，臭骨裹閑皮。',56,'全唐诗/poet.song.101000.json','["赤肉穿多孔，臭骨裹閑皮。", "已是不著便，更將描畫伊。", "一柄拂聊爲伴手，三世佛誰敢稱師。", "鯨怒飲乾滄海水，月明爛爛珊瑚枝。"]'),
('0d46d519-a2e4-4ec5-81b2-59a4a21a3abd','禪人寫真求贊  其六一','釋正覺','宋','宋诗','song-poetry','','[]','器宇潭潭，風骨巖巖。',56,'全唐诗/poet.song.101000.json','["器宇潭潭，風骨巖巖。", "雲夢之氣吞八九，嵩少之道落二三。", "守一爻生成之機紐，秉諸祖烹鍛之鎚鉗。", "捏聚放行也肖嶽蓄而海涵。"]'),
('95c13a90-b5c4-4395-bd18-06590a3a32c9','禪人寫真求贊  其六二','釋正覺','宋','宋诗','song-poetry','','[]','閒兮無寄，用也不痕。',54,'全唐诗/poet.song.101000.json','["閒兮無寄，用也不痕。", "月雖能現影，雲自不生根。", "活卓卓諸塵莫混，明歷歷曠劫長存。", "相隨鬧市堆中去，普光三昧發門門。"]'),
('30724bcd-3eef-47d0-9cd0-f794a0201971','禪人寫真求贊  其六三','釋正覺','宋','宋诗','song-poetry','','[]','不以律拘，不以禪縛。',40,'全唐诗/poet.song.101000.json','["不以律拘，不以禪縛。", "說法口窄，默遊步闊。", "草木陽春來，池塘明月落，何妨處處相安著。"]'),
('90c9b81c-cc1b-4794-ae09-679e6a83482b','禪人寫真求贊  其六四','釋正覺','宋','宋诗','song-poetry','','[]','天童比丘，還相識不。',50,'全唐诗/poet.song.101000.json','["天童比丘，還相識不。", "白髮寒巖雪，青瞳古澗秋。", "現身不墮類，分影也隨流。", "它日果能窺頂相，晴雲似放去山頭。"]'),
('93f2bf78-7730-4b01-822b-2480b4983e78','禪人寫真求贊  其六五','釋正覺','宋','宋诗','song-poetry','','[]','白雲之身，寒月之心。',40,'全唐诗/poet.song.101000.json','["白雲之身，寒月之心。", "性靈麋鹿，氣韻山林。", "不墮兩頭兮匪明匪暗，全超三際兮誰古誰今。"]'),
('7d11aa0e-235c-4a9d-a541-8309001aee95','禪人寫真求贊  其六六','釋正覺','宋','宋诗','song-poetry','','[]','說也說不破，畫也畫不成。',52,'全唐诗/poet.song.101000.json','["說也說不破，畫也畫不成。", "慷慨鼻氣通快，清閒眉棱覺輕。", "靜不得像，動不流情。", "十方三世無安處，歷歷諸緣頭上行。"]'),
('f5c8b263-f8a3-48fb-96c3-63329f544098','禪人寫真求贊  其六七','釋正覺','宋','宋诗','song-poetry','','[]','圓顱方衣，靜樞活機。',38,'全唐诗/poet.song.101000.json','["圓顱方衣，靜樞活機。", "天空雲淡淡，潭凈月依依。", "十分化事成華木，默默冰壺春信歸。"]'),
('af905d01-bf06-4ac2-8e82-ccc15e0e62aa','禪人寫真求贊  其六八','釋正覺','宋','宋诗','song-poetry','','[]','握筇之像，對機之身。',53,'全唐诗/poet.song.101000.json','["握筇之像，對機之身。", "六根攝一處，三昧起諸塵。", "蚌腸孕於月明之夜，蟄戶開於雷動之春。", "箇般手段兮，分付善應之人。"]'),
('e60bbfe3-95ab-499d-9981-695ab84ac76a','禪人寫真求贊  其六九','釋正覺','宋','宋诗','song-poetry','','[]','看看靜，見其端。',44,'全唐诗/poet.song.101000.json','["看看靜，見其端。", "星河斗濕，月窟蟾寒。", "體無棱縫，用絕痕瘢。", "不須喝彩還贏也，已見雙雙六在盤。"]'),
('786f8708-81c6-4517-bc9e-b21742faef21','禪人寫真求贊  其七○','釋正覺','宋','宋诗','song-poetry','','[]','春山似肥，春雪纔晞。',44,'全唐诗/poet.song.101000.json','["春山似肥，春雪纔晞。", "默中有句，用也無機。", "不來而來兮非三界之籠絡，無住而住兮是二儀之範圍。"]'),
('50e241e8-e524-4b7f-911e-9a444627f0b1','禪人寫真求贊  其七一','釋正覺','宋','宋诗','song-poetry','','[]','曲木床穩，刺蔾杖橫。',54,'全唐诗/poet.song.101000.json','["曲木床穩，刺蔾杖橫。", "攬五宗之家法，據萬象之主盟。", "秋半風清，霽空月明。", "水雲模楷兮無禪可說，叢林規矩兮不令而行。"]'),
('232912ad-5cca-498c-a904-55449c7019e5','禪人寫真求贊  其七二','釋正覺','宋','宋诗','song-poetry','','[]','棱眉眼自深，闊口笑吟吟。',49,'全唐诗/poet.song.101000.json','["棱眉眼自深，闊口笑吟吟。", "崢嶸一片膽，疏豁十方心。", "默默春回萬象，星星雪點孤岑。", "恁麽來也兮，不用相尋。"]'),
('4b10640d-767e-460b-a183-da99b92b6fd0','禪人寫真求贊  其七三','釋正覺','宋','宋诗','song-poetry','','[]','坐曲木床，握烏藤杖。',40,'全唐诗/poet.song.101000.json','["坐曲木床，握烏藤杖。", "鑄佛祖之楷模，活叢林之氣象。", "你莫來虎口撩鬚，誰更敢蛇頭揩癢。"]'),
('2459bd1c-31d8-4c4a-8600-ef1ce68ebfd3','禪人寫真求贊  其七四','釋正覺','宋','宋诗','song-poetry','','[]','袈娑在肩，柱杖入握。',34,'全唐诗/poet.song.101000.json','["袈娑在肩，柱杖入握。", "未動六爻，全提一著。", "分身是處相隨，當面不須諱却。"]'),
('130ae3ab-f3d4-4e0c-83c9-8831784bbf43','禪人寫真求贊  其七五','釋正覺','宋','宋诗','song-poetry','','[]','笑含口角，喜在眉棱。',80,'全唐诗/poet.song.101000.json','["笑含口角，喜在眉棱。", "一默照源底，三乘空葛藤。", "清白濯秋之月，光明破夜之燈。", "柱杖有時橫膝上，箇般面觜得人憎。", "動而靜，虛而應。", "專氣致柔，湛神如凝。", "一住天童，十分沒興。"]'),
('630bc421-4025-43f7-94b7-f2a08cd22ed0','禪人寫真求贊  其七六','釋正覺','宋','宋诗','song-poetry','','[]','廬陵米價百念升，趙州蘿蔔半千秤。',41,'全唐诗/poet.song.101000.json','["廬陵米價百念升，趙州蘿蔔半千秤。", "只麽郎當住持，洎合殃殺性命。", "省不省，腦後更將楔釘。"]'),
('d260acca-54de-4ece-9e74-77d70016c51f','禪人寫真求贊  其七七','釋正覺','宋','宋诗','song-poetry','','[]','閒雲卷雨，野水懷秋。',31,'全唐诗/poet.song.101000.json','["閒雲卷雨，野水懷秋。", "一心絕待，六處不收。", "是箇面觜兮，還相識不。"]'),
('0e9fd6b6-20a4-4d5f-868e-e88e924c510e','禪人寫真求贊  其七八','釋正覺','宋','宋诗','song-poetry','','[]','胸中事簡，面上氣和。',52,'全唐诗/poet.song.101000.json','["胸中事簡，面上氣和。", "白頭隨我老，青眼見人多。", "一身幸且慚愧，千鉢相從奈何。", "曲木床頭坐不語，玉蟾推月過星河。"]'),
('0c7cc464-20b3-4203-bd12-16f8b09d72d3','禪人寫真求贊  其七九','釋正覺','宋','宋诗','song-poetry','','[]','髮白星星，心鑑靈靈。',41,'全唐诗/poet.song.101000.json','["髮白星星，心鑑靈靈。", "隨機說法，應物現形。", "天與之清，地與之寧。", "野雲曳曳兮，山月亭亭。"]'),
('20159faa-7ab2-45f3-9600-92dd46e172cb','禪人寫真求贊  其八○','釋正覺','宋','宋诗','song-poetry','','[]','家風貧自慚，面孔惡人嫌。',58,'全唐诗/poet.song.101000.json','["家風貧自慚，面孔惡人嫌。", "點漆之眼有角，截筒之鼻無尖。", "顛毛寒覆雪，項癭暗消鹽。", "說妙談玄兮遲鈍口觜，呵佛罵祖兮誑嚇閭閻。"]'),
('9837feab-b824-4358-9da0-dd805227ab58','禪人寫真求贊  其八一','釋正覺','宋','宋诗','song-poetry','','[]','禪床默默，無得之得。',54,'全唐诗/poet.song.101000.json','["禪床默默，無得之得。", "寒淡賦心，清貧入骨。", "秋徹鮫人之家，霜摩老兔之窟。", "萬象影中兮自縱自橫，百草頭上兮隨出隨沒。"]'),
('078a3dd5-f92a-4152-97be-d08a7eceb8d5','禪人寫真求贊  其八二','釋正覺','宋','宋诗','song-poetry','','[]','眼低眉棱，骨寒肩聳。',56,'全唐诗/poet.song.101000.json','["眼低眉棱，骨寒肩聳。", "道情閒不羈，禪膽老能勇。", "流水清而月隨，青山瘦而雲擁。", "諸緣廓凈兮拈却頭皮，一句妙圜兮好看鼻孔。"]'),
('b3fcc9eb-42db-404d-97e4-d66d42982e96','禪人寫真求贊  其八三','釋正覺','宋','宋诗','song-poetry','','[]','且道是何面觜，剛地無風浪起。',44,'全唐诗/poet.song.101000.json','["且道是何面觜，剛地無風浪起。", "默默閒自照心，了了倚誰傳髓。", "白鷗暮落煙沙秋，寒卧蘆華明月裏。"]'),
('41ae2186-6cbd-4406-aef2-78fe4f0e70b7','禪人寫真求贊  其八四','釋正覺','宋','宋诗','song-poetry','','[]','是處分身，如谷之神。',36,'全唐诗/poet.song.101000.json','["是處分身，如谷之神。", "有應之月，無私之春。", "行將五路開雙手，一切門頭只箇人。"]'),
('15cf7d74-2bed-479a-ac98-1af6155c983d','禪人寫真求贊  其八五','釋正覺','宋','宋诗','song-poetry','','[]','虛而通，用而沖。',42,'全唐诗/poet.song.101000.json','["虛而通，用而沖。", "默遊量外，直照環中。", "雲水一身瘠，家風四壁空。", "相逢有知己，點指識渠儂。"]'),
('4af54401-b3b3-404b-9d64-94f747914ffe','禪人寫真求贊  其八六','釋正覺','宋','宋诗','song-poetry','','[]','雙目寒青，秋水冷冷。',56,'全唐诗/poet.song.101000.json','["雙目寒青，秋水冷冷。", "半顛衰白，春雪星星。", "山霧霏霏文豹變，松月娟娟夢鶴醒。", "妙應方圜兮了無外法，塵緣俯仰兮初不吾經。"]'),
('cc50046d-899e-4f19-ae0c-6b8122e1e2f4','禪人寫真求贊  其八七','釋正覺','宋','宋诗','song-poetry','','[]','鶴老松孤，泉寒石癯。',46,'全唐诗/poet.song.101000.json','["鶴老松孤，泉寒石癯。", "鏡之對像，谷之答呼。", "萬緣雜錯不是有，一點靈明不是無。", "湛存妙應兮機輪活樞。"]'),
('7e9c003c-8cfe-430a-a55d-c0c24b670d4a','憑宣教寫真請贊','釋正覺','宋','宋诗','song-poetry','','[]','山林之姿，水月之像。',66,'全唐诗/poet.song.101000.json','["山林之姿，水月之像。", "雷潛九地之中，春在百華之上。", "隨緣半合半開，分付全收全放。", "淵默家風，縱橫伎倆。", "道超情也萬法齊平，心出礙也十方通暢。"]'),
('892c3576-99fc-4e6c-bd14-756fb95688ff','薄了固保義寫予真請贊','釋正覺','宋','宋诗','song-poetry','','[]','靈靈而真，默默而神。',56,'全唐诗/poet.song.101000.json','["靈靈而真，默默而神。", "眉毛低蓋眼，鼻孔直欺唇。", "千華上何須問佛，百草頭自然有春。", "一微塵裏也來說法，三千界內不礙分身。"]'),
('4443dbd5-66b9-4978-813c-e8d6924db96b','烏墩密印大師仁公真贊','釋正覺','宋','宋诗','song-poetry','','[]','唇口能緘，眉目如笑。',36,'全唐诗/poet.song.101000.json','["唇口能緘，眉目如笑。", "應外而沖，虛中而照。", "全身放下是全身，一點獨靈常了了。"]'),
('73019286-cc0c-4f28-acba-3274a99789f8','善友陸銓寫真請贊','釋正覺','宋','宋诗','song-poetry','','[]','野雲情態閒，秋山風骨瘦。',48,'全唐诗/poet.song.101000.json','["野雲情態閒，秋山風骨瘦。", "真照也默默而靈，湛存也綿綿而壽。", "圓蒲曲木兮清白傳家，老鶴蒼松兮歲寒去就。"]'),
('acc1ea4c-2619-4afd-96d1-4c96a435d0d1','贊法雲昇律師','釋正覺','宋','宋诗','song-poetry','','[]','雲容閒而未收，月魄湛而不流。',54,'全唐诗/poet.song.101000.json','["雲容閒而未收，月魄湛而不流。", "嚴凈身器也依律而住，虛明神宇也唯道而遊。", "凜凜清姿兮顛毛覆雪，寥寥霽色兮心鑑含秋。"]'),
('1ffc4a4d-eab1-4b01-ae2d-12e974925ccb','仗錫爲長老寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','木老春遲，山寒雪早。',56,'全唐诗/poet.song.101000.json','["木老春遲，山寒雪早。", "潮退珊瑚林，霽空明月曉。", "守默自如，對緣恰好。", "得往得來，隨起隨倒。", "龍潭覷破天皇，馬祖踏著水潦。"]'),
('89dfe33f-75dc-4ace-9c06-58a43e4d137b','像維那寫老病阿師像請贊','釋正覺','宋','宋诗','song-poetry','','[]','芙蓉之枝，丹山之兒。',56,'全唐诗/poet.song.101000.json','["芙蓉之枝，丹山之兒。", "一絲聯自信，三昧約誰知。", "珊瑚寒月墮影，琥珀老松流滋。", "諸緣豁凈兮山空秋壯，萬態變通兮華麗春脂。"]'),
('b6a5f5ff-6d98-4949-baa1-d8fcf36800fc','次韻真歇和尚圓覺經頌一十四首 大光明藏','釋正覺','宋','宋诗','song-poetry','','[]','衲僧撥轉鐵牛機，默耀靈通底是誰。',64,'全唐诗/poet.song.101000.json','["衲僧撥轉鐵牛機，默耀靈通底是誰。", "月兔影沉雲母地，海禽夢卧珊瑚枝。", "韶陽佛法嫌饒舌，魯祖家風解惜眉。", "端坐環中虛白處，縱經塵劫箇難移。"]'),
('4645203f-8b3d-4fb6-ba08-c8bad3b7c312','次韻真歇和尚圓覺經頌一十四首 文殊師利菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','曼殊大士振真風，智洗無明去夙蒙。',64,'全唐诗/poet.song.101000.json','["曼殊大士振真風，智洗無明去夙蒙。", "眼翳纔消華自滅，靈光獨照妄還鎔。", "木人步轉初歸位，玉女機回却借功。", "綱領提持看手段，門門變態是神通。"]'),
('2792b4ca-6834-4200-91ce-fa3986329f3a','次韻真歇和尚圓覺經頌一十四首 普賢菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','儂家活計本天然，剎剎塵塵見普賢。',64,'全唐诗/poet.song.101000.json','["儂家活計本天然，剎剎塵塵見普賢。", "犀角一星蟾影透，神珠九曲蟻絲穿。", "覺非漸次亡稜縫，幻自消鎔得混圓。", "妙應通身無向背，古菱花不染媸妍。"]'),
('97586579-44f0-4ac6-b80e-3f99d5221b7c','次韻真歇和尚圓覺經頌一十四首 普眼菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','誰從普眼道場來，天帝堂前珠網開。',64,'全唐诗/poet.song.101000.json','["誰從普眼道場來，天帝堂前珠網開。", "徹底光明成一段，箇中清凈絕纖埃。", "交羅理事真空觀，照破根塵不夜臺。", "恰恰相應爾時節，陶家壁上起梭雷。"]'),
('159ab7c3-73d1-4b64-a83d-d09b37619b22','次韻真歇和尚圓覺經頌一十四首 金剛藏菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','黄金出鑛斷前疑，岸走舟安覺所欺。',64,'全唐诗/poet.song.101000.json','["黄金出鑛斷前疑，岸走舟安覺所欺。", "動目是渠摇湛水，聚螢無我灼須彌。", "翳消便見飛華盡，機迅將知擊電遲。", "識得堆堆庵內主，外魔那得到藩籬。"]'),
('15da283c-e1ec-4367-adad-c067ae28b005','次韻真歇和尚圓覺經頌一十四首 彌勒菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','癡根愛種力鋤除，一段靈明是舊基。',64,'全唐诗/poet.song.101000.json','["癡根愛種力鋤除，一段靈明是舊基。", "插草天人深會意，拈華尊者笑開眉。", "魚行大士須珍重，布袋憨僧且伏惟。", "處處鼻頭相撞磕，唯心境界你謾誰。"]'),
('d6b44d49-ef9e-4b93-935c-163206d6cfe3','次韻真歇和尚圓覺經頌一十四首 清凈慧菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','覺了前前非處難，而今步步到長安。',64,'全唐诗/poet.song.101000.json','["覺了前前非處難，而今步步到長安。", "色心㳷合無絲路，法性圓融沒許般。", "箇事本來元脫灑，幾人到此出顢頇。", "妄亡起滅功成也，應笑風旛動剎竿。"]'),
('97fb76de-9fc6-4998-ac98-dbeef077c49f','次韻真歇和尚圓覺經頌一十四首 威德自在菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','門開三觀莫遲留，得路行行到始休。',64,'全唐诗/poet.song.101000.json','["門開三觀莫遲留，得路行行到始休。", "鑑像照心無所住，樓鐘出礙有來由。", "頂中具眼如天主，肘後分符似國侯。", "應世度生遊幻海，月船風棹駕濤頭。"]'),
('e1ff96f6-642a-499a-af43-8e6acb59c0cb','次韻真歇和尚圓覺經頌一十四首 辯音菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','妙圓單複絕中邊，五五機輪互換難。',64,'全唐诗/poet.song.101000.json','["妙圓單複絕中邊，五五機輪互換難。", "絃管調來聲律合，梭絲織出錦文觀。", "身心一一能分應，手眼千千不可謾。", "似付鹽梅巖叟用，和羹無復見鹹酸。"]'),
('b2faf486-bf92-4704-9329-89379e4c68fa','次韻真歇和尚圓覺經頌一十四首 凈諸業障菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','證語由來把柄長，重重脫處雪加霜。',64,'全唐诗/poet.song.101000.json','["證語由來把柄長，重重脫處雪加霜。", "衆生相在猶流浪，壽命根除自息狂。", "退骨龍能將雨去，蛻鱗鯤復得風翔。", "郢人斲盡蠅泥也，方見元初鼻孔光。"]'),
('d23e68ec-a30e-451d-a4da-4281760c9e32','次韻真歇和尚圓覺經頌一十四首 普覺菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','藥病相攻雙去難，心華開發自家禪。',64,'全唐诗/poet.song.101000.json','["藥病相攻雙去難，心華開發自家禪。", "天真歷歷非修證，日用堂堂豈授傳。", "高步丹霄知得計，止啼黄葉信成權。", "底時屑屑行泥滓，可笑蝸牛自涴涎。"]'),
('d3feecd1-b84a-4c3d-956e-f3b6bda4d704','次韻真歇和尚圓覺經頌一十四首 圓覺菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','選場隨手取標毬，長短期中入社流。',64,'全唐诗/poet.song.101000.json','["選場隨手取標毬，長短期中入社流。", "覺後繩繩機自脫，悟來密密類難收。", "十分飽足雪山草，一色渾成露地牛。", "風掃水天塵翳盡，蘆華相照月明秋。"]'),
('2e614a32-dd96-4bca-a9f1-2f11f4f4c38a','次韻真歇和尚圓覺經頌一十四首 賢善首菩薩章','釋正覺','宋','宋诗','song-poetry','','[]','陀羅尼句覺皇宣，一略聞名勝施緣。',64,'全唐诗/poet.song.101000.json','["陀羅尼句覺皇宣，一略聞名勝施緣。", "端見髓心相付囑，莫將耳口作流傳。", "頓機做處天飛電，大器任時海納川。", "不是老婆情分切，肯留文字破尼乾。"]'),
('7b02d566-2a34-4a7c-987f-d505b2634b39','次韻真歇和尚圓覺經頌一十四首 總頌','釋正覺','宋','宋诗','song-poetry','','[]','木童吟處槁回春，箇裏莊嚴功德林。',64,'全唐诗/poet.song.101000.json','["木童吟處槁回春，箇裏莊嚴功德林。", "垂手斷崖知路活，藏身空劫忌機沈。", "未翻識浪無多子，不挂唇皮有一音。", "佛祖契心言迹外，炷香清坐與追尋。"]'),
('dd4d8f88-45ea-4d8c-9181-9e485e35c4c9','別洪山預和尚','釋正覺','宋','宋诗','song-poetry','','[]','般遊念未穩，又別住山人。',60,'全唐诗/poet.song.101000.json','["般遊念未穩，又別住山人。", "雁影水中字，雲心江上賓。", "同條如是住，千里亦成鄰。", "深翠一枝璽，腐紅五合陳。", "回途登鳥道，華木故園春。"]'),
('c757a090-e321-400f-86b3-077c3209e9df','別滿首座','釋正覺','宋','宋诗','song-poetry','','[]','丹山鳳窟冷相依，慚愧如今羽翼齊。',64,'全唐诗/poet.song.101000.json','["丹山鳳窟冷相依，慚愧如今羽翼齊。", "雲外翔鳴同頡頏，林間啄步暫分携。", "玉華銜處天容曉，珠樹棲時月影低。", "引喙醴泉期後會，殆將新語濯塵泥。"]'),
('53a88da0-d13c-433d-a2f6-2c1bbc44c447','別環首座','釋正覺','宋','宋诗','song-poetry','','[]','雪立空庭疇墮賓，丹山握手履芳塵。',64,'全唐诗/poet.song.101000.json','["雪立空庭疇墮賓，丹山握手履芳塵。", "石人破曉初移位，玉女羞明却轉身。", "去意江湖頻挂夢，回頭棠棣一成春。", "叢林衰色待膏沃，側耳風霆起蟄鱗。"]'),
('4eef1983-2602-44b1-8224-853115349eb8','與楷知倉','釋正覺','宋','宋诗','song-poetry','','[]','米坊能者較些些，七百僧中獨作家。',64,'全唐诗/poet.song.101000.json','["米坊能者較些些，七百僧中獨作家。", "半夜傳來衣有據，機前收得鏡無瑕。", "祖師只麽閑舂碓，若子如今莫撒沙。", "古井先秋念枯冷，金繩釣出玉蝦蟆。"]'),
('be3eee02-0c13-4303-a11b-b4ae3dbe70d0','與因典座','釋正覺','宋','宋诗','song-poetry','','[]','胸中行脚事分明，親見芙蓉綴晚英。',64,'全唐诗/poet.song.101000.json','["胸中行脚事分明，親見芙蓉綴晚英。", "黑馬踏霜元不迹，白魚吹水了無聲。", "投機曾弄無須鎖，出手相扶折脚鐺。", "去米去沙還未可，要須偏正竝頭行。"]'),
('a7cd596b-7238-4ac9-bda8-87f63daaa2b5','與白表白','釋正覺','宋','宋诗','song-poetry','','[]','密室分燈光焰焰，空壺著月影沈沈。',32,'全唐诗/poet.song.101000.json','["密室分燈光焰焰，空壺著月影沈沈。", "誰言古殿今無佛，只在其時來梵音。"]'),
('3f3c9e85-685f-458e-833c-421022a4f7c5','十月朔與法上人南谷行  其一','釋正覺','宋','宋诗','song-poetry','','[]','拖策鳴林遊興濃，要將丘壑醉青瞳。',64,'全唐诗/poet.song.101000.json','["拖策鳴林遊興濃，要將丘壑醉青瞳。", "黄華尚媚秋餘日，錦樹那禁霜後風。", "轉岫虵行岐屈曲，斷崖虹卧水丁東。", "誰慳劇味平生事，分付飲茶談笑中。"]'),
('f3fc4754-6f5b-4a25-b739-6c5410939602','十月朔與法上人南谷行  其二','釋正覺','宋','宋诗','song-poetry','','[]','一筇雙屨征具簡，幽討勝友賓棲深。',64,'全唐诗/poet.song.101000.json','["一筇雙屨征具簡，幽討勝友賓棲深。", "與公半夜丘壑語，慰我平生麋鹿心。", "倒榻雅成山水夢，落泉寒作絲桐音。", "歸歟城寺禪膚粟，定是流想來家林。"]'),
('a54e2e37-1d57-44fe-b7aa-db9266dd1a42','別覺知藏','釋正覺','宋','宋诗','song-poetry','','[]','一從豆顆爆寒灰，頭角崢嶸頂目開。',64,'全唐诗/poet.song.101000.json','["一從豆顆爆寒灰，頭角崢嶸頂目開。", "碧玉盤中珠宛轉，瑠璃殿上月徘徊。", "木人顧影當明去，石女披雲半夜來。", "偏正功圓須轉位，入廛垂手類難該。"]'),
('6de0cf58-3b20-4ee8-a392-690f91bd7a40','與諾侍者','釋正覺','宋','宋诗','song-poetry','','[]','夢回茶碗手親扶，雅意溈山轉道樞。',64,'全唐诗/poet.song.101000.json','["夢回茶碗手親扶，雅意溈山轉道樞。", "自喚主人酬一諾，誰違尊者應三呼。", "死生到日還能否，辜負當年是有無。", "妙得古人行履處，了無些事作工夫。"]'),
('31f3ce40-cdfd-4118-a570-4970c276868c','與杲侍者','釋正覺','宋','宋诗','song-poetry','','[]','道吾當年不肯道，漸源中路沒商量。',32,'全唐诗/poet.song.101000.json','["道吾當年不肯道，漸源中路沒商量。", "先師靈骨今猶在，無用扶鍬上法堂。"]'),
('eef52cf1-26ec-48d9-8ac9-c294c8bcf04b','送通禪者之襄陽','釋正覺','宋','宋诗','song-poetry','','[]','疏巢凄冷卧西柯，夢覺歸思遽許多。',64,'全唐诗/poet.song.101000.json','["疏巢凄冷卧西柯，夢覺歸思遽許多。", "風雨江頭亂雁字，家山塢外懸漁蓑。", "白楊村落龐居士，青石浮圖藴大哥。", "倦倚蒼松坐凉夕，兔推明月下星河。"]'),
('34c68734-6c34-471d-bbcc-152ff3367baf','宗知客','釋正覺','宋','宋诗','song-poetry','','[]','虛明一念洗粉埃，眼在髑髏眉底開。',64,'全唐诗/poet.song.101000.json','["虛明一念洗粉埃，眼在髑髏眉底開。", "玉鳳銜華春不老，金雞喚月夢初回。", "匣中古劍光干斗，壁上寒梭蟄破雷。", "佛祖入廛成化事，那嫌榼𣜂鼻頭堆。"]'),
('5c058c3d-3c80-4dd9-9bc1-5eebdc531fa2','與初禪人','釋正覺','宋','宋诗','song-poetry','','[]','洞下家風虛一著，白牛耕斷青山脚。',44,'全唐诗/poet.song.101000.json','["洞下家風虛一著，白牛耕斷青山脚。", "而今何處不逢渠，鼻孔纍垂相撞磕。", "阿剌剌，始信從來無縛脫。"]'),
('d78422fe-9bd9-4fdb-ab85-f3ca0c042a52','與充維那','釋正覺','宋','宋诗','song-poetry','','[]','機梭未動若爲顔，一點虛靈入道環。',64,'全唐诗/poet.song.101000.json','["機梭未動若爲顔，一點虛靈入道環。", "明月光中窺自己，白雲影外到家山。", "金鼇轉側夜潮落，玉馬嘶鳴春信還。", "得手應心無不可，脫然時事豈相關。"]'),
('c37f72d0-f15d-4cf6-afaa-099151409425','送僧歸豫章省親','釋正覺','宋','宋诗','song-poetry','','[]','賓繭風枝夢不寧，夜堂思對老人星。',64,'全唐诗/poet.song.101000.json','["賓繭風枝夢不寧，夜堂思對老人星。", "一心歸去事萱草，千里相求鳴鶺鴒。", "樹樹丹楓金墮葉，叢叢黄葉雪浮汀。", "西山秀骨濯秋雨，窗戶卷簾分遠青。"]'),
('674d93a9-70c8-4c72-a1e1-dc98c4475fe5','與簡禪人','釋正覺','宋','宋诗','song-poetry','','[]','虛明道洗壯心秋，畦服蒙顱下板頭。',32,'全唐诗/poet.song.101000.json','["虛明道洗壯心秋，畦服蒙顱下板頭。", "定起要看星漢兔，回機失却雪山牛。"]'),
('85f7afed-26b7-4caa-842b-a83db28f9f6c','與演侍者','釋正覺','宋','宋诗','song-poetry','','[]','白鷗定怪盟事寒，杖蔾投社不多難。',64,'全唐诗/poet.song.101000.json','["白鷗定怪盟事寒，杖蔾投社不多難。", "葦風華雪秋著岸，船月蓬霜夜轉灘。", "丘壑身心徒役夢，江湖臭味賦遊般。", "它時衣外傳來物，喚得回頭倒剎竿。"]'),
('53f52d4b-fde7-4008-a7ae-adf877cc80c0','顯禪人求頌','釋正覺','宋','宋诗','song-poetry','','[]','顯處機須隱，忙時智自閒。',48,'全唐诗/poet.song.101000.json','["顯處機須隱，忙時智自閒。", "泥牛初出海，玉馬復臨關。", "寒水澄涵月，流雲靜倚山。", "回途分化柄，不作舊家慳。"]'),
('cebfc4de-846c-43bb-9f2e-1274f99c0713','蒙禪人丐麥求頌','釋正覺','宋','宋诗','song-poetry','','[]','杖頭挂鉢丐丹丘，力破清貧一點憂。',64,'全唐诗/poet.song.101000.json','["杖頭挂鉢丐丹丘，力破清貧一點憂。", "紅雨幾番華事老，黄雲萬頃麥家秋。", "對緣手眼通身是，應物機輪轉處幽。", "歸理韶陽餬餅話，肚皮束篾飽齁齁。"]'),
('e7349b4f-d256-4da6-bb75-4304524ef936','送緣上人持鉢','釋正覺','宋','宋诗','song-poetry','','[]','緣丐人間一錫飛，蒼巖煙膩雪初晞。',64,'全唐诗/poet.song.101000.json','["緣丐人間一錫飛，蒼巖煙膩雪初晞。", "風絲未許鬧禪眼，雲錦將看落化機。", "自勉叢林供食鉢，誰嫌塵土翳征衣。", "歸來僧飽上方飯，相伴春山歌采薇。"]'),
('8e365b30-a4fc-4a0c-8ed6-71a28dc4866b','與法上人南谷過黄氏居  其一','釋正覺','宋','宋诗','song-poetry','','[]','淡煙蒼樹水濺濺，黄氏初平已得仙。',32,'全唐诗/poet.song.101000.json','["淡煙蒼樹水濺濺，黄氏初平已得仙。", "滿地癡羊不收拾，夕陽零亂繞籬眠。"]'),
('cd7c8041-1dbd-4a16-bd8a-550088c822be','與法上人南谷過黄氏居  其二','釋正覺','宋','宋诗','song-poetry','','[]','亂石深雲尋野泉，老儂怪我地行仙。',32,'全唐诗/poet.song.101000.json','["亂石深雲尋野泉，老儂怪我地行仙。", "鍾情山水醇於酒，今夜竹床成醉眠。"]'),
('27fa6dc6-f3d5-4c80-a170-9c16d7a1db5f','與輔禪人','釋正覺','宋','宋诗','song-poetry','','[]','方遊捋遍虎髭鬚，空劫壺中探有無。',64,'全唐诗/poet.song.101000.json','["方遊捋遍虎髭鬚，空劫壺中探有無。", "風月滿頭功未轉，江山入骨病難扶。", "針投芥粒機非爽，絃續鸞膠道不枯。", "歸去叢林看儀羽，丹山出處九包雛。"]'),
('46a6e3bc-29e5-447c-8db2-41010a8fee45','與嵩禪人','釋正覺','宋','宋诗','song-poetry','','[]','烏石嶺頭相見，長生路上常逢。',28,'全唐诗/poet.song.101000.json','["烏石嶺頭相見，長生路上常逢。", "正是遊山時節，落華芳草蒙茸。"]'),
('e0c4f25e-bbe6-4226-9f13-8cdcf45628c2','次韻端楞伽與生首座','釋正覺','宋','宋诗','song-poetry','','[]','縛茨枯坐九江東，鏡像虛融方寸中。',64,'全唐诗/poet.song.101000.json','["縛茨枯坐九江東，鏡像虛融方寸中。", "舜若多身禪夜看，母陀羅臂用時通。", "緣生誰兆有非有，寂照自知空不空。", "道契觀音斯善應，蕭蕭竹雨雜松風。"]'),
('bc217815-9ce7-452d-8904-f02f30ad4edd','假日山行','釋正覺','宋','宋诗','song-poetry','','[]','平生胸中雲外峯，有閒便與扶瘦筇。',64,'全唐诗/poet.song.101000.json','["平生胸中雲外峯，有閒便與扶瘦筇。", "但知一世丘壑味，想得十分猿鳥從。", "明見秋容山洗雨，清可人意風吟松。", "歸來遊興散不盡，誰杵喚月黄昏鐘。"]'),
('94ad9bf6-6dd8-4e36-be1e-cf6a80badd11','別陸尚書','釋正覺','宋','宋诗','song-poetry','','[]','千里同風德不孤，心秋覺月照空壺。',64,'全唐诗/poet.song.101000.json','["千里同風德不孤，心秋覺月照空壺。", "兩頭坐斷何生死，一點圓明異有無。", "木馬寒嘶青草塢，泥牛春種白雲區。", "見聞佛事誰迎背，用處全機道轉樞。"]'),
('610acdfd-853b-44ea-bdc8-33f851e6475d','超然居士得得問道於寶峰祥禪師且欲歸歌長篇以謝予偕其行見挽以和漬筆說句繼之','釋正覺','宋','宋诗','song-poetry','','[]','門門通徹長安道，信手拈來還恰好。',152,'全唐诗/poet.song.101000.json','["門門通徹長安道，信手拈來還恰好。", "脚跟踏著趙州關，丈六金身一莖草。", "我初相會箇中人，法法圓通見懷抱。", "杖屨追隨來道場，不學癡禪事關掃。", "青山白雲一徑通，行行鳥道誰尋討。", "寶峯師是馬馰兒，相得而今恨不早。", "吸盡西江居士龐，喚回豎指俱胝老。", "泥牛力耕空劫春，木人捧出形山寶。", "罷捋虎鬚歸去來，荆棘林中任起倒，午日麗天光杲杲。"]'),
('585e9d82-e0cb-4e47-98b8-5155280d8e75','過王彥與郊居','釋正覺','宋','宋诗','song-poetry','','[]','晨露晞時桑柘，宿雲歛處溪山。',28,'全唐诗/poet.song.101000.json','["晨露晞時桑柘，宿雲歛處溪山。", "摩詰畫圖未卷，淵明農事初閒。"]'),
('392b02bb-240e-48c1-967a-69f4610eaec6','與福州滿禪人','釋正覺','宋','宋诗','song-poetry','','[]','而今別後記丁寧，曹洞家風句未形。',64,'全唐诗/poet.song.101000.json','["而今別後記丁寧，曹洞家風句未形。", "月滿鳳林寒不夢，年深龜殻灼猶靈。", "沈沈莫觸蛇頭毒，的的須明犀角星。", "便與放開聊展手，那時相見望州亭。"]'),
('4f08fd7b-cdac-416b-9c89-60ff3161b937','投食山家','釋正覺','宋','宋诗','song-poetry','','[]','霜晨蔾杖起孤禪，乞食山家圖省緣。',64,'全唐诗/poet.song.101000.json','["霜晨蔾杖起孤禪，乞食山家圖省緣。", "斜徑順風鳴竹火，飛甍迷眼映松煙。", "秋羹木鼈有真味，午飯樹雞無俗羶。", "誰謂客床卧不穩，我無支遁買山錢。"]'),
('cc043859-1ae2-4da5-a253-2dc6793e4ded','禮大陽明安塔道中得句','釋正覺','宋','宋诗','song-poetry','','[]','佳處軫遊念，芒鞋筇杖俱。',48,'全唐诗/poet.song.101000.json','["佳處軫遊念，芒鞋筇杖俱。", "溪寒卧虹餓，路暗垂雲腴。", "岡樹鳩呼雨，田家雞告晡。", "此心亮誰語，三繞石浮屠。"]'),
('6ff58604-4c99-47f7-b7cc-687ac857d64d','教禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','歷歷樞中轉化機，出門氣象履芳時。',64,'全唐诗/poet.song.101000.json','["歷歷樞中轉化機，出門氣象履芳時。", "溪光麗濯紅錦段，風柳細撚黄金絲。", "空空不礙渾亡我，處處相逢却是誰。", "會得賓頭盧見佛，向人賣弄有長眉。"]'),
('eaaa5c3f-b31e-411b-b76d-24d5bcca2c9e','妙禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','劫壺浩浩洗魔緣，妙處真觀自見前。',64,'全唐诗/poet.song.101000.json','["劫壺浩浩洗魔緣，妙處真觀自見前。", "的的未萌明賓際，靈靈無得入深禪。", "風摶海運鯤將蛻，月皎沙寒鷺不眠。", "觸事投諧能轉變，何妨大浪駕空船。"]'),
('3ab3c97e-42ae-4588-8805-8f4b717ed36d','折桂章首座近自雙泉來因作句與之','釋正覺','宋','宋诗','song-poetry','','[]','家林穩卧一巢雲，厭作梁家庵底賓。',64,'全唐诗/poet.song.101000.json','["家林穩卧一巢雲，厭作梁家庵底賓。", "折桂手舒寒觸月，銜珠眼合夢遊春。", "庭除不見雨華鳥，麋鹿能來呼谷神。", "五老芳鄰歸問訊，笑談相對白頭新。"]'),
('68291c44-554f-468a-b496-b8f94cb92dc5','宣和甲辰歲開十日予欲束衣隨淮水東下錦官常禪人且合掌請語因留三絕  其一','釋正覺','宋','宋诗','song-poetry','','[]','麓華聯蕾破春紅，慚愧無私造化功。',32,'全唐诗/poet.song.101000.json','["麓華聯蕾破春紅，慚愧無私造化功。", "誰怕滿頭椿歲月，要聽啼鳥說家風。"]'),
('36627174-1348-4014-aa1d-692c0935f623','宣和甲辰歲開十日予欲束衣隨淮水東下錦官常禪人且合掌請語因留三絕  其二','釋正覺','宋','宋诗','song-poetry','','[]','蔬腸那著一星愁，但覺春眠粥似稠。',32,'全唐诗/poet.song.101000.json','["蔬腸那著一星愁，但覺春眠粥似稠。", "夢外尋盟何處是，荻洲稚子綠排頭。"]'),
('712c6463-91b3-4feb-8b1d-98d5c95cbca9','宣和甲辰歲開十日予欲束衣隨淮水東下錦官常禪人且合掌請語因留三絕  其三','釋正覺','宋','宋诗','song-poetry','','[]','恬然誰作去留心，月下滄波風過林。',32,'全唐诗/poet.song.101000.json','["恬然誰作去留心，月下滄波風過林。", "相別相逢定何所，明明向道只如今。"]'),
('21613f2b-26e8-4814-bc78-fdff64b8cff2','送仝座主歸上黨  其一','釋正覺','宋','宋诗','song-poetry','','[]','月兔含清欲噴霜，客懷陳習作歸翔。',64,'全唐诗/poet.song.101000.json','["月兔含清欲噴霜，客懷陳習作歸翔。", "雖云掃盡名言垢，我笑熏成知見香。", "聚石爲徒頭易點，悟空能講義難量。", "到家握麈隨宜說，莫對餘機揮界方。"]'),
('79c6a76e-4f8e-4017-9de3-6cc1ae8d390a','送仝座主歸上黨  其二','釋正覺','宋','宋诗','song-poetry','','[]','覺海長鯨作蛻翔，青天端以背磨光。',64,'全唐诗/poet.song.101000.json','["覺海長鯨作蛻翔，青天端以背磨光。", "胸中浩浩吞雲夢，眉際津津秀太行。", "靜榻每來成友語，孤筇它往咽人腸。", "後將訪我先傳雁，爲薙別來三徑荒。"]'),
('3be58d7d-ccd9-4bb2-9c5b-c34ec7b0a80e','送仝座主歸上黨  其三','釋正覺','宋','宋诗','song-poetry','','[]','夜明簾外月天霜，衲子還家機事忘。',64,'全唐诗/poet.song.101000.json','["夜明簾外月天霜，衲子還家機事忘。", "枯木吟雲須內照，死蛇含毒更隄防。", "聞琴起舞飲光習，放鏡迷頭演若狂。", "好是重來斲蠅翼，祖師鼻孔要生光。"]'),
('04699c95-24ce-4211-8887-1e5a6312687f','大明庵留偈','釋正覺','宋','宋诗','song-poetry','','[]','略彴橫門下轉流，挂窗山在屋檐頭。',32,'全唐诗/poet.song.101000.json','["略彴橫門下轉流，挂窗山在屋檐頭。", "大明古意是時節，霜夜月堂簾上鈎。"]'),
('b1833a21-6fc8-40a0-9140-404551309ef3','心知莊求頌','釋正覺','宋','宋诗','song-poetry','','[]','耕雲種月自由人，田地分明契券真。',64,'全唐诗/poet.song.101000.json','["耕雲種月自由人，田地分明契券真。", "黄獨將看炊作飯，白牛今已牧來純。", "钁頭活計時時用，物外家風處處親。", "禾黍十分秋可望，飽叢林漢著精神。"]'),
('c2658536-06fe-4878-b983-0c1a613b0047','與腖禪人','釋正覺','宋','宋诗','song-poetry','','[]','白蘋風作江頭秋，青鳥夢隨沙水流。',56,'全唐诗/poet.song.101000.json','["白蘋風作江頭秋，青鳥夢隨沙水流。", "清興十分蓬上月，滿船載入蘆華洲。", "斯適意，去來休。", "六鼇合負歸來也，煙浪雪飜收釣鈎。"]'),
('6ac31577-b13f-414e-bee8-320f4c9f237a','純白禪人求頌','釋正覺','宋','宋诗','song-poetry','','[]','明月蘆華未得如，清光自照本來虛。',64,'全唐诗/poet.song.101000.json','["明月蘆華未得如，清光自照本來虛。", "十方坐斷須拈帽，一色功圓要放鋤。", "轉背石人歸位後，擡頭玉馬過關初。", "塵塵剎剎見身相，方信曹山井覷驢。"]'),
('7225c13b-b7ea-498a-9001-61204d000695','泐潭雲庵偶作','釋正覺','宋','宋诗','song-poetry','','[]','曦色雲庵半堵紅，霜林初暖鳥啼風。',32,'全唐诗/poet.song.101000.json','["曦色雲庵半堵紅，霜林初暖鳥啼風。", "下知人在蘿窗裏，瞑目爐薰百慮空。"]'),
('b40cc19e-97d1-4352-bdac-090d9a72d6fe','次韻超然與折桂覺大師兼簡方丈老','釋正覺','宋','宋诗','song-poetry','','[]','束肚三條篾，恬然卧家林。',48,'全唐诗/poet.song.101000.json','["束肚三條篾，恬然卧家林。", "機深大仰寂，用捷長沙岑。", "空壑溪鳴玉，疏筠月漏金。", "東山師叔在，此道未浮沈。"]'),
('85f1960c-2cf7-48a6-9ad0-1826570be43c','借雪竇韻送超然居士趙表之時在泐潭','釋正覺','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一口吸盡西江水，馬師家風擢然起。',128,'全唐诗/poet.song.101000.json','["一口吸盡西江水，馬師家風擢然起。", "老龐俯伏嗣芳塵，古也今也誰如此。", "超然道與若人交，南遊浩意未相饒。", "風清骨秀眼寒碧，玉井冰壺凍不消。", "羌床孤卧凈名室，無住無依脫虛溢。", "淵然一默乃全提，不二門開肖當日。", "佛事圓來作歸想，出門歧路平如掌。", "到家兒女獨圞頭，相對無言得真賞。"]'),
('600affa6-9a98-48fd-a9f8-87f2b955e27d','南麓新居','釋正覺','宋','宋诗','song-poetry','','[]','山麓水濱竹木陰，我儂懶養靜居深。',64,'全唐诗/poet.song.101000.json','["山麓水濱竹木陰，我儂懶養靜居深。", "一生自足淡中味，三際那收閒底心。", "壑雲未成出岫意，松風能作下灘音。", "十分清興與誰共，想有沃洲支道林。"]'),
('531393f2-3afb-4061-931b-8b5ce65fc719','送嵩上人住庵  其一','釋正覺','宋','宋诗','song-poetry','','[]','世間塵雜長人癭，歸卧蘿龕霜月影。',64,'全唐诗/poet.song.101000.json','["世間塵雜長人癭，歸卧蘿龕霜月影。", "裏許離微妙轉功，玉壺夜汲瑠璃井。", "吾家語味嚼枯硬，醉飽回來雙眼冷。", "雲水明明得自由，六門事外誰關屏。"]'),
('da060315-1c0a-4475-bc2c-9cba258c46fd','送嵩上人住庵  其二','釋正覺','宋','宋诗','song-poetry','','[]','禪腹須來竹篾纏，好看水牯自耕田。',64,'全唐诗/poet.song.101000.json','["禪腹須來竹篾纏，好看水牯自耕田。", "布單不賣三千里，樹耳誰疑二十年。", "一句合頭尊旅會，十方坐斷正偏圓。", "它時投杖來相訪，且莫窮忙空豎拳。"]'),
('a485894c-8042-402b-b559-c3176e3478dc','送嵩上人住庵  其三','釋正覺','宋','宋诗','song-poetry','','[]','燒痕笋蕨富登春，誰解看承庵內人。',64,'全唐诗/poet.song.101000.json','["燒痕笋蕨富登春，誰解看承庵內人。", "天供異華功未盡，龍吟枯木病難泯。", "夜禪終作寒蟬蛻，晝卧何妨倦鳥伸。", "後日重來勘諸祖，阿誰鈎上赤梢鱗。"]'),
('2cb994c3-10de-43bb-acf6-e092fa58ae0d','榮上人發心知羅漢堂辦茶油事乞頌','釋正覺','宋','宋诗','song-poetry','','[]','這開夢覺底因緣，佛佛心同亡後先。',64,'全唐诗/poet.song.101000.json','["這開夢覺底因緣，佛佛心同亡後先。", "一點靈明三世外，十分妙凈萬機前。", "琢磨自得叢林下，遊戲何妨百草顛。", "塵剎縱橫俱化事，起家人只奮空拳。"]'),
('2c574390-df5b-4f82-9a1e-f565e5fb73f3','心上人乞食求頌','釋正覺','宋','宋诗','song-poetry','','[]','去去之人乞食心，春風浩蕩洗叢林。',64,'全唐诗/poet.song.101000.json','["去去之人乞食心，春風浩蕩洗叢林。", "松蹊香膩糝黄粉，竹塢清癯包玉簪。", "炊甑分珠齋鉢滿，凈瓶汲月夜塘深。", "歸來磨濯光明在，向道塵泥不涴金。"]'),
('ed73f400-8faf-4687-b4e1-2681dc3df3a8','訪楊才叔不遇留偈齋舍','釋正覺','宋','宋诗','song-poetry','','[]','呼筇起寂下雲居，寒麓回春尋友于。',64,'全唐诗/poet.song.101000.json','["呼筇起寂下雲居，寒麓回春尋友于。", "煙染草芒三徑暗，雪晞麥脚一鉏濡。", "欲求真語滌塵想，那畏峭風生粟膚。", "不見詩郎歸悵怏，清癯時對石菖蒲。"]'),
('1e10df2a-5db5-4c8f-ad8e-a4f394d7a5fa','解首座職事書記相招以偈力辭','釋正覺','宋','宋诗','song-poetry','','[]','原鴒能作歸呼音，暮風墮葉秋在林。',64,'全唐诗/poet.song.101000.json','["原鴒能作歸呼音，暮風墮葉秋在林。", "路沙漠漠水潏潏，夜色冉冉山陰陰。", "坐冠多士自省短，挽袂乃友相知深。", "乞與高閒償夙歉，閉門穩卧舒疲心。"]'),
('de8d68c1-0c80-4337-9adf-2137c70648f0','偶成示衆','釋正覺','宋','宋诗','song-poetry','','[]','楊柳斜風力弱，芭蕉擊雨聲寒。',28,'全唐诗/poet.song.101000.json','["楊柳斜風力弱，芭蕉擊雨聲寒。", "莫把見聞作對，誰將聲色相瞞。"]'),
('784bcbbf-0bd8-44ab-9ee5-d0a0857878d6','成侍者求頌','釋正覺','宋','宋诗','song-poetry','','[]','真源不皺風，月兔影澄水。',48,'全唐诗/poet.song.101000.json','["真源不皺風，月兔影澄水。", "枯情但恬如，默默飽禪味。", "家風乃廓然，當年第一義。", "機輪轉有方，萬化出彈指。"]'),
('4dfd7490-cb85-4f95-bce7-ea35c1b38312','庚子冬二十八日天意晴和與止上人同南麓行橫岡轉流長作清響陰溪直木寒無悴容到竹林人家飲茶而還','釋正覺','宋','宋诗','song-poetry','','[]','雲麓勝處夙未到，清行興銳忘崎嶔。',64,'全唐诗/poet.song.101000.json','["雲麓勝處夙未到，清行興銳忘崎嶔。", "誰無瘦杖少扶力，我與幽人同賞心。", "壑津軟緣自宛轉，岸樹老碧長陰森。", "溪西乞火煮茶去，竹裏人家齋磬音。"]'),
('20955f77-6da4-4fdd-88f2-80b2aec05f97','別五祖山悅衆','釋正覺','宋','宋诗','song-poetry','','[]','東山聚散亦夤緣，華吐芳姿柳鎖煙。',64,'全唐诗/poet.song.101000.json','["東山聚散亦夤緣，華吐芳姿柳鎖煙。", "肯處根塵非一一，用時手眼恰千千。", "塔中祖有相傳事，嶺外人元不會禪。", "後日能來圓此話，未嫌敲枕喚春眠。"]'),
('bf635802-ea70-412e-a64c-aaaa80b26774','五祖將禪人求頌','釋正覺','宋','宋诗','song-poetry','','[]','東風吹斷濡華雨，淮上秀峯青可數。',64,'全唐诗/poet.song.101000.json','["東風吹斷濡華雨，淮上秀峯青可數。", "束屨欲尋南北山，卷衣又別東西祖。", "淵魚蒲鳥鬧一家，汀笋溪蔬甘兩箸。", "處處相逢記得麽，夜寒月在珊瑚樹。"]'),
('35af94f8-c8bd-457e-a169-02cf8c7de762','雲上人持鉢求頌','釋正覺','宋','宋诗','song-poetry','','[]','雲林風雪暮纖纖，滴瀝寒聲曉斷檐。',64,'全唐诗/poet.song.101000.json','["雲林風雪暮纖纖，滴瀝寒聲曉斷檐。", "一點丐心盟杖屨，十分化事入鎚鉗。", "霽光如拭月無礙，華錦落機春不嫌。", "百億分身遍塵剎，見聞蕭灑孰相黏。"]'),
('1b10faa3-a5c9-406e-abb6-c38275e51a0e','清上人持鉢求頌','釋正覺','宋','宋诗','song-poetry','','[]','苕霅溪頭柳眼青，食時持鉢衆香城。',64,'全唐诗/poet.song.101000.json','["苕霅溪頭柳眼青，食時持鉢衆香城。", "諸鄰定怪顛毛白，久客自憐心境清。", "重念雪寒親麈語，無忘水暖走鷗盟。", "飽叢林漢深相悉，笋蕨春山次第生。"]'),
('3c92b310-9eee-4437-878f-602a915744d3','送廣禪人','釋正覺','宋','宋诗','song-poetry','','[]','溫風促客下雲嶺，觸處無心即道遊。',64,'全唐诗/poet.song.101000.json','["溫風促客下雲嶺，觸處無心即道遊。", "得坐會當明變豹，出門須解倒騎牛。", "衝煙筇入青蘿徑，載月船回白鳥洲。", "中外夷猶功迹絕，㳷然天水一成秋。"]'),
('029a8a8d-3d6f-4ac4-97df-63ee9912af21','勤大師訪別作句贈之','釋正覺','宋','宋诗','song-poetry','','[]','若子能來過我門，端知良遂志彌敦。',64,'全唐诗/poet.song.101000.json','["若子能來過我門，端知良遂志彌敦。", "微塵破處得經卷，萬象紛時空眼根。", "與世支離誰惡意，怪人棱瘦自秋痕。", "歸興定到家林穩，山月流明洗夜昏。"]'),
('5d4cb7d7-3785-4bc8-b6be-f96b9c33a514','送金上人之水南','釋正覺','宋','宋诗','song-poetry','','[]','裏許由來懶荷擔，百草頭上何廉纖。',64,'全唐诗/poet.song.102000.json','["裏許由來懶荷擔，百草頭上何廉纖。", "半夜對月笑拍手，不見噴霜三脚蟾。", "劫空有句妙如許，公去誰余對眉語。", "後見太平堂上師，敢煩爲我分明舉。"]'),
('12b9182a-1f9c-4d53-9476-f10d302e31d2','送覺禪人','釋正覺','宋','宋诗','song-poetry','','[]','明月堂虛客不留，衡湘秀處賦清遊。',32,'全唐诗/poet.song.102000.json','["明月堂虛客不留，衡湘秀處賦清遊。", "回途復妙無遺影，天水從來一樣秋。"]'),
('fcca8065-2a8a-4560-b575-ef26e1b16bd6','送願上人歸鄉','釋正覺','宋','宋诗','song-poetry','','[]','溪頭買船歸鄂渚，一櫂清風夜蟾午。',108,'全唐诗/poet.song.102000.json','["溪頭買船歸鄂渚，一櫂清風夜蟾午。", "行盡韶山半月程，白雲兒就青山父。", "巖頭老子末後句，此到將知問不語。", "無縫塔前風色高，洞然不隔絲毫許。", "丁寧此去快須回，吾家之子要全才。", "不坐兩頭明暗路，偏中歸去正中來。", "阿呵呵，胸次風流知幾何。"]'),
('bbf6440f-763a-463e-a063-874db1646733','自廬山折桂旛竿原下望彭蠡湖握杖過前山僧舍說偈','釋正覺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','木落山骨瘦，水退沙痕隆。',48,'全唐诗/poet.song.102000.json','["木落山骨瘦，水退沙痕隆。", "漁舟弄江日，一葉浮軟紅。", "眼底事不俗，道人心若沖。", "旛竿頭進步，雲水展家風。"]'),
('ee694320-6792-4b55-b5e2-7a0b0d809c8d','出康廬渡江淮山拜諸祖塔道中作','釋正覺','宋','宋诗','song-poetry','','[]','澀舟沙水岸棱棱，岸上春泥深涴藤。',64,'全唐诗/poet.song.102000.json','["澀舟沙水岸棱棱，岸上春泥深涴藤。", "回首康山懷結社，真情祖室事傳燈。", "子孫亹亹雪庭可，衣鉢繩繩舂屋能。", "坐照少林牆面意，湛明心地瑩如冰。"]'),
('24ac98fd-9396-4dd7-80c2-5b086518f84d','與傳道者','釋正覺','宋','宋诗','song-poetry','','[]','殘毳編衣裹槁形，胸中底事獨醒醒。',64,'全唐诗/poet.song.102000.json','["殘毳編衣裹槁形，胸中底事獨醒醒。", "亡機沖應用時妙，活眼冷窺虛處靈。", "語秀錦雲春片段，氣清梅雪曉零星。", "而今功盡牛頭懶，華鳥不來風掃庭。"]'),
('b10f8113-c36c-4107-a4ef-948558f27d1a','題至遊庵兼簡庵中道友','釋正覺','宋','宋诗','song-poetry','','[]','真實人居遍十方，至遊處處露堂堂。',64,'全唐诗/poet.song.102000.json','["真實人居遍十方，至遊處處露堂堂。", "鵝於水器擇其乳，蜂在華房採得香。", "心鑑照中無垢翳，道環虛裏見神光。", "能來鬧市住三昧，鳥度長空迹不彰。"]'),
('9764f7b2-6127-4132-aecc-a630d58d7ed0','次韻傳道者且遊落星院','釋正覺','宋','宋诗','song-poetry','','[]','風立沙根膚粟頑，冷涵星石水灣灣。',64,'全唐诗/poet.song.102000.json','["風立沙根膚粟頑，冷涵星石水灣灣。", "登舟欲濟軒窗底，扶檻政疑圖畫間。", "雲拭山容蒼玉障，日浮江面紫金環。", "回頭五老相招我，林友無嫌夜扣關。"]'),
('2da826c6-67ec-4c65-9bea-527e446e03ac','懷上人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','胡床擁毳怯春寒，懷丐人行野雪乾。',64,'全唐诗/poet.song.102000.json','["胡床擁毳怯春寒，懷丐人行野雪乾。", "風信入華披錦段，月魂墮水濯金盤。", "浄名取飯亡多力，慈氏開門只一彈。", "妙得其中佛受用，頭頭成見不相瞞。"]'),
('e9d7a881-4502-4a82-8514-773b80bde684','一知殿化佛殿僧堂中燈油求頌','釋正覺','宋','宋诗','song-poetry','','[]','佛燈誰我續光明，果若蓮開大夢醒。',64,'全唐诗/poet.song.102000.json','["佛燈誰我續光明，果若蓮開大夢醒。", "香草有心持潔白，蘭膏無脚湛寒青。", "默耕化外那知夜，真照壺中不覺冥。", "家世兒孫傳底事，從教輝耀顯門庭。"]'),
('0054d98a-b67e-44b9-849b-a2bb4e4da335','亮禪人持鉢求頌','釋正覺','宋','宋诗','song-poetry','','[]','家林一錫飛，炊處青煙微。',48,'全唐诗/poet.song.102000.json','["家林一錫飛，炊處青煙微。", "嚴默起禪板，虛通轉化機。", "溪寒秋染色，月冷夜流輝。", "莫學西山亮，此行宜早歸。"]'),
('334a69ad-706c-4312-8568-3747ab35a290','初禪人持鉢求頌','釋正覺','宋','宋诗','song-poetry','','[]','佛事潛通興化門，用時斤斧莫成痕。',64,'全唐诗/poet.song.102000.json','["佛事潛通興化門，用時斤斧莫成痕。", "全機超出輪回際，一句拔除生死根。", "凉吹洗磨煩袂暑，素蟾排逐夜臺昏。", "鵝王引飲唯醇味，水乳斯分不我渾。"]'),
('e08789dc-d694-464b-9a56-d7fd187f94a5','過般若庵','釋正覺','宋','宋诗','song-poetry','','[]','重軒瘦立曲欄頭，島嶼青微冷枕流。',64,'全唐诗/poet.song.102000.json','["重軒瘦立曲欄頭，島嶼青微冷枕流。", "望眼解隨沙水轉，賞心真與岸雲浮。", "平分野色連延屋，點破江光相趁舟。", "般若空宗深得義，森羅元不礙人休。"]'),
('4a7a382e-dbf7-4fb5-b715-2763957c7a0a','登雲庵','釋正覺','宋','宋诗','song-poetry','','[]','屠蘇對碧溪，霜草露幽蹊。',48,'全唐诗/poet.song.102000.json','["屠蘇對碧溪，霜草露幽蹊。", "顧我丘壑醉，知誰塵土迷。", "蘿門窺窈窕，雲磴履高低。", "猿鳥未相棄，伴人煙樹棲。"]'),
('fa460551-6ec2-4049-8944-2de63737e9eb','送傳道者歸省母氏  其一','釋正覺','宋','宋诗','song-poetry','','[]','夜來霜嚇橘臍黄，乞與歸人懷冷香。',32,'全唐诗/poet.song.102000.json','["夜來霜嚇橘臍黄，乞與歸人懷冷香。", "到日跨門須轉却，白頭不是本生娘。"]'),
('31e6e176-ef4d-4bef-86be-1d6bec62d44a','送傳道者歸省母氏  其二','釋正覺','宋','宋诗','song-poetry','','[]','妙盡功圓轉處幽，若人真解倒騎牛。',32,'全唐诗/poet.song.102000.json','["妙盡功圓轉處幽，若人真解倒騎牛。", "雨蓑風笠舊行李，適意明明百草頭。"]'),
('1345e448-d08a-44b2-bfef-67374f42ffc9','圓禪者求頌','釋正覺','宋','宋诗','song-poetry','','[]','枯歇身心百不思，湛圓自照劫空時。',64,'全唐诗/poet.song.102000.json','["枯歇身心百不思，湛圓自照劫空時。", "妙明智鑑那留垢，虛廓靈機未度絲。", "的的髑髏看活眼，堂堂塵剎用閒眉。", "是須恁麽承當去，鼻孔纍垂識祖師。"]'),
('b341b342-37c1-4b56-87a5-d5f7518b5c11','斜川道上望廬山三絕  其一','釋正覺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','真味酣心倚瘦筇，蕭騷風嘯一蹊松。',32,'全唐诗/poet.song.102000.json','["真味酣心倚瘦筇，蕭騷風嘯一蹊松。", "無人共語圓通境，笑看雲吞石耳峯。"]'),
('af7134de-65c2-49a9-b219-28c95550d9a5','斜川道上望廬山三絕  其二','釋正覺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','青山放足溪轉腰，蓑翁理網兒摇舠。',32,'全唐诗/poet.song.102000.json','["青山放足溪轉腰，蓑翁理網兒摇舠。", "先生疇日騎魚去，岸上人家誰姓陶。"]'),
('f69238c8-cf69-4045-bb40-22b2c5ea5157','斜川道上望廬山三絕  其三','釋正覺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','水從烏石山前轉，人在斜川岸上行。',32,'全唐诗/poet.song.102000.json','["水從烏石山前轉，人在斜川岸上行。", "寂漠柴桑古祠下，我來無酒酹淵明。"]'),
('7dc872ee-ff8d-447d-be8d-be0de44e4970','妙湛大師求頌','釋正覺','宋','宋诗','song-poetry','','[]','妙則不粗，湛則不渾。',60,'全唐诗/poet.song.102000.json','["妙則不粗，湛則不渾。", "妙湛而照，瑩然亡痕。", "雲山是主，水月無根。", "瘦坐一默，虛融六門。", "竅作風籟，華含春恩。", "相承箇事，子子孫孫。"]'),
('27bb75e9-7dcf-423b-9428-0b24e6a99c29','次韻谷書記勝果院絕句','釋正覺','宋','宋诗','song-poetry','','[]','沙風漠漠卷煙湖，默默漁舟似有無。',32,'全唐诗/poet.song.102000.json','["沙風漠漠卷煙湖，默默漁舟似有無。", "五老回看更癡絕，渠應怪我得工夫。"]'),
('a7d498ad-94b6-462a-a5df-51c4dd158f7a','小師慧果丐鹽求頌','釋正覺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','可中滋味欠些些，成就廬山笋蕨家。',64,'全唐诗/poet.song.102000.json','["可中滋味欠些些，成就廬山笋蕨家。", "丐事子行黄葦渡，盟心人在白鷗沙。", "和羹戶戶俱煎鹵，掃雪村村欲沒靴。", "味及衲僧初偃月，圓通只箇是生涯。"]'),
('7362b441-104b-4f61-8a04-4ddae8812d1c','暉禪人丐鹽求頌','釋正覺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山淡薄已多時，誰與叢林洗敗姿。',64,'全唐诗/poet.song.102000.json','["廬山淡薄已多時，誰與叢林洗敗姿。", "爲愛海冰資菜味，不嫌春雨破華枝。", "仙陀婆事行行辨，舜若多身處處宜。", "快意截流船到岸，江頭風順看檣旗。"]'),
('e34c629b-3fa8-4003-a7de-a57b5e6b0ef3','送元上人過長蘆','釋正覺','宋','宋诗','song-poetry','','[]','阿祖江濱插葦枝，叢林蕃茂果臻斯。',64,'全唐诗/poet.song.102000.json','["阿祖江濱插葦枝，叢林蕃茂果臻斯。", "師門昆仲知名舊，緣法東西得面遲。", "沙上盟寒鷗怪晚，屋頭字草雁來時。", "月明古渡清鋪練，千里同風不隔絲。"]'),
('4ada38a0-7a69-4e86-8993-a7c008f2c8af','登雲頂庵峽口倚杖說偈','釋正覺','宋','宋诗','song-poetry','','[]','雪梯陟雲頂，來尋壞衲師。',48,'全唐诗/poet.song.102000.json','["雪梯陟雲頂，來尋壞衲師。", "破峽水一脈，挂松月半規。", "疏曠麋鹿性，厭飫丘壑姿。", "眷言携不去，遲立倚筇枝。"]'),
('174bbb27-e79f-4683-8202-e8fad9ca2aeb','景禪人求頌','釋正覺','宋','宋诗','song-poetry','','[]','混處還須轉側看，底時妙在一絲端。',64,'全唐诗/poet.song.102000.json','["混處還須轉側看，底時妙在一絲端。", "閑雲卷雨秋空闊，明月流輝夜水寒。", "棹破波光華細碎，夢驚蓬曉影團圞。", "真機分應頭頭准，却出黄蘆把釣竿。"]'),
('a5fc4558-6805-4629-a1e4-f0a33bf0ac95','次韻傳道者過香林','釋正覺','宋','宋诗','song-poetry','','[]','松烟竹藹細蹊通，清津白石寒瓏璁。',64,'全唐诗/poet.song.102000.json','["松烟竹藹細蹊通，清津白石寒瓏璁。", "艾禪真是甘蔗種，香林再吹薝蔔風。", "一溪冷引藩籬外，五老秀蹲懷抱中。", "寫目軒窗意幽遠，淡然消息不雷同。"]'),
('4daef6a7-8db0-48f8-98c0-50ec08dcd5e5','滿化士與圓通大衆出丐說偈送之','釋正覺','宋','宋诗','song-poetry','','[]','過門衲子上饒人，破我胡床默味真。',64,'全唐诗/poet.song.102000.json','["過門衲子上饒人，破我胡床默味真。", "道活髑髏前有地，用沖赤肉上無塵。", "盟心蘆笋白鷗社，夢眼華枝蝴蝶春。", "滿著圓通無盡意，四衢處處主中賓。"]'),
('28c55122-abbb-42d8-b6cd-2e17f2371414','送照禪人之湖南','釋正覺','宋','宋诗','song-poetry','','[]','衡岳迎秋翡翠瘦，瀟湘漾風瑠璃皴。',32,'全唐诗/poet.song.102000.json','["衡岳迎秋翡翠瘦，瀟湘漾風瑠璃皴。", "夜船載月急如箭，歸去來兮休問津。"]'),
('874acf4f-b732-4509-8e6f-858d8ca28634','還南麓舊居。','釋正覺','宋','宋诗','song-poetry','','[]','枝藤結伴得遊娛，懷習難寧尋舊居。',64,'全唐诗/poet.song.102000.json','["枝藤結伴得遊娛，懷習難寧尋舊居。", "雲水夢思孤榻穩，山林眼味四窗虛。", "秋衣未絮怯繁雨，午飯無鹽甘軟蔬。", "老境端來償底志，道同巢鳥與淵魚。"]'),
('62f53b6f-0dd0-431c-8674-c9da13b8d271','拜芭蕉情禪師','釋正覺','宋','宋诗','song-poetry','','[]','來謁芭蕉大仰孫，要明圜相識躭源。',64,'全唐诗/poet.song.102000.json','["來謁芭蕉大仰孫，要明圜相識躭源。", "橫山煙雨洗秋骨，掠面溪風吹暑痕。", "菖蒲葉瘦水石秀，枇杷樹密軒窗昏。", "阿誰床頭柱杖子，乞我款曲尋雲根。"]'),
('19536526-efa8-4eb0-8527-0d059be68a4f','芭蕉道中','釋正覺','宋','宋诗','song-poetry','','[]','雨暗岡頭客路，炊煙山裏人家。',28,'全唐诗/poet.song.102000.json','["雨暗岡頭客路，炊煙山裏人家。", "映水竹雞聒聒，飄風字雁斜斜。"]'),
('63839b56-0732-4132-8b93-4771d7facfe4','大陽道中','釋正覺','宋','宋诗','song-poetry','','[]','耿人胸次佳處，借力床頭古藤。',28,'全唐诗/poet.song.102000.json','["耿人胸次佳處，借力床頭古藤。", "風樹葉頹淅淅，秋山骨瘦棱棱。"]'),
('01280a8a-2939-4a6b-9a1c-6f2e9efdbb5d','禮明安塔二偈  其一','釋正覺','宋','宋诗','song-poetry','','[]','老阿師卒無嗣，石浮屠立有年。',28,'全唐诗/poet.song.102000.json','["老阿師卒無嗣，石浮屠立有年。", "丁寧金針玉線，慚愧鸞膠鳳絃。"]'),
('f277a18d-e9c9-47eb-82a9-c98e266610c0','禮明安塔二偈  其二','釋正覺','宋','宋诗','song-poetry','','[]','石床冷卧禪虎，階蕪秋跳草蟲。',28,'全唐诗/poet.song.102000.json','["石床冷卧禪虎，階蕪秋跳草蟲。", "有念耿懷陳事，無言凄立西風。"]'),
('ac95462f-cc6b-45d0-a53e-4642436181cb','玉壺閣頌','釋正覺','宋','宋诗','song-poetry','','[]','風霜磨洗秋空清，月浴星河分外明。',32,'全唐诗/poet.song.102000.json','["風霜磨洗秋空清，月浴星河分外明。", "默默玉壺中自照，家傳清白妙難名。"]'),
('81eb9d9c-bec6-4285-8fa4-be423b11c9ba','送僧歸撫州','釋正覺','宋','宋诗','song-poetry','','[]','不肯雲林伴冷凄，疏山歸謁矮闍梨。',32,'全唐诗/poet.song.102000.json','["不肯雲林伴冷凄，疏山歸謁矮闍梨。", "非枯樁句如明白，會要重來摩伏犀。"]'),
('c6702b12-230c-4b44-91d4-a76847cf09d7','送鹿門宗席頭','釋正覺','宋','宋诗','song-poetry','','[]','吉祥草織禪家供，一片瑠璃滑無縫。',64,'全唐诗/poet.song.102000.json','["吉祥草織禪家供，一片瑠璃滑無縫。", "門掩鱗鱗水不流，窗含冉冉雲初凍。", "坐寒風月蒲蘆秋，睡足江湖鷗鳥夢。", "而今卷處追昔人，隱隱猶懷鼻頭痛。"]'),
('356a7d49-4c97-4a45-b410-8a030c8796dc','籜庵頌','釋正覺','宋','宋诗','song-poetry','','[]','玉龍退殘鱗，編庵事枯兀。',48,'全唐诗/poet.song.102000.json','["玉龍退殘鱗，編庵事枯兀。", "禪棲錦鳳巢，道履霜蟾窟。", "飲茲明月津，濯彼微塵骨。", "五葉少林春，家風未湮沒。"]'),
('36f56296-28d7-456b-8f0e-ba746e22bf9a','登清凉三山亭','釋正覺','宋','宋诗','song-poetry','','[]','絮風花雨一春殘，未厭茲亭夜倚闌。',32,'全唐诗/poet.song.102000.json','["絮風花雨一春殘，未厭茲亭夜倚闌。", "隱隱三山抱江月，清凉境界露松寒。"]'),
('158ea29a-ade6-4224-8ef2-20746a8f6975','送圓上人之龍舒  其一','釋正覺','宋','宋诗','song-poetry','','[]','赤頭老師無揀擇，灊峯染翠吳塘碧。',32,'全唐诗/poet.song.102000.json','["赤頭老師無揀擇，灊峯染翠吳塘碧。", "明明萬法入齊觀，豁浄絲毫元不立。"]'),
('ce5d40e8-7ded-48c4-b9f8-338feffd8fbc','送圓上人之龍舒  其二','釋正覺','宋','宋诗','song-poetry','','[]','道人歸作山下賓，霜筇笋屨飄孤雲。',32,'全唐诗/poet.song.102000.json','["道人歸作山下賓，霜筇笋屨飄孤雲。", "到時春滿石牛谷，蔬蕨是誰相與分。"]'),
('7e919c7c-5203-449a-a894-746b892eb4fd','舉侍者求頌','釋正覺','宋','宋诗','song-poetry','','[]','秋風濯煩骨，日日覺清省。',48,'全唐诗/poet.song.102000.json','["秋風濯煩骨，日日覺清省。", "相與事枯禪，所養飽正命。", "老蟾浴星河，魂魄明耿耿。", "真味入誰腸，但知百念冷。"]'),
('253149e6-995d-4fdb-8826-25b19edbe26f','春意漸深送客至山麓田舍來往道中復逢法上人因作數語以記所見云  其一','釋正覺','宋','宋诗','song-poetry','','[]','青桑柳暗山前路，麥脚含滋一鋤雨。',32,'全唐诗/poet.song.102000.json','["青桑柳暗山前路，麥脚含滋一鋤雨。", "陽林桃是舊家春，冷眼靈雲合頭語。"]'),
('b191b1b0-7301-4f36-888e-7b99cf4efaa3','春意漸深送客至山麓田舍來往道中復逢法上人因作數語以記所見云  其二','釋正覺','宋','宋诗','song-poetry','','[]','雲陣纖纖洗花雨，深竹新聞子規語。',32,'全唐诗/poet.song.102000.json','["雲陣纖纖洗花雨，深竹新聞子規語。", "青山白雲吾定居，枯腸那著歸思慮。"]'),
('a98238d8-f95e-4a4d-ac63-8c20b9558122','春意漸深送客至山麓田舍來往道中復逢法上人因作數語以記所見云  其三','釋正覺','宋','宋诗','song-poetry','','[]','鳥拳花枝作春語，風日煥然晞宿雨。',32,'全唐诗/poet.song.102000.json','["鳥拳花枝作春語，風日煥然晞宿雨。", "水肥山翠木欣欣，芳事駢羅不容數。"]'),
('5360f749-7c72-411a-956e-f9f42da46373','春意漸深送客至山麓田舍來往道中復逢法上人因作數語以記所見云  其四','釋正覺','宋','宋诗','song-poetry','','[]','華蹊歸來鳥啼暮，庖舍炊煙卧風縷。',32,'全唐诗/poet.song.102000.json','["華蹊歸來鳥啼暮，庖舍炊煙卧風縷。", "西窗舊有竹肋床，伸足曲肱成栩栩。"]'),
('88c3e4a1-56fe-4b0d-afa8-f24357a417c5','春意漸深送客至山麓田舍來往道中復逢法上人因作數語以記所見云  其五','釋正覺','宋','宋诗','song-poetry','','[]','隔年相逢瘦驚許，風立溪頭少時語。',32,'全唐诗/poet.song.102000.json','["隔年相逢瘦驚許，風立溪頭少時語。", "緘情客上釣魚磯，四面垂雲一蓑雨。"]'),
('6d4605af-429c-43b4-a5f9-6b20b2bc3b2d','三印頌示衆  其一','釋正覺','宋','宋诗','song-poetry','','[]','印空印水印泥，無言桃李成蹊。',28,'全唐诗/poet.song.102000.json','["印空印水印泥，無言桃李成蹊。", "隨分納些稅賦，牧牛溪水東西。"]'),
('25428dd1-57b8-4f05-8f0d-d265f2b64668','三印頌示衆  其二','釋正覺','宋','宋诗','song-poetry','','[]','印泥印空印水，疾雷不及掩耳。',28,'全唐诗/poet.song.102000.json','["印泥印空印水，疾雷不及掩耳。", "豁然樓閣門開，消得輕輕彈指。"]'),
('8f8b7d57-3bd3-44eb-89d7-69c627361a9e','三印頌示衆  其三','釋正覺','宋','宋诗','song-poetry','','[]','印水印泥印空，誰傳祖稱家風。',28,'全唐诗/poet.song.102000.json','["印水印泥印空，誰傳祖稱家風。", "夢眼影迷一色，轉身體合全功。"]'),
('19c583eb-8e20-42cb-a481-3ebed3d95a68','機禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','塵剎分身看化機，青煙幾處午家炊。',64,'全唐诗/poet.song.102000.json','["塵剎分身看化機，青煙幾處午家炊。", "面牆坐照叢林事，持鉢丐緣雲水饑。", "出谷鳥傳春次第，漾舟人愛月相隨。", "歸來定有飽參句，笑解枯禪篾肚皮。"]'),
('134e362a-84e2-4ea1-b0a9-abf98dc85ff4','心禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','將看秋早瘦風林，禾卷黄雲副丐心。',64,'全唐诗/poet.song.102000.json','["將看秋早瘦風林，禾卷黄雲副丐心。", "妙印手中那外物，虛空胸次不容針。", "誰家落甑炊香雪，後夜歸船棹軟金。", "洗足蒲團松石上，繞籬山水有清音。"]'),
('987c2be2-9795-424c-92d9-00dcfb6f45c4','一禪人化鹽求頌','釋正覺','宋','宋诗','song-poetry','','[]','泥沙淘洗浪煎乾，一片照人冰雪寒。',64,'全唐诗/poet.song.102000.json','["泥沙淘洗浪煎乾，一片照人冰雪寒。", "意得試蓮浮鹵力，默知隨筯入蔬盤。", "萬家婉婉能相助，衆口調和信不難。", "無像有神聊勘過，圓通眼在舌頭端。"]'),
('ffad594f-784d-4437-991b-8d6c9ae929f7','寄大洪和尚','釋正覺','宋','宋诗','song-poetry','','[]','飲茶作別出蘿門，相送猶懷握手溫。',64,'全唐诗/poet.song.102000.json','["飲茶作別出蘿門，相送猶懷握手溫。", "斷雁幾時歸綴字，浮萍隨處卧生根。", "秋風窗外擁蘆雪，夢冷床頭墮月魂。", "麈柄年來疲轉徙，却思紅顆共炊盆。"]'),
('189a4847-2677-468e-aef3-56f6f55fdc11','送智首座還鄉','釋正覺','宋','宋诗','song-poetry','','[]','顛毛垂雪墮清貧，卧久風林夢轉身。',64,'全唐诗/poet.song.102000.json','["顛毛垂雪墮清貧，卧久風林夢轉身。", "一境妙明還就父，六門虛應却來人。", "凉秋月兔流魂瑩，湛水雲龍蛻骨陳。", "家法兒孫須力振，此行未可腐賓賓。"]'),
('bf982f95-b158-4def-ac37-4cb1ef8b289b','嵩山老人告行作六偈送之  其一','釋正覺','宋','宋诗','song-poetry','','[]','未能老養卧林麓，要乞優恩除髮鬚。',32,'全唐诗/poet.song.102000.json','["未能老養卧林麓，要乞優恩除髮鬚。", "濯足滄浪歲寒事，終來清友石菖蒲。"]'),
('6318ff3a-9ae6-415e-90be-0a36061231a3','嵩山老人告行作六偈送之  其二','釋正覺','宋','宋诗','song-poetry','','[]','挽衣苦怪不我住，懷事乞成今乃時。',32,'全唐诗/poet.song.102000.json','["挽衣苦怪不我住，懷事乞成今乃時。", "雷動定知開蟄戶，春寒無要勒華枝。"]'),
('ed133f2c-6dd0-4802-b455-ac7792d64982','嵩山老人告行作六偈送之  其三','釋正覺','宋','宋诗','song-poetry','','[]','嚶嚶鳥鳴如客情，行行柳眼向人青。',32,'全唐诗/poet.song.102000.json','["嚶嚶鳥鳴如客情，行行柳眼向人青。", "投心舊友春成物，汲水前溪月下瓶。"]'),
('a2857012-f12e-427f-8b04-85de79b6e9d9','嵩山老人告行作六偈送之  其四','釋正覺','宋','宋诗','song-poetry','','[]','夢裏結憂三變事，覺來還喜一成春。',32,'全唐诗/poet.song.102000.json','["夢裏結憂三變事，覺來還喜一成春。", "鶯華時節洗衰落，不信餘寒猶著人。"]'),
('cac3bb19-2ae0-44c0-b456-aac0e6d159a1','嵩山老人告行作六偈送之  其五','釋正覺','宋','宋诗','song-poetry','','[]','服像中情將有得，江湖底事勿相忘。',32,'全唐诗/poet.song.102000.json','["服像中情將有得，江湖底事勿相忘。", "橘洲白鳥秋成伍，漁火蒓羹蓬底香。"]'),
('7e7883cc-bf92-458e-b046-5f731c8a0f46','嵩山老人告行作六偈送之  其六','釋正覺','宋','宋诗','song-poetry','','[]','應緣分影來池月，遊世無心出岫雲。',32,'全唐诗/poet.song.102000.json','["應緣分影來池月，遊世無心出岫雲。", "適意歸來尖屋底，蔬畦還與力鉏勤。"]'),
('273f7509-cc15-43e3-bc80-0be18719f130','送淵上人','釋正覺','宋','宋诗','song-poetry','','[]','朱絲不用挂燒桐，一曲新豐爲送公。',32,'全唐诗/poet.song.102000.json','["朱絲不用挂燒桐，一曲新豐爲送公。", "後夜老松風籟靜，皋禽不見月巢空。"]'),
('d8ab0b3d-a67e-4c46-8352-52290ddc1ba8','送平禪人歸鄂渚','釋正覺','宋','宋诗','song-poetry','','[]','浮舟春水作歸征，家有良田可飯羹。',64,'全唐诗/poet.song.102000.json','["浮舟春水作歸征，家有良田可飯羹。", "久客回翔雲一點，舊巢卧看月三更。", "人猜我住尖頭屋，爾去誰扶折脚鐺。", "爲問巖頭窮鬼子，當時何似此時生。"]'),
('5e21d91e-e134-4754-8d4b-92f508b4fccf','資聖庵欲過圓通','釋正覺','宋','宋诗','song-poetry','','[]','我初浮舟濟九江，幽尋蘭若山蒼龍。',64,'全唐诗/poet.song.102000.json','["我初浮舟濟九江，幽尋蘭若山蒼龍。", "王摩詰畫倚欄檻，謝靈運詩開綺窗。", "艾禪高談肖琢玉，法身雅論非枯樁。", "夢回便是圓通路，月冷上方鐘一撞。"]'),
('4c527283-2a8d-4fc7-b785-866531b0b29b','登祥雲庵謁東林明首座','釋正覺','宋','宋诗','song-poetry','','[]','伐木清哦癖在腸，握筇蒼磴履重霜。',64,'全唐诗/poet.song.102000.json','["伐木清哦癖在腸，握筇蒼磴履重霜。", "玲瓏墮壑乳泉響，蕭瑟到門松吹香。", "高寒夜雨凍一色，虛浄曉雲流五光。", "社散荷枯有遺友，目青鬚髮半滄浪。"]'),
('260ffe04-ee5a-4eac-b0d3-e65815052219','與天池信長老','釋正覺','宋','宋诗','song-poetry','','[]','晚歲叢林鬧葦麻，可中著眼辨龍蛇。',64,'全唐诗/poet.song.102000.json','["晚歲叢林鬧葦麻，可中著眼辨龍蛇。", "行當五路我能事，坐斷孤峯渠作家。", "佛法從來如嚼蠟，朋儔此去似團沙。", "音書不寄思惟盡，千里同風却較些。"]'),
('cb703abf-92e1-4ffa-9d03-59f0433e57ab','朱熙載作平陰令八十日致仕而歸','釋正覺','宋','宋诗','song-poetry','','[]','勇退歸來適舊遊，家林禾黍一成秋。',64,'全唐诗/poet.song.102000.json','["勇退歸來適舊遊，家林禾黍一成秋。", "黄蘆雪照沙頭屋，明月波浮江口舟。", "耕道誰從夫子後，逃禪今與老僧儔。", "柴桑試問陶彭澤，風味真醇相肖不。"]'),
('19e7cd9f-0f1f-421a-8ff3-07e690b6c9c0','周秀才出家求頌','釋正覺','宋','宋诗','song-poetry','','[]','標心脫帽法丹霞，借力堂前剗草些。',64,'全唐诗/poet.song.102000.json','["標心脫帽法丹霞，借力堂前剗草些。", "塞上不須嗟失馬，杯中端欲斷疑蛇。", "久懷甘露濯塵骨，將意叢林開覺華。", "古渡雪蘆明月共，一壺秋色屬吾家。"]'),
('20f11531-c4cf-4fa3-baf9-1144aca9c802','牧童','釋正覺','宋','宋诗','song-poetry','','[]','水牯老行步穩，蓑郎癡歌笑繁。',28,'全唐诗/poet.song.102000.json','["水牯老行步穩，蓑郎癡歌笑繁。", "物外初無塵滓，胸中別有丘園。"]'),
('6e22d622-ac92-4f35-9555-01ce1bc8b7ec','遊司真洞','釋正覺','宋','宋诗','song-poetry','','[]','桃華濯錦春水寒，洞門窈窕玉勾欄。',64,'全唐诗/poet.song.102000.json','["桃華濯錦春水寒，洞門窈窕玉勾欄。", "三峯擁翠雲吞屋，九井揚波雪濺壇。", "象帝先身元老語，谷神後事阿誰觀。", "羽郎清瘦髮半白，待乞安期五色丸。"]'),
('bdc43820-7cbb-405e-9bbf-dc9584f7dc23','仲春過龍舒法華山尋誦經道者舊庵','釋正覺','宋','宋诗','song-poetry','','[]','支徑入窮谷，來尋道者庵。',48,'全唐诗/poet.song.102000.json','["支徑入窮谷，來尋道者庵。", "梵音今默默，華雨尚毿毿。", "夜白月半屋，寒青燈一龕。", "夢隨歌吹去，借路過江南。"]'),
('34b2e7f6-0bc3-4ebb-860b-bf11f26d70df','月禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','踏雪到人家，投機的不差。',48,'全唐诗/poet.song.102000.json','["踏雪到人家，投機的不差。", "月魂通水脈，春信入梅華。", "去覓炊香許，來寬束篾些。", "上方分佛事，先我過毗耶。"]'),
('fd5cfbba-4049-4580-9108-5a66cbac2979','淵禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','淵源徹底碧涵秋，誰道寒光凝不流。',58,'全唐诗/poet.song.102000.json','["淵源徹底碧涵秋，誰道寒光凝不流。", "轉盼蘆華與明月，更無一物礙船頭。", "去來得妙，縱橫自由。", "巨鼇犯餌快須掣，便是仙山墜也休。"]'),
('c8dc15ca-479d-49cb-ae73-2c57a72b1df7','即覺庵子中居士來訪妙峰之西既去作六言五首送之  其一','釋正覺','宋','宋诗','song-poetry','','[]','越境能來訪我，扶筇頗肖遊僧。',28,'全唐诗/poet.song.102000.json','["越境能來訪我，扶筇頗肖遊僧。", "得與坐間語味，諒其胸底懷冰。"]'),
('a32098a9-41e6-453b-bf1f-971d8a93cc1d','即覺庵子中居士來訪妙峰之西既去作六言五首送之  其二','釋正覺','宋','宋诗','song-poetry','','[]','夢曉寒松挂月，心秋古井含津。',28,'全唐诗/poet.song.102000.json','["夢曉寒松挂月，心秋古井含津。", "至道百家合轍，同風千里成鄰。"]'),
('7a3c282c-2b01-4e71-a435-201e0ed806e8','即覺庵子中居士來訪妙峰之西既去作六言五首送之  其三','釋正覺','宋','宋诗','song-poetry','','[]','欲下前時雪磴，重開向日風翎。',28,'全唐诗/poet.song.102000.json','["欲下前時雪磴，重開向日風翎。", "此去丁寧華鳥，莫來狼藉春庭。"]'),
('9e7f4e46-689d-427b-8362-94871fc7e60a','即覺庵子中居士來訪妙峰之西既去作六言五首送之  其四','釋正覺','宋','宋诗','song-poetry','','[]','歸來三徑春草，夢卧一團雨蓑。',28,'全唐诗/poet.song.102000.json','["歸來三徑春草，夢卧一團雨蓑。", "白髮暗移玉燭，昏窗浄洗金波。"]'),
('aed26cce-dd29-4f60-a5a2-32501eb1545b','即覺庵子中居士來訪妙峰之西既去作六言五首送之  其五','釋正覺','宋','宋诗','song-poetry','','[]','世外道人有在，庵中瓶粟無儲。',28,'全唐诗/poet.song.102000.json','["世外道人有在，庵中瓶粟無儲。", "過客未容空去，挽衣相與分蔬。"]'),
('f61e35ab-dbcf-4cbd-9df3-71a5cfb397a5','送月上人歸鄉','釋正覺','宋','宋诗','song-poetry','','[]','西風木落山露骨，秋月在水波濯魂。',64,'全唐诗/poet.song.102000.json','["西風木落山露骨，秋月在水波濯魂。", "客意歸卧四明麓，三世佛從禪口吞。", "大千俱壞我不壞，三六相昏渠不昏。", "劫空照見造化種，回首應物亡塵根。"]'),
('dade48a1-ad6f-43f4-a5f9-bed12cf29d3a','夏安居日過實上人東軒時新竹浴雨因作句歌之','釋正覺','宋','宋诗','song-poetry','','[]','籜龍出叢林，脫錦露新綠。',96,'全唐诗/poet.song.102000.json','["籜龍出叢林，脫錦露新綠。", "昂藏引頭角，密密均節目。", "娟然塵外姿，雲霧膩寒玉。", "翠滿東窗陰，心眼掃惡俗。", "虛靜頗道情，清癯見風骨。", "惠我不老春，爲誰無絃曲。", "葛陂蟄時事，第恐雷雨促。", "不能留高閒，雙碧淡相矚。"]'),
('e5d9b096-395f-49d2-81f9-161ec3ee403c','再和朱朝奉見寄','釋正覺','宋','宋诗','song-poetry','','[]','朅來林下人，挂冠脫朝綠。',96,'全唐诗/poet.song.102000.json','["朅來林下人，挂冠脫朝綠。", "身閒道愈尊，神靜碧照目。", "落落我就璞，碌碌誰如玉。", "欲學陶淵明，高情異浮俗。", "白雲無定心，青山有奇骨。", "肯從蓮社賓，共奏無絃曲。", "佛生等一念，日劫詎延促。", "傾蓋同故人，道存聊一矚。"]'),
('af693d27-6f9e-439b-97ed-7f9859c3c327','擬石牛與悟上人','釋正覺','宋','宋诗','song-poetry','','[]','阿牛純熱不鞭牽，卧向古源蒼樹邊。',64,'全唐诗/poet.song.102000.json','["阿牛純熱不鞭牽，卧向古源蒼樹邊。", "春谷玉田看去種，雪山香草飽來眠。", "背頭隆骨任豐載，鼻底流津大作川。", "異路行行哮吼處，莫忘露地未萌前。"]'),
('b2cb0fdc-21ae-49b4-9fd9-e933a08a8d16','雨夜宿龍門曉登靈光臺禮佛眼塔','釋正覺','宋','宋诗','song-poetry','','[]','一躍龍門適舊懷，棱棱浪級向人開。',64,'全唐诗/poet.song.102000.json','["一躍龍門適舊懷，棱棱浪級向人開。", "洗塵雲陣澆華雨，借力天衢破蟄雷。", "略彴駕溪桃水滿，浮屠瘞骨玉山頹。", "欲知佛眼無遮障，須到靈光不夜臺。"]'),
('b48442b8-1ced-4c19-acce-2f59c0ec4624','過虎頭巖','釋正覺','宋','宋诗','song-poetry','','[]','空巖儼若虎頭蒼，雲膩巖前草木光。',64,'全唐诗/poet.song.102000.json','["空巖儼若虎頭蒼，雲膩巖前草木光。", "竹吐錦萌春雨飽，松含黄粉野吹香。", "石床蟠足散征倦，道境洗心聊坐忘。", "投飯上方蘭若去，未能癡學顧長康。"]'),
('3fb7e8d3-2f88-49ae-b00f-3978ec5450a0','塵上人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','輕輕彈指便開門，百億門前百億身。',64,'全唐诗/poet.song.102000.json','["輕輕彈指便開門，百億門前百億身。", "妙應因緣通處處，圓明箇事遍塵塵。", "華間蜂採黄鬚蜜，柳上鶯傳青眼春。", "歸日相呼滿鉢飯，一時分付飽參人。"]'),
('7c679e8c-98b4-4029-9061-e4d2d0370b2c','別鄒秀才','釋正覺','宋','宋诗','song-poetry','','[]','聲利明來若夢遊，肯迂征家宿雲棲。',64,'全唐诗/poet.song.102000.json','["聲利明來若夢遊，肯迂征家宿雲棲。", "情高素抱山樊志，性淡幽尋松石儔。", "愛我家風清入眼，問伊時事默摇頭。", "今朝送別還孤坐，空對爐煙篆字浮。"]'),
('5ea644cf-ad21-4058-b615-2a2e0db48123','遊雲棲院作偈與住山琛老禪','釋正覺','宋','宋诗','song-poetry','','[]','紫霄峯頂金浮屠，風鈴揚音鬧蒼虛。',64,'全唐诗/poet.song.102000.json','["紫霄峯頂金浮屠，風鈴揚音鬧蒼虛。", "玉欄中地穩行道，雲磴下林新葺廬。", "江山懷抱富不惡，霜月軒窗清有餘。", "老眼寒青伴耶舍，炷香心醉竺仙書。"]'),
('37766ac3-5a06-45f4-89e4-a0ae2ea7c53e','與觀禪者','釋正覺','宋','宋诗','song-poetry','','[]','豁浄虛通入覺場，體前一段本來光。',64,'全唐诗/poet.song.102000.json','["豁浄虛通入覺場，體前一段本來光。", "孤禪恰恰如擔板，默照明明似面牆。", "秋光蘆華兩岸雪，夜寒桂月一船霜。", "迢迢象外行歸路，雁字低低正夕陽。"]'),
('d0f979c7-3763-4561-af02-d3e1754d9827','禪人發心丐席求頌  其一','釋正覺','宋','宋诗','song-poetry','','[]','萬指相從作正觀，出求卧席著蒲團。',64,'全唐诗/poet.song.102000.json','["萬指相從作正觀，出求卧席著蒲團。", "恬處歛雨野雲薄，湛若磨風秋水寒。", "卷去猶知鼻頭痛，坐來方信髑髏乾。", "蘆花明月阿誰事，人在江湖把釣竿。"]'),
('e54aa786-7093-4a11-849e-c8435cdc3692','禪人發心丐席求頌  其二','釋正覺','宋','宋诗','song-poetry','','[]','吉祥長者草茸茸，香軟登機棱路通。',64,'全唐诗/poet.song.102000.json','["吉祥長者草茸茸，香軟登機棱路通。", "卷去若人呈己事，得來與我展家風。", "默遊兩岸雪蘆外，瘦坐五湖煙水中。", "未許春眠夢蝴蝶，大方引步劫壺空。"]'),
('c87fb0ab-5c5a-4e57-81fd-fd678fd8616d','送從上人馳書至京西','釋正覺','宋','宋诗','song-poetry','','[]','衲帔蒙頭自照人，月明堂上轉機輪。',64,'全唐诗/poet.song.102000.json','["衲帔蒙頭自照人，月明堂上轉機輪。", "肯傳千里鶺鴒語，要作十分棠棣春。", "雪嶺同風當日事，石頭束篾舊時麟。", "家林歸卧長連穩，滿眼清光不見身。"]'),
('c64afcc2-b21b-4256-8df2-25029aa2dead','蔣新臣秀才告別作句送之','釋正覺','宋','宋诗','song-poetry','','[]','雪屋高寒能我過，疏梅清秀雪林柯。',64,'全唐诗/poet.song.102000.json','["雪屋高寒能我過，疏梅清秀雪林柯。", "不慳屈宋楚人語，來試宗雷蓮社科。", "後會說盟如有以，此行洗念入無何。", "春風遲立欄干曲，白雪樓前船弄梭。"]'),
('a8d65061-f427-4611-b6c7-15704ad5a22f','津禪人出化盞橐乞頌','釋正覺','宋','宋诗','song-poetry','','[]','喫茶去語落諸方，聚首商量柄杷長。',64,'全唐诗/poet.song.102000.json','["喫茶去語落諸方，聚首商量柄杷長。", "相席是渠能打令，同塵輸爾解和光。", "舌頭狤獠明無骨，鼻孔纍垂暗有香。", "盞橐成來圓此話，儂家受用恰平常。"]'),
('9942d5d7-3d9a-46ed-aa90-243612bfce97','宣和甲辰三月三日山谷寺偶成是時欲下長蘆也','釋正覺','宋','宋诗','song-poetry','','[]','溫風在山谷，青紫班芳妍。',216,'全唐诗/poet.song.102000.json','["溫風在山谷，青紫班芳妍。", "浩然春公心，不作彼此偏。", "其來初無像，榮事亦自然。", "雲容淡如鶴，草色齊膩煙。", "竹萌裹豹袴，蕨茁引兒拳。", "盤箸富可喜，齒頰甘亦便。", "山水濯塵念，風雲會前緣。", "葦江懷道人，擁衆幾兩千。", "頂門眼照世，胸中海吞川。", "同雛丹山巢，羽成各翔遷。", "而今欲住集，相見而忘年。", "執鞭驅並駕，未愧無綵韉。", "白鷗行作伍，水蔬對烹煎。", "撫摩青石牛，不得陪高眠。", "將趨皖口市，就買莎郎船。", "回首謝諸祖，覺法吾所天。", "慧燈耿不夜，心花芳枝聯。", "後日兒孫輩，莫怪森羅前。"]'),
('fe63f6cc-df39-490c-b6c7-ea23c8181535','欲渡長蘆與琛上人漁家詞  其一','釋正覺','宋','宋诗','song-poetry','','[]','岸樹藤繩欲解維，海門蒲席弄清吹。',32,'全唐诗/poet.song.102000.json','["岸樹藤繩欲解維，海門蒲席弄清吹。", "舟不澀，興無涯，回首灊山煙翠姿。"]'),
('34e12e73-0785-4607-a115-33f7b0ee1ac9','欲渡長蘆與琛上人漁家詞  其二','釋正覺','宋','宋诗','song-poetry','','[]','一葦江頭老白眉，而今問訊慰相思。',32,'全唐诗/poet.song.102000.json','["一葦江頭老白眉，而今問訊慰相思。", "風靜夜，月明時，滿眼寒光下釣絲。"]'),
('714ee206-125d-4c83-9d64-31fdb9b2ef55','遊龜山和何學士','釋正覺','宋','宋诗','song-poetry','','[]','一宿曹溪今乃時，永嘉想見未忘茲。',96,'全唐诗/poet.song.102000.json','["一宿曹溪今乃時，永嘉想見未忘茲。", "如何淮風遏行色，不得扶杖相參隨。", "斯須佳惠玩珠璧，璨然傾瀉胸中奇。", "詞鋒明銳許誰敵，禪悅清酣還我追。", "約君入社背時事，種藕著華春滿池。", "道在金蘭端未艾，回頭閱世真兒嬉。"]'),
('3c0ba28a-6774-4768-a486-c10fb5b7106f','送慧禪人往上江糴麻米  其一','釋正覺','宋','宋诗','song-poetry','','[]','石霜拈處最分明，萬萬千千一粒生。',32,'全唐诗/poet.song.102000.json','["石霜拈處最分明，萬萬千千一粒生。", "歸日飯香穿鼻吼，相呼作舞下堂行。"]'),
('0c6758d9-8ded-4b8e-8bd6-1f8f5f446a1a','送慧禪人往上江糴麻米  其二','釋正覺','宋','宋诗','song-poetry','','[]','雲門糊餅趙州茶，裏許明明著得些。',32,'全唐诗/poet.song.102000.json','["雲門糊餅趙州茶，裏許明明著得些。", "公案見成知味底，一千二百衲僧家。"]'),
('c9928d1b-77d7-465f-978c-7bdaff060d81','送慧禪人往上江糴麻米  其三','釋正覺','宋','宋诗','song-poetry','','[]','解開篾束肚皮寬，子去誰憂甑釜寒。',32,'全唐诗/poet.song.102000.json','["解開篾束肚皮寬，子去誰憂甑釜寒。", "雲水相迎船到岸，飽叢林事不相瞞。"]'),
('8eec23ef-ff9e-4fac-9258-ecdc67a73017','送慧禪人往上江糴麻米  其四','釋正覺','宋','宋诗','song-poetry','','[]','蘆華明月水茫茫，激箭風舟破冷光。',32,'全唐诗/poet.song.102000.json','["蘆華明月水茫茫，激箭風舟破冷光。", "親到廬陵酬米價，那時開口便相當。"]'),
('5a1c6c82-81da-4d36-a12c-e07d8e5090e9','送慧禪人往上江糴麻米  其五','釋正覺','宋','宋诗','song-poetry','','[]','去去西江趁便風，丁寧底意語龐公。',32,'全唐诗/poet.song.102000.json','["去去西江趁便風，丁寧底意語龐公。", "歸來定是通身飯，直下人人識己躬。"]'),
('0de3ea8a-b4c0-4723-b60f-8495cb7c6ea0','浮舟下淮訪龜山禪師','釋正覺','宋','宋诗','song-poetry','','[]','霜風獵獵掃平野，沙頭蓁翳浄如燖。',64,'全唐诗/poet.song.102000.json','["霜風獵獵掃平野，沙頭蓁翳浄如燖。", "淮津斜轉龜山麓，雲漢微分雁塔尖。", "籬落梅梢春點點，庭除松影月纖纖。", "禪家況是不羈友，問訊勤來想未嫌。"]'),
('32a47cce-3855-4822-a497-92d5bc1895b3','與黄道友','釋正覺','宋','宋诗','song-poetry','','[]','人頭膏火底心休，來預林儔默默遊。',64,'全唐诗/poet.song.102000.json','["人頭膏火底心休，來預林儔默默遊。", "犀暈成時月魄夜，雁行斷處霽容秋。", "百年分付三椽下，萬象崢嶸一指頭。", "歸去懶融無伎倆，庵前華鳥莫相求。"]'),
('af58fbda-fded-4029-aaac-072e1b489a70','浮舟之昌國謁韓克明知縣','釋正覺','宋','宋诗','song-poetry','','[]','南風帆腹飽，半夜渡滄津。',48,'全唐诗/poet.song.102000.json','["南風帆腹飽，半夜渡滄津。", "鯨海漾新月，仙山尋故人。", "浪寒千里雪，烟暖十洲春。", "來就昌黎語，良慚我效顰。"]'),
('6ee6b7d8-5e01-4952-9deb-8824769aa62f','沖禪人與翠山出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','歸去家山雪未消，到時雪後翠棱高。',64,'全唐诗/poet.song.102000.json','["歸去家山雪未消，到時雪後翠棱高。", "豁然直下斷三際，卓爾箇中抽一毫。", "化鉢不妨遊幻海，虛舟何憚駕驚濤。", "因緣成熟袖雙手，莫學吾家敗酒糟。"]'),
('b8ab1383-6beb-42b9-8783-b029303cd909','和禪人發心丐開海田','釋正覺','宋','宋诗','song-poetry','','[]','檀度夤緣約遠尋，利他方稱出家心。',64,'全唐诗/poet.song.102000.json','["檀度夤緣約遠尋，利他方稱出家心。", "丐行端取叢林飽，耕縟不嫌泥水深。", "地面丕平春種玉，波痕清淺月浮金。", "栽田博飯吾家事，一段風規得老琛。"]'),
('7f3261b9-56ec-4f88-b841-5ce2b9839a6e','湛禪人開田求頌','釋正覺','宋','宋诗','song-poetry','','[]','衲僧茲欲起家門，老牯鞭催泥水渾。',64,'全唐诗/poet.song.102000.json','["衲僧茲欲起家門，老牯鞭催泥水渾。", "混處蹈翻明月影，轉時耕斷白雲根。", "力田辛苦遵吾祖，炊飯馨香飽子孫。", "底事既歸蒲坐穩，湛圓心鑑夙忘痕。"]'),
('087d8025-9473-4e62-a0db-1bcc6d86611f','小師智寬與國清作丐請語','釋正覺','宋','宋诗','song-poetry','','[]','入廛一鉢是生涯，來自寒山拾得家。',64,'全唐诗/poet.song.102000.json','["入廛一鉢是生涯，來自寒山拾得家。", "曉影玉鈎蘿戶月，春叢黄粉蜜房華。", "午炊佛土香傳鼻，參飽雲門飯打牙。", "准擬神通何處借，浄名居士住毗耶。"]'),
('384991a0-4e12-4fd6-9e65-3436994b18a1','靈上人丐鹽求頌','釋正覺','宋','宋诗','song-poetry','','[]','熬煉渠經幾度難，炎炎爐鞴裏頭看。',64,'全唐诗/poet.song.102000.json','["熬煉渠經幾度難，炎炎爐鞴裏頭看。", "可中皓色從來瑩，直下滄溟吸得乾。", "力展家風排淡薄，妙將滋味破辛酸。", "道人意滿期歸也，雪擁茅檐不覺寒。"]'),
('19c17005-ef09-4a6d-9f81-3ad7db454a32','端禪人丐鹽求頌','釋正覺','宋','宋诗','song-poetry','','[]','紅爐焰裏結冰霜，收拾儂家妙有方。',64,'全唐诗/poet.song.102000.json','["紅爐焰裏結冰霜，收拾儂家妙有方。", "舌本要資雲水味，鼻端相助蕨薇香。", "掃歸茅舍閒堆雪，坐照金盤浄發光。", "去去道人成底事，芳滋許我沃枯腸。"]'),
('bb28349c-8d05-46b7-b61f-1e953926aacc','與孫宣教','釋正覺','宋','宋诗','song-poetry','','[]','作別江頭五載餘，海邊相訪未嫌迂。',64,'全唐诗/poet.song.102000.json','["作別江頭五載餘，海邊相訪未嫌迂。", "山林意與世幾絕，丘壑姿逢秋更癯。", "約我道耕新活計，輟君詩戰老工夫。", "兒婚女嫁誰家事，居士有心從馬駒。"]'),
('94803274-9e0a-4e4b-aa7b-8d70f78802f7','鄰月堂求頌','釋正覺','宋','宋诗','song-poetry','','[]','畦衣我是出塵人，卜築高堂與月鄰。',64,'全唐诗/poet.song.102000.json','["畦衣我是出塵人，卜築高堂與月鄰。", "床上金刀香剪桂，篋中玉斧冷修輪。", "寒癯破夢無嫌病，清白傳家不愧貧。", "門外潮平船著棹，點頭老兔靜分身。"]'),
('1aa34a81-5fa6-4ff7-a0ae-eb9ed24f6076','善應不觸','釋正覺','宋','宋诗','song-poetry','','[]','出門雲水任茫茫，相應相酬許當行。',32,'全唐诗/poet.song.102000.json','["出門雲水任茫茫，相應相酬許當行。", "一切時無第二念，雪峯於此謝靈光。"]'),
('7aee1ab3-0f92-4654-bc8b-6e0428c60ec3','大功不宰','釋正覺','宋','宋诗','song-poetry','','[]','吾家消息默中看，看處虛明霽月寒。',32,'全唐诗/poet.song.102000.json','["吾家消息默中看，看處虛明霽月寒。", "一色是功須轉却，石霜端要髑髏乾。"]'),
('ea42835c-908e-4fb9-b6e3-800bed28b627','寄石湫童知縣','釋正覺','宋','宋诗','song-poetry','','[]','溪頭茅屋遠追陶，斗米而今懶折腰。',64,'全唐诗/poet.song.102000.json','["溪頭茅屋遠追陶，斗米而今懶折腰。", "漢水丈人甘抱甕，箕山居士厭鳴瓢。", "心秋霽月夜相照，鬢雪溫風吹不消。", "身世曲肱分付夢，蘧隨蝴蝶到華條。"]'),
('f6b2d6d4-b7bc-433c-91b5-046ad0921542','上元後二日過謙師庵','釋正覺','宋','宋诗','song-poetry','','[]','橫溪一徑兩山分，深翠蘢葱竹日昏。',64,'全唐诗/poet.song.102000.json','["橫溪一徑兩山分，深翠蘢葱竹日昏。", "流水漱冰寒有骨，閒雲歛霽雪無根。", "應容野毳來投飯，不管春眠往扣門。", "窗几薰爐摇篆字，龜床麈語對清溫。"]'),
('3af3a95d-ba53-41d3-9e47-740c3874f7fb','應禪人開田求頌','釋正覺','宋','宋诗','song-poetry','','[]','飄飄捉杖出煙蘿，行丐身心遽許多。',64,'全唐诗/poet.song.102000.json','["飄飄捉杖出煙蘿，行丐身心遽許多。", "針鼻細中投玉線，機頭密處度金梭。", "應緣片片雲成雨，分照團團月在波。", "底意周旋便回首，舊巢寒卧雪林柯。"]'),
('1de7cca5-9f70-4c44-ba4d-1523fbf022cd','恭鑑二禪人幹浴鑊求頌  其一','釋正覺','宋','宋诗','song-poetry','','[]','大冶鎔金入範看，不嫌口闊肚皮寬。',64,'全唐诗/poet.song.102000.json','["大冶鎔金入範看，不嫌口闊肚皮寬。", "得來妙觸通身眼，浄放光明赤肉團。", "衲子落成俱受賜，檀那相助許投干。", "底心試問楞嚴友，道契圓通只箇般。"]'),
('82bc7c02-5f49-4b10-a17f-07900fbd0b26','恭鑑二禪人幹浴鑊求頌  其二','釋正覺','宋','宋诗','song-poetry','','[]','範金爲鑊沸蘭津，分付楞嚴會上賓。',64,'全唐诗/poet.song.102000.json','["範金爲鑊沸蘭津，分付楞嚴會上賓。", "妙觸宣明渠具眼，纖塵不受我通身。", "投諧冷暖渾忘水，迎合溫和似得春。", "爐鞴相催成底器，量吞雲夢可斯人。"]'),
('e3627f08-4136-41f3-9ba3-de2dd59a43a1','航海之寶陀訪真歇師兄  其一','釋正覺','宋','宋诗','song-poetry','','[]','至人親見古觀音，化迹今居海上岑。',64,'全唐诗/poet.song.102000.json','["至人親見古觀音，化迹今居海上岑。", "煙機外分青嶂骨，水天中見白雲心。", "潮痕擁岸棱棱雪，月魄浮波爛爛金。", "根境一如能所斷，圓通遊踐法門深。"]'),
('960bbaa5-872f-4ecc-a0fb-df28304fefc5','航海之寶陀訪真歇師兄  其二','釋正覺','宋','宋诗','song-poetry','','[]','得得來尋真歇兄，孤舟揚檝順潮行。',64,'全唐诗/poet.song.102000.json','["得得來尋真歇兄，孤舟揚檝順潮行。", "重聯斷雁雲中字，遠赴閒鷗沙上盟。", "新味清油燣紫菜，古方淳蜜漬黄菁。", "海山只箇供盤筯，一段家風不世情。"]'),
('48e4c79b-a320-4d4f-bd66-f1d9b22fe41d','與昌國善友','釋正覺','宋','宋诗','song-poetry','','[]','駕潮舟澀岸頭沙，得與巖僧款語些。',64,'全唐诗/poet.song.102000.json','["駕潮舟澀岸頭沙，得與巖僧款語些。", "夢付莊周窗外蝶，疑醒樂廣酒中蛇。", "夜堂莫怪雲慳月，春嶠將知雨促華。", "想像舊山歸去路，照門新錦眼迷家。"]'),
('e5b5ad63-0a98-4eab-b774-df6cb17514a7','化上人持鉢乞頌','釋正覺','宋','宋诗','song-poetry','','[]','化事而今盡付君，歸來還我驗兒孫。',64,'全唐诗/poet.song.102000.json','["化事而今盡付君，歸來還我驗兒孫。", "諸塵正受盛於鉢，一句含胡覆却盆。", "別處見人知雪嶺，自家喫飯識雲門。", "底心肯負檀那力，開發真機報施恩。"]'),
('a0ab0393-7311-4699-b500-14a2303d5b0d','端禪人開田乞頌','釋正覺','宋','宋诗','song-poetry','','[]','衲僧田地有來端，底意相携出問檀。',64,'全唐诗/poet.song.102000.json','["衲僧田地有來端，底意相携出問檀。", "春塢耕開雲錦曉，月津劃破練光寒。", "飽期束肚三條篾，功就移身百尺竿。", "恰恰相投看規矩，谷聲鑑像一般般。"]'),
('434f104f-ca8a-4016-b622-34ff4c41bb96','珊知浴求頌','釋正覺','宋','宋诗','song-poetry','','[]','妙觸宣明不洗塵，楞嚴會上悟心人。',64,'全唐诗/poet.song.102000.json','["妙觸宣明不洗塵，楞嚴會上悟心人。", "潛鱗窟宅半篙水，枯木形骸一杓春。", "涓滴量同法界性，髮毛垢浄虛空身。", "南園應問聊彈指，用處綿綿谷有神。"]'),
('e034e246-77d9-4929-b6ec-d1473d4c5d29','傳上人丐鹽求頌','釋正覺','宋','宋诗','song-poetry','','[]','瀕海人居不事田，生涯清白是家傳。',64,'全唐诗/poet.song.102000.json','["瀕海人居不事田，生涯清白是家傳。", "雷鳴山麓潮橫雪，津出泥沙鹵泛蓮。", "冰玉色承熬煉力，蕨薇滋藉合和緣。", "舌頭妙有圓通眼，坐斷叢林五味禪。"]'),
('dd5cfa6f-e665-490f-8feb-5909f1548157','崇上人求默庵頌','釋正覺','宋','宋诗','song-poetry','','[]','默默中居底是庵，白槌上首乃同參。',64,'全唐诗/poet.song.102000.json','["默默中居底是庵，白槌上首乃同參。", "深明鐵磨莫顛倒，真見末山非女男。", "坐裏水天能湛湛，門前華雨任毿毿。", "一言妙證超名相，不惜眉毛笑翠巖。"]'),
('3553ac99-6db3-44ce-a149-632195b17289','雪晴寄劉殿撰','釋正覺','宋','宋诗','song-poetry','','[]','半氈半幅一羌床，寒淡家風肖老龐。',64,'全唐诗/poet.song.102000.json','["半氈半幅一羌床，寒淡家風肖老龐。", "容易著身藏北斗，等閑開口吸西江。", "龕燈梵夾香摇几，茅屋禪蒲雪照窗。", "方外友於思對麈，隱人胸次作舂撞。"]'),
('7d3ff7ef-20ef-43bb-b3dd-69dae7bc9ede','餘姚胡氏繡觀音求頌','釋正覺','宋','宋诗','song-poetry','','[]','線蹊密密度金針，一一針針觀世音。',64,'全唐诗/poet.song.102000.json','["線蹊密密度金針，一一針針觀世音。", "妙浄莊嚴成相好，光明感應發身心。", "江橫練色月浮水，雨灌華枝春在林。", "聞見可中超有路，普門處處許相尋。"]'),
('44f66a46-bde8-4b54-a663-1767c6c61f01','丹霞忌日','釋正覺','宋','宋诗','song-poetry','','[]','明月清風霽景凉，華鯨噴雪水茫茫。',32,'全唐诗/poet.song.102000.json','["明月清風霽景凉，華鯨噴雪水茫茫。", "靈然一點誰人委，懷抱千年作夜光。"]'),
('28161a52-dd4b-4d11-9b2a-fbb7f7f2f948','鑑維那求月堂頌','釋正覺','宋','宋诗','song-poetry','','[]','桂轂誰將玉斧修，風簾收卷許相留。',64,'全唐诗/poet.song.102000.json','["桂轂誰將玉斧修，風簾收卷許相留。", "虛明窗戶不知夜，清白身心長濯秋。", "鶴夢巢寒松挂壁，魚驚波動水浮鈎。", "胡床瘦坐摇香篆，浄照壺中一默遊。"]'),
('bfd2c9f1-5084-41f8-8955-29173e95816d','一禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','一霎山前春雨乾，叢林氣韻洗衰寒。',64,'全唐诗/poet.song.102000.json','["一霎山前春雨乾，叢林氣韻洗衰寒。", "水明玉兔隨征棹，線重金鱗上釣竿。", "午鉢莫嫌分飯甑，千僧無念集蒲團。", "化機妙應頭頭准，手眼通身不著謾。"]'),
('3fbe135e-ffa2-4c40-9d13-23153997aef1','過則上人庵','釋正覺','宋','宋诗','song-poetry','','[]','歸來蘿蔦挂煙蓑，釣月耕雲倦也那。',64,'全唐诗/poet.song.102000.json','["歸來蘿蔦挂煙蓑，釣月耕雲倦也那。", "山上山下吞佛語，溪東溪西牧牛歌。", "廿年樹耳亡疑著，一箇拳頭得用麽。", "做盡平生閑伎倆，赤鱗無奈甕虀何。"]'),
('092a4ecc-fb9d-4315-8a4c-19bdc0e3c63e','泉州王道友捨簟乞頌','釋正覺','宋','宋诗','song-poetry','','[]','秋入眠床水一方，江湖風月坐來凉。',32,'全唐诗/poet.song.102000.json','["秋入眠床水一方，江湖風月坐來凉。", "浮浮爽氣仙遊去，身在蒼煙白鳥行。"]'),
('c601bc94-3a22-4209-ae93-13aa0dbff2bf','真戒大師求頌','釋正覺','宋','宋诗','song-poetry','','[]','炷香坐羊氈，默默心住禪。',48,'全唐诗/poet.song.102000.json','["炷香坐羊氈，默默心住禪。", "仙桂萌兔窟，神珠媚龍淵。", "湛照自家事，出隨羣動緣。", "應機分手眼，不翅有千千。"]'),
('18be2d9d-db6e-4315-888d-d273260ac2f6','謝通講師五偈  其一','釋正覺','宋','宋诗','song-poetry','','[]','得得客來窺大方，松間目擊揖歸堂。',64,'全唐诗/poet.song.102000.json','["得得客來窺大方，松間目擊揖歸堂。", "秋橫兩眼瞳人碧，雲擁三衣梔子香。", "奪席胸襟君隗礧，愕鄰鬚髮我滄浪。", "竹床相對夜深語，河漢濯磨星斗光。"]'),
('a06f6f26-546a-449d-86b2-7e6105570a4a','謝通講師五偈  其二','釋正覺','宋','宋诗','song-poetry','','[]','五月人間膏火煎，清風麈對有夤緣。',64,'全唐诗/poet.song.102000.json','["五月人間膏火煎，清風麈對有夤緣。", "點頭頑石能明證，借口虛空解講玄。", "隨類佛身分百億，出塵紅卷等三千。", "未閑相約蒲禪穩，作別又趨華雨筵。"]'),
('7a5c6de9-d1fe-410a-8bb9-91fab6488a22','謝通講師五偈  其三','釋正覺','宋','宋诗','song-poetry','','[]','慰心佛氏未蕭條，卓卓緇林有俊髦。',64,'全唐诗/poet.song.102000.json','["慰心佛氏未蕭條，卓卓緇林有俊髦。", "知見香熏舌本利，名言垢浄眼棱高。", "錦雲脚踏冷修月，仙嶠牽頹閒釣鼇。", "良遂肯從麻谷後，聲光矯矯壯吾曹。"]'),
('9dc9adf1-1568-4a4d-9537-ef540b97979a','謝通講師五偈  其四','釋正覺','宋','宋诗','song-poetry','','[]','一昨書來約見過，遲留行李未成那。',64,'全唐诗/poet.song.102000.json','["一昨書來約見過，遲留行李未成那。", "梨黄棗赤秋如許，髮白眉龐老奈何。", "相伴採薇雲膩襪，不嫌伐木雨濡蓑。", "對床默默香摇篆，霽月夜窗懸女蘿。"]'),
('30cdf48c-ba75-433e-b703-f3c91acaf52a','謝通講師五偈  其五','釋正覺','宋','宋诗','song-poetry','','[]','乞食因循答教遲，想能心照未相疑。',64,'全唐诗/poet.song.102000.json','["乞食因循答教遲，想能心照未相疑。", "三年約友共連璧，千里同風那隔絲。", "鞭笋嫩黄出泥土，槿華寒紫裹藩籬。", "雨驅暑去晚明霽，來雁門頭字脚垂。"]'),
('ab69f61b-b9b2-4772-ad63-9bf6c42a5961','鄭通判母氏贊','釋正覺','宋','宋诗','song-poetry','','[]','法喜爲食，慈悲爲舍。',84,'全唐诗/poet.song.102000.json','["法喜爲食，慈悲爲舍。", "信佛是歸，視身如借。", "住正念以唯勤，趣外塵而無暇。", "機閑萬象光中，眼活髑髏眉下。", "彼亡也夢蝶露蟬，自得也雲犀香麝。", "神遊真浄兮天水同秋，心印妙明兮風月破夜。"]'),
('49638464-d1f0-4576-aaf6-3e86a7c27251','機禪人發心丐田','釋正覺','宋','宋诗','song-poetry','','[]','歷歷機梭看轉旋，衲僧手眼有千千。',64,'全唐诗/poet.song.102000.json','["歷歷機梭看轉旋，衲僧手眼有千千。", "將知白雪上方飯，出自黄雲負郭田。", "溉灌流金溪口月，耕犂卷幕隴頭煙。", "和泥合水誰家事，參飽元無分外禪。"]'),
('8d117a2f-36bc-4696-9b3d-a55a54f00edc','虛禪人發心丐田','釋正覺','宋','宋诗','song-poetry','','[]','虛廓襟懷作丐遊，機緣處處定相投。',64,'全唐诗/poet.song.102000.json','["虛廓襟懷作丐遊，機緣處處定相投。", "開田大義聊舒手，得意忘言暗點頭。", "白牯耕回山月曉，金刀剪斷野雲秋。", "長連趺坐通身飯，一飽分明百不憂。"]'),
('d035a464-ef17-431f-a46f-6f026fb022c2','早發寧海壽寧道中過奉化','釋正覺','宋','宋诗','song-poetry','','[]','曉徑風香雨陣紅，鑿崖棱石上梯空。',64,'全唐诗/poet.song.102000.json','["曉徑風香雨陣紅，鑿崖棱石上梯空。", "勸歸鳥語春過半，投飯人家日正中。", "山怪翠寒臺對偶，溪能柔碧剡相通。", "楊華便是浮萍草，蹤迹又隨流水東。"]'),
('468d13b2-6add-40dc-be38-3f13e656790d','宿覆船山阻雨','釋正覺','宋','宋诗','song-poetry','','[]','枝筇同到覆船巔，暫寄筇枝借榻眠。',64,'全唐诗/poet.song.102000.json','["枝筇同到覆船巔，暫寄筇枝借榻眠。", "山水鈎簾知屬我，煙霞膩枕夢遊仙。", "覺來笋窟投蔬筯，閒把華房入線編。", "想像玲瓏巖下雨，春寒猶可卧羊氈。"]'),
('29cb5583-0f65-4edb-b8d5-3613ec993741','行通善友求頌','釋正覺','宋','宋诗','song-poetry','','[]','明白家風月洗霜，道人寒夜坐繩床。',64,'全唐诗/poet.song.102000.json','["明白家風月洗霜，道人寒夜坐繩床。", "安身誰效兔三窟，返照自如龜六藏。", "疑若蛇弓蟠酒醆，妙同蜂蜜得華房。", "默遊宛轉臻元極，虛廓無涯步大方。"]'),
('24b5a9a2-4cae-48e4-9c5d-c35bf530aea3','姚道人乞頌','釋正覺','宋','宋诗','song-poetry','','[]','慈悲方便事，觸處有工夫。',24,'全唐诗/poet.song.102000.json','["慈悲方便事，觸處有工夫。", "應變隨聲色，團團盤走珠。"]'),
('a52f1221-2a5e-49b7-be12-5c12eceead72','戚澤民從新正日供三僧求頌','釋正覺','宋','宋诗','song-poetry','','[]','君家炊飯辦蔬薇，日供畦衣三阿師。',64,'全唐诗/poet.song.102000.json','["君家炊飯辦蔬薇，日供畦衣三阿師。", "海上浮杯登岸後，雲間飛錫過門時。", "伊蒲塞作新香氣，賓度盧迎老白眉。", "施受等心相稱可，月隨流水下春池。"]'),
('fffb2da1-f864-4a52-8f43-8095a3aa39c9','時禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','老能碓下米無舂，一出相煩作變通。',64,'全唐诗/poet.song.102000.json','["老能碓下米無舂，一出相煩作變通。", "陣陣香風看稻熟，番番時雨見年豐。", "手携拍板傅大士，杖挂剪刀梁誌公。", "妙應羣機真絕待，秋清河淡月行空。"]'),
('98821b62-d658-4036-8c62-16d431c0ecc0','仙上人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','綴鉢持來勇入廛，家家行結勝因緣。',64,'全唐诗/poet.song.102000.json','["綴鉢持來勇入廛，家家行結勝因緣。", "三千界重慈悲佛，五百生稱忍辱仙。", "芳濯叢林春冉冉，明隨流水月娟娟。", "飽參事與千僧供，洗足蒲團枯木禪。"]'),
('8ce0b41a-2084-4a8d-bbc1-caab8b7d9533','普淵行者請頌','釋正覺','宋','宋诗','song-poetry','','[]','脫盡塵機真出家，平持心地是生涯。',64,'全唐诗/poet.song.102000.json','["脫盡塵機真出家，平持心地是生涯。", "法堂剗草墮僧數，舂屋傳衣聯祖華。", "想變石頭山下虎，悟空弓影酒中蛇。", "寒枯只麽清修去，佛種從今却較些。"]'),
('0bdaf9d8-7536-4cda-8e2e-c1bea37ab480','妙慧上人求頌','釋正覺','宋','宋诗','song-poetry','','[]','妙中有慧獨醒醒，歷歷機前自照靈。',64,'全唐诗/poet.song.102000.json','["妙中有慧獨醒醒，歷歷機前自照靈。", "老兔夢寒眠浄魄，真犀心醉得通星。", "道遊剎剎參諸佛，智破塵塵出大經。", "頑石點頭揮麈尾，坐間華雨一番馨。"]'),
('26f0b856-d75e-43f6-82ec-a106e05dc92a','宗禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','萬指生涯一鉢歸，叢林宗尚默無機。',64,'全唐诗/poet.song.102000.json','["萬指生涯一鉢歸，叢林宗尚默無機。", "道耕自信我寒槁，妙用相煩君發揮。", "薜荔藩籬秋蔓衍，女蘿窗戶月依稀。", "時時處處通消息，物象都盧入範圍。"]'),
('1c28a73c-8ea6-4e50-9bab-a3f3147127e5','小師慧果馳書取雪峰真歇和尚','釋正覺','宋','宋诗','song-poetry','','[]','鳥窠閑口聊吹布，雪老低頭却入庵。',32,'全唐诗/poet.song.102000.json','["鳥窠閑口聊吹布，雪老低頭却入庵。", "生死同條末後句，也應千里問同參。"]'),
('330ff755-9e1c-4d01-a322-646416222385','解兄之雪峰禮本師','釋正覺','宋','宋诗','song-poetry','','[]','南山去見雪峯師，古澗寒泉瞪目時。',64,'全唐诗/poet.song.102000.json','["南山去見雪峯師，古澗寒泉瞪目時。", "徹底無痕才識己，轉身有路復名誰。", "子歸父處那求顧，雲向山來不待吹。", "西舍機鳴聊織錦，梭臍陰陰細飛絲。"]'),
('76c3689e-dae6-4eee-a101-b5d3e15ad3c0','與辨庵主','釋正覺','宋','宋诗','song-poetry','','[]','夾山鈎上得芳鱗，不作當年棒喝嗔。',64,'全唐诗/poet.song.102000.json','["夾山鈎上得芳鱗，不作當年棒喝嗔。", "直向劫前分手眼，端能化外撥機輪。", "是須眉底有筋漢，方契寰中無舌人。", "徹照自宗知細密，任從天下樂忻忻。"]'),
('2f988f9d-a84a-49f4-b9fa-efdbd48466ab','甲寅春之海山雨後訪王淵明知縣','釋正覺','宋','宋诗','song-poetry','','[]','誰問春泥沒履牙，蘿門窈窕綠差斜。',64,'全唐诗/poet.song.102000.json','["誰問春泥沒履牙，蘿門窈窕綠差斜。", "幽芳松菊淵明徑，深秀溪山摩詰家。", "默照佛燈寒不掉，對緣心鑑浄無瑕。", "仍聞懶甚融居士，庭鳥幾番狼藉華。"]'),
('253072ae-42e3-4e54-9f24-13a609e11e95','禪人發心幹鐘乞頌','釋正覺','宋','宋诗','song-poetry','','[]','木落空山霜，夜樓時一撞。',48,'全唐诗/poet.song.102000.json','["木落空山霜，夜樓時一撞。", "隨風度林嶺，喚月到蘿窗。", "響應虛傳谷，聲飛不礙江。", "夢回天意曉，蝴蝶失雙雙。"]'),
('95a7d89b-6072-474a-b8ba-4dcf63912a09','保福傳化士乞頌','釋正覺','宋','宋诗','song-poetry','','[]','梅福仙遊井汲枯，而今雲水穩禪蒲。',64,'全唐诗/poet.song.102000.json','["梅福仙遊井汲枯，而今雲水穩禪蒲。", "青原門下藏麟角，黄蘗床頭捋虎鬚。", "學子柏庭寒立雪，檀家飯甑軟炊珠。", "乞歸將意叢林煖，松食荷衣良槁癯。"]'),
('70b04f5f-9426-437c-8749-7e09b2465a27','偁上人幹造延壽院乞頌','釋正覺','宋','宋诗','song-poetry','','[]','叢林百丈有清規，特設堂安老病師。',64,'全唐诗/poet.song.102000.json','["叢林百丈有清規，特設堂安老病師。", "隱几虛心還自照，炷香孤坐絕他思。", "妙窮正念空三世，浄洗餘昏月一墀。", "底意欲從何處問，毗耶居士飽相知。"]'),
('99e5cc65-42e5-4b25-a89f-cd576ad1099d','訪黄給事承往寶陀禮普門大士留偈','釋正覺','宋','宋诗','song-poetry','','[]','泛舟誰畏海門津，丈室來尋彼上人。',64,'全唐诗/poet.song.102000.json','["泛舟誰畏海門津，丈室來尋彼上人。", "麈語欲求青眼舊，友心未爽白頭新。", "黄家羊卧藩籬晚，梅氏仙遊島嶼春。", "餬餅饅頭看手段，觀音妙智在塵塵。"]'),
('666610fe-da79-4f34-b892-cf6fd31a2b1c','廓禪人幹田求頌','釋正覺','宋','宋诗','song-poetry','','[]','廓虛田地絕蓁荆，望斷玉壺冰鑑平。',64,'全唐诗/poet.song.102000.json','["廓虛田地絕蓁荆，望斷玉壺冰鑑平。", "素色依稀雲擁耒，練光片段月分耕。", "意爲衲子延筇履，力丐檀那助飯羹。", "將見金牛笑相喚，叢林氣像不多爭。"]'),
('265fd502-2758-483b-b9c3-faf97bf8ebdc','送修街坊出丐','釋正覺','宋','宋诗','song-poetry','','[]','海上鼇峯裹綺霞，梅仙朋舊有生涯。',64,'全唐诗/poet.song.102000.json','["海上鼇峯裹綺霞，梅仙朋舊有生涯。", "清眠夢落三山月，和氣吹成一縣華。", "去駕風舟尋長者，來分甑飯入吾家。", "待君歸掃餘疑膜，杯影垂弓不是蛇。"]'),
('88c6ce11-47d7-43a5-8788-97065e48c209','退天童上太守吳學士','釋正覺','宋','宋诗','song-poetry','','[]','三椽五合不求餘，汩汩營營笑拙疏。',64,'全唐诗/poet.song.102000.json','["三椽五合不求餘，汩汩營營笑拙疏。", "妄立是非徒喻馬，樂同彼此解觀魚。", "洗霜骨出山宜瘦，答響神藏谷應虛。", "莫涴人間名字垢，身雲心月本如如。"]'),
('58f61d98-86f3-4684-9f18-770148fc6a33','衛進可寺丞臘月二十九日招我以蔬飯從容勝集其居之西一堂榜曰六湛意六處休復同一湛然且求語因作偈云','釋正覺','宋','宋诗','song-poetry','','[]','風瀾未作見靈源，六處亡功體湛存。',64,'全唐诗/poet.song.102000.json','["風瀾未作見靈源，六處亡功體湛存。", "諸法性空方得座，一彈指響頓開門。", "寒梅籬落春能早，野雪櫺窗夜不昏。", "萬像森羅心印印，根塵超豁妙無痕。"]'),
('c609b376-ff64-4e3b-9116-8ff8af4c9d13','因雪示隨行禪者','釋正覺','宋','宋诗','song-poetry','','[]','家家種玉滿區區，誰裹煙蓑細步趣。',64,'全唐诗/poet.song.102000.json','["家家種玉滿區區，誰裹煙蓑細步趣。", "千里同風休綴綴，十方一色尚拘拘。", "夢醒光彩兩頭斷，坐穩身心三際無。", "清白傳家衲僧事，其間轉處看工夫。"]'),
('e51c3a8f-101d-4a83-a3d4-b9be3871d5c9','符十五郎求頌  其一','釋正覺','宋','宋诗','song-poetry','','[]','塵勞排遣廓而明，靈照心空合未萌。',32,'全唐诗/poet.song.102000.json','["塵勞排遣廓而明，靈照心空合未萌。", "妙盡源窮成本得，從來等佛與衆生。"]'),
('03414168-fefa-473d-a732-4c4f6c939645','符十五郎求頌  其二','釋正覺','宋','宋诗','song-poetry','','[]','圓虛裏許得真遊，離水犀通一點秋。',32,'全唐诗/poet.song.102000.json','["圓虛裏許得真遊，離水犀通一點秋。", "機應無私登鳥道，妙同明月靜隨流。"]'),
('129fac1f-ffc4-41b5-b489-9ed495c80c33','歲開八日謁西溪真悟講師','釋正覺','宋','宋诗','song-poetry','','[]','雨華几席自清馨，茗碗初收篆縷青。',64,'全唐诗/poet.song.102000.json','["雨華几席自清馨，茗碗初收篆縷青。", "柔弄柳條風剪剪，冷濡梅蕊雪星星。", "不嫌黄卷閑遮眼，有意微塵破出經。", "思大氣吞三世佛，兒孫未到敗門庭。"]'),
('d299a70a-aec8-4cd0-ba25-e18eddb2a53c','雲上人持鉢乞頌','釋正覺','宋','宋诗','song-poetry','','[]','雲水千僧共默耕，煩君乞食出山行。',64,'全唐诗/poet.song.102000.json','["雲水千僧共默耕，煩君乞食出山行。", "蕨薇夜雨萌寒麓，桃李春風織錦城。", "空谷一呼同響應，圓珠衆色合光明。", "上方此去分香飯，爲我先須見浄名。"]'),
('522ed922-e2bc-4b6e-b44b-90adee1c179f','方上人持鉢乞頌','釋正覺','宋','宋诗','song-poetry','','[]','卷衣破曉下連城，意欲分炊往上方。',64,'全唐诗/poet.song.102000.json','["卷衣破曉下連城，意欲分炊往上方。", "僧鉢飯歸三篾飽，蜂房蜜合百華香。", "柳絲鶯友調唇滑，雲錦人家照眼光。", "應變縱橫看伎倆，隨身干木慣逢場。"]'),
('a42d73fc-c943-47a0-bdc3-67c3058461f1','與李居士','釋正覺','宋','宋诗','song-poetry','','[]','枯禪胸底洗餘紛，一點虛明湛若存。',64,'全唐诗/poet.song.102000.json','["枯禪胸底洗餘紛，一點虛明湛若存。", "剎剎塵塵成浄土，華華葉葉發靈根。", "無心頗肖雲爲潤，有照渾如月破昏。", "舒卷縱橫俱在我，箇人真得總持門。"]'),
('cc0e356f-ab69-431f-8944-83257120caba','森禪人持鉢求頌','釋正覺','宋','宋诗','song-poetry','','[]','森羅萬象本同根，箇事虛通有化門。',64,'全唐诗/poet.song.102000.json','["森羅萬象本同根，箇事虛通有化門。", "歷歷當機元不爽，頭頭大用了無痕。", "妙明田地傳家祖，參飽叢林委子孫。", "緣就歸來牆面坐，秋空連水月黄昏。"]'),
('4bffc882-c90f-4978-93ba-ce07d58347fc','立春後五日次本上人韻','釋正覺','宋','宋诗','song-poetry','','[]','雪繞樓欄同楚些，梅將青子柳柔柯。',64,'全唐诗/poet.song.102000.json','["雪繞樓欄同楚些，梅將青子柳柔柯。", "山林臭味入新語，風月膺胸遵古科。", "夢付曲肱春困甚，乞如駢拇老閒何。", "雨師雷伯情多妬，收拾陶家壁上梭。"]'),
('beea2fd4-e42c-41fa-8c6a-555280efe699','良禪人幹田求頌','釋正覺','宋','宋诗','song-poetry','','[]','良田一片望無涯，曠古相傳佛祖家。',64,'全唐诗/poet.song.102000.json','["良田一片望無涯，曠古相傳佛祖家。", "四至町畦誰作伴，中心樹子自開華。", "示人鎌樣秋雲卷，催牯鞭聲春日斜。", "收拾歸來付耕事，衲僧氣味較些些。"]'),
('b41713ba-274b-4271-b568-138168a258f9','古上人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','化門到處大千身，古鑑無塵谷有神。',32,'全唐诗/poet.song.102000.json','["化門到處大千身，古鑑無塵谷有神。", "方信相隨混不得，堂堂獨露是何人。"]'),
('a2e3c622-5368-4698-936a-9f9e2ac7b8cf','江郎中求頌','釋正覺','宋','宋诗','song-poetry','','[]','浄治心地廓無垠，一段光明破夙昏。',32,'全唐诗/poet.song.102000.json','["浄治心地廓無垠，一段光明破夙昏。", "撥轉機輪分化事，百千三昧見門門。"]'),
('647a45d4-03b9-488f-844f-af340943edc8','雨晴偶作示禪者','釋正覺','宋','宋诗','song-poetry','','[]','快雨快晴寒食近，崢嶸芳事趁佳辰。',64,'全唐诗/poet.song.102000.json','["快雨快晴寒食近，崢嶸芳事趁佳辰。", "弄風柳絮疑成雪，滿地榆錢買得春。", "雷吐英英茶爪露，暖班茁茁蕨拳伸。", "桃華眼鬧隨蝴蝶，誰似靈雲識故人。"]'),
('78eb800c-6fc5-4274-a2c7-acbf32f65ba8','來上人幹延壽院乞頌','釋正覺','宋','宋诗','song-poetry','','[]','披蓁卜築古林阿，百丈心於老病多。',64,'全唐诗/poet.song.102000.json','["披蓁卜築古林阿，百丈心於老病多。", "照徹有無方得我，緣分生滅不干他。", "谷雲冷抱松根石，山月明懸屋角蘿。", "若子殷勤圓此話，毗耶城裏問維摩。"]'),
('afa52e98-7ed6-4256-9e9d-325bbfb9bb90','道禪人發心幹田乞頌','釋正覺','宋','宋诗','song-poetry','','[]','道人欲乞一囊錢，爲我成褫負郭田。',64,'全唐诗/poet.song.102000.json','["道人欲乞一囊錢，爲我成褫負郭田。", "淺水駕牛披曉月，深雲下耒破春煙。", "力耕妙用吾家事，坐照真機自己禪。", "寄語檀那好相助，年年長得飯僧緣。"]'),
('ff9fdb70-c474-42fa-8e53-a1e67135102c','以何學士韻示像侍者','釋正覺','宋','宋诗','song-poetry','','[]','茂養高標松抱苓，歲寒姿傲雪霜丁。',64,'全唐诗/poet.song.102000.json','["茂養高標松抱苓，歲寒姿傲雪霜丁。", "蕭騷風度山林韻，偃蹇氣鍾丘壑形。", "霽月霽雲胸次淡，秋山秋水眼棱青。", "磨磚誰問馬師語，妙發枯龜一灼靈。"]'),
('9fa743e3-2793-452a-94ff-a985c6b4bcdb','夢齋求頌','釋正覺','宋','宋诗','song-poetry','','[]','香風華雨政紛紛，春困何妨聊曲肱。',32,'全唐诗/poet.song.102000.json','["香風華雨政紛紛，春困何妨聊曲肱。", "三世佛相傳寐語，覺來無我壞兒孫。"]'),
('cf21b2d4-9a0b-4db4-a12a-9ed0f07a4718','觀知殿化殿堂燈油求頌','釋正覺','宋','宋诗','song-poetry','','[]','廣堂清白照蒲團，相續真燈未許殘。',64,'全唐诗/poet.song.102000.json','["廣堂清白照蒲團，相續真燈未許殘。", "寂默無聲閑口醭，光明不掉寸心寒。", "蓮開似對秋波淺，夢覺渾疑曉漏乾。", "十法界身流影事，自他交徹鏡中看。"]'),
('6d9b06dc-1d06-4a9d-bfed-145bed95a852','海上人知浴求頌','釋正覺','宋','宋诗','song-poetry','','[]','溫溫氣象半篙津，匏杓調和冷煖勻。',64,'全唐诗/poet.song.102000.json','["溫溫氣象半篙津，匏杓調和冷煖勻。", "直得通身渾是水，端知赤肉了無塵。", "風埃面目揩磨浄，丘壑形骸洗濯春。", "妙觸宣明佛子住，首楞嚴會有斯人。"]'),
('d26f473f-0eb9-49b8-a519-335a9ca680c5','時司理求頌','釋正覺','宋','宋诗','song-poetry','','[]','浄磨心鑑絕遊塵，本際靈明自照神。',32,'全唐诗/poet.song.102000.json','["浄磨心鑑絕遊塵，本際靈明自照神。", "箇裏機回圓歷歷，化分百億大千身。"]'),
('179abce0-42db-462c-8090-f10530575a4b','行月大師求頌','釋正覺','宋','宋诗','song-poetry','','[]','霽明夜永月行空，破暗真光默默中。',64,'全唐诗/poet.song.102000.json','["霽明夜永月行空，破暗真光默默中。", "一點至靈虛且應，十方圓鑑照而沖。", "床頭爐篆浮寒紫，壁上龕燈對冷紅。", "箇裏宗乘消息在，蒲團紙帳舊家風。"]'),
('6cfbc7be-3728-49fb-a372-aafc1a3b3fbf','齊上人發心知羅漢堂求頌','釋正覺','宋','宋诗','song-poetry','','[]','修結僧緣清浄因，青油白茗與烏薪。',64,'全唐诗/poet.song.102000.json','["修結僧緣清浄因，青油白茗與烏薪。", "龐眉五百聖尊者，行脚一千吾上人。", "雲屋芳姿開菡萏，地爐煖氣卧麒麟。", "睡魔不至蒲禪穩，自照光明默默神。"]'),
('565b40fc-c77b-4517-ac6d-e5ea1fa1d4f6','華亭顧道友兒女俱出家求頌','釋正覺','宋','宋诗','song-poetry','','[]','兒兒女女著袈裟，留得閑身且在家。',64,'全唐诗/poet.song.102000.json','["兒兒女女著袈裟，留得閑身且在家。", "不作丘坑看覺地，當鉏薈蘙種曇華。", "深藏北斗端能許，吸盡西江始較些。", "三界脫然亡影像，浄名居士好生涯。"]'),
('2197d18f-af90-49c2-a2ff-43fd35a88918','送明專使','釋正覺','宋','宋诗','song-poetry','','[]','廓落無依合太虛，行行何處不逢渠。',64,'全唐诗/poet.song.102000.json','["廓落無依合太虛，行行何處不逢渠。", "功回冷眼雙眉底，照盡橫身曠劫初。", "大仰默知東寺意，玄沙明上雪峯書。", "將歸束肚三條蔑，鈯斧相隨到處居。"]'),
('35f21bc7-1559-470b-bc9c-73a0d0a18d63','月禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','一月在諸水，動隨來去舟。',48,'全唐诗/poet.song.102000.json','["一月在諸水，動隨來去舟。", "分身能恁麽，到處恰相投。", "湖海墮全璧，魚龍吞曲鈎。", "歸來端可慶，俱得飽參休。"]'),
('21be615c-7b59-48bb-be60-8e579ef79b74','應禪人出丐求頌','釋正覺','宋','宋诗','song-poetry','','[]','應身隨處見塵塵，能順因緣不背真。',64,'全唐诗/poet.song.102000.json','["應身隨處見塵塵，能順因緣不背真。", "樹上虎頭呈伎倆，毛端師子顯精神。", "平生自許得遊刃，投老難傳知斲輪。", "香氣滿城燂鉢飯，叢林一洗浩然春。"]'),
('866c3960-410e-4e86-a881-15406e513623','王觀察求頌','釋正覺','宋','宋诗','song-poetry','','[]','廓虛深浄裏頭看，一點至靈珠走盤。',64,'全唐诗/poet.song.102000.json','["廓虛深浄裏頭看，一點至靈珠走盤。", "默默通身明有眼，塵塵分應妙無瘢。", "江湖浩浩月隨溜，華木欣欣春入端。", "變化鯤鵬是時節，便乘羊角作風摶。"]'),
('6953838e-7551-414c-9c2e-79ff2580e765','趙學士求頌','釋正覺','宋','宋诗','song-poetry','','[]','身前身後獨靈靈，一切如來出此經。',32,'全唐诗/poet.song.102000.json','["身前身後獨靈靈，一切如來出此經。", "歇盡狂心便相見，水秋天浄月亭亭。"]'),
('29493c83-5fb4-44f8-b3b3-a165f0145f83','朱幹辦求頌','釋正覺','宋','宋诗','song-poetry','','[]','磨洗紛塵百念秋，湛然源底未分流。',32,'全唐诗/poet.song.102000.json','["磨洗紛塵百念秋，湛然源底未分流。", "其間自照因緣外，水浄娟娟浮月鈎。"]'),
('e4dd163f-ece2-4600-8418-cea53bcb8b3f','久上人出丐乞頌','釋正覺','宋','宋诗','song-poetry','','[]','孤禪抖擻起僧氈，挂鉢寒藤著瘦肩。',64,'全唐诗/poet.song.102000.json','["孤禪抖擻起僧氈，挂鉢寒藤著瘦肩。", "破夜無私看霽月，開華不染出泥蓮。", "底心衆事水雲餓，何處人家粥飯緣。", "寄語毗耶老居士，相投莫怪喚春眠。"]'),
('a1bf11ce-da95-48aa-b2d9-b9db14ca03ad','五位  其一','釋正覺','宋','宋诗','song-poetry','','[]','正中偏，霽碧星河冷浸乾。',28,'全唐诗/poet.song.102000.json','["正中偏，霽碧星河冷浸乾。", "半夜木童敲月戶，暗中驚破玉人眠。"]'),
('7c643988-0bf9-44c0-9ed3-7f3559eee6c9','五位  其二','釋正覺','宋','宋诗','song-poetry','','[]','偏中正，海雲依約神山頂。',28,'全唐诗/poet.song.102000.json','["偏中正，海雲依約神山頂。", "歸人鬢髮白垂絲，羞對秦臺寒照影。"]'),
('8adfa7e3-97c2-4277-8cc0-18336a868640','五位  其三','釋正覺','宋','宋诗','song-poetry','','[]','正中來，月夜長鯤蛻甲開。',28,'全唐诗/poet.song.102000.json','["正中來，月夜長鯤蛻甲開。", "大背摩天振雲羽，翔遊鳥道類難該。"]'),
('e7774ae8-e359-4579-b7d7-d21954eb2083','五位  其四','釋正覺','宋','宋诗','song-poetry','','[]','兼中至，覿面不須相忌諱。',28,'全唐诗/poet.song.102000.json','["兼中至，覿面不須相忌諱。", "風化無傷的意玄，光中有路天然異。"]'),
('eec94e16-1a1f-423f-8cc5-cdd2ceed34fe','五位  其五','釋正覺','宋','宋诗','song-poetry','','[]','兼中到，斗柄橫斜天未曉。',28,'全唐诗/poet.song.102000.json','["兼中到，斗柄橫斜天未曉。", "鶴夢初醒露氣寒，舊巢飛出雲松倒。"]'),
('75fa2a3e-f0d4-4175-8a01-3c760fce50d4','五王子 誕生','釋正覺','宋','宋诗','song-poetry','','[]','星攢金殿降生時，稱體宮衣覆雪肌。',32,'全唐诗/poet.song.102000.json','["星攢金殿降生時，稱體宮衣覆雪肌。", "功就轉身全合父，光中潛撥玉輪移。"]'),
('c2a3b5d4-e0d1-4488-82c9-38b263b0bfb8','五王子 朝生','釋正覺','宋','宋诗','song-poetry','','[]','雄心脫略戰文場，端把煙蓑換龍章。',32,'全唐诗/poet.song.102000.json','["雄心脫略戰文場，端把煙蓑換龍章。", "葵藿奉君知貴味，肯懷歸去見嚴光。"]'),
('b2550c6d-6c9d-4f9e-936d-b38b5faddd93','五王子 末生','釋正覺','宋','宋诗','song-poetry','','[]','甘分清孤守固窮，衡門寥落正西風。',32,'全唐诗/poet.song.102000.json','["甘分清孤守固窮，衡門寥落正西風。", "一鳴便是蒼梧鳳，不意飄流鷗鷺中。"]'),
('73d00463-1bfc-4480-804d-80eaf2bb87a2','五王子 化生','釋正覺','宋','宋诗','song-poetry','','[]','絲綸傳得出宸幃，宣花春城類莫齊。',32,'全唐诗/poet.song.102000.json','["絲綸傳得出宸幃，宣花春城類莫齊。", "妙握當途無字印，馬蹄終不染塵泥。"]'),
('8511bc6e-8a33-4613-a89c-77cd517b66f3','五王子 內生','釋正覺','宋','宋诗','song-poetry','','[]','妙齡天嗣自重瞳，尊貴威嚴鎮六宮。',32,'全唐诗/poet.song.102000.json','["妙齡天嗣自重瞳，尊貴威嚴鎮六宮。", "規步從來不出禁，閽人祇得頌芳風。"]'),
('d54fca94-d729-47b4-8cb4-229bc173e1bb','四賓主 賓中賓','釋正覺','宋','宋诗','song-poetry','','[]','平生心事結眉頭，滿面風埃鬢已秋。',32,'全唐诗/poet.song.102000.json','["平生心事結眉頭，滿面風埃鬢已秋。", "大底出門無伎術，奈何今日路貧愁。"]'),
('fa5951a4-f46b-47b1-b401-9f49413f68e7','四賓主 賓中主','釋正覺','宋','宋诗','song-poetry','','[]','不戀經商利萬金，晚來古路問家音。',32,'全唐诗/poet.song.102000.json','["不戀經商利萬金，晚來古路問家音。", "分明得報尊親健，爭奈難平喜懼心。"]'),
('a690808e-c49b-425b-ae8e-fbeed21c31f8','四賓主 主中賓','釋正覺','宋','宋诗','song-poetry','','[]','御樓吹角六街明，金馬將軍出禁城。',32,'全唐诗/poet.song.102000.json','["御樓吹角六街明，金馬將軍出禁城。", "閫外化權良有準，不傷風物致昇平。"]'),
('d6c8ea94-4fcf-4f21-8fce-5dc1bb62b5bd','四賓主 主中主','釋正覺','宋','宋诗','song-poetry','','[]','不動金輪萬德全，宸苔含月未排班。',32,'全唐诗/poet.song.102000.json','["不動金輪萬德全，宸苔含月未排班。", "當頭諱字寰中禁，誰敢依稀犯聖顔。"]'),
('1cd8b12f-0eba-4ef8-b6c3-592dae8df3e1','四料簡 奪人不奪境','釋正覺','宋','宋诗','song-poetry','','[]','懶問誰持造化權，門前春事正暄妍。',32,'全唐诗/poet.song.102000.json','["懶問誰持造化權，門前春事正暄妍。", "雨晴花色明如錦，風暖鶯聲滑似絃。"]'),
('3ea54af4-cc44-4173-a7e5-e346df8565ac','四料簡 奪境不奪人','釋正覺','宋','宋诗','song-poetry','','[]','厭餘客路忽思家，鬢髮春饒盡雪華。',32,'全唐诗/poet.song.102000.json','["厭餘客路忽思家，鬢髮春饒盡雪華。", "月底路歧通著脚，歸心未穩隔煙霞。"]'),
('e57e151c-2cce-460a-a7e8-acf2f4dd8c54','四料簡 人境兩俱奪','釋正覺','宋','宋诗','song-poetry','','[]','罷奏笙篁夜欲闌，銀河光浸紫微寒。',32,'全唐诗/poet.song.102000.json','["罷奏笙篁夜欲闌，銀河光浸紫微寒。", "星移月暗無消息，客散雲樓酒椀乾。"]'),
('b1d3ea07-d073-47f5-8fe1-c55120c16745','四料簡 人境俱不奪','釋正覺','宋','宋诗','song-poetry','','[]','十分花事屬歌喉，笑入芳塵爛漫遊。',32,'全唐诗/poet.song.102000.json','["十分花事屬歌喉，笑入芳塵爛漫遊。", "皇道太平無忌諱，縱橫何處不風流。"]'),
('7f6ab18e-41fd-4969-a8ed-cee2d4b88259','借功明位','釋正覺','宋','宋诗','song-poetry','','[]','蘋末風休夜正央，水天虛碧共秋光。',32,'全唐诗/poet.song.102000.json','["蘋末風休夜正央，水天虛碧共秋光。", "月船不犯東西岸，須信篙人用意良。"]'),
('f51d8639-1726-4588-b407-130aec6791e9','借位明功','釋正覺','宋','宋诗','song-poetry','','[]','六戶虛通路不迷，太陽影裏不當機。',32,'全唐诗/poet.song.102000.json','["六戶虛通路不迷，太陽影裏不當機。", "縱橫妙展無私化，恰恰行從鳥道歸。"]'),
('bda7aebd-933a-4cb6-9dda-1b8ed727d1cb','借借不借借','釋正覺','宋','宋诗','song-poetry','','[]','識盡甘辛百草頭，鼻無牽纆得優遊。',32,'全唐诗/poet.song.102000.json','["識盡甘辛百草頭，鼻無牽纆得優遊。", "不知有去成知有，始信南泉喚作牛。"]'),
('f4d52d46-3509-4627-b1b5-dcc242afa3d1','全超不借借','釋正覺','宋','宋诗','song-poetry','','[]','霜重風嚴景寂寥，玉關金鎖手慵敲。',32,'全唐诗/poet.song.102000.json','["霜重風嚴景寂寥，玉關金鎖手慵敲。", "寒松盡夜無虛籟，老鶴移棲空月巢。"]'),
('567426c5-1bc8-425d-83e3-839f68136277','針線貫通','釋正覺','宋','宋诗','song-poetry','','[]','峩峩青山著秋瘦，毛髮凋減風骨舊。',64,'全唐诗/poet.song.102000.json','["峩峩青山著秋瘦，毛髮凋減風骨舊。", "白雲乃子久相依，清風借力扶出岫。", "人間雨足便歸來，澹泞寒明同去就。", "箇中消息妙不傳，白雲無心青山壽。"]'),
('843200e2-1fe1-4b1f-b3b6-fa258393a282','真身','釋正覺','宋','宋诗','song-poetry','','[]','一葉落時天下秋，不風流處却風流。',32,'全唐诗/poet.song.102000.json','["一葉落時天下秋，不風流處却風流。", "木人退步金繩斷，直下無機牽鐵牛。"]'),
('1cbae67f-e879-41e9-8596-26852dc18a38','應身','釋正覺','宋','宋诗','song-poetry','','[]','雙六盤中信彩贏，風行草偃月彎晴。',32,'全唐诗/poet.song.102000.json','["雙六盤中信彩贏，風行草偃月彎晴。", "攔街截巷憨皮袋，彌勒何時不下生。"]'),
('8806abee-0bdc-4ab9-a4ac-40a84ad07573','門裏出身','釋正覺','宋','宋诗','song-poetry','','[]','無位真人赤肉團，大千沙界著毛端。',32,'全唐诗/poet.song.102000.json','["無位真人赤肉團，大千沙界著毛端。", "明明不借他家事，用處全功祇箇般。"]'),
('d562d3ba-8167-49a4-877c-d8f6008a7888','身裏出門','釋正覺','宋','宋诗','song-poetry','','[]','放曠還來荆棘林，倒騎牛自醉吟吟。',32,'全唐诗/poet.song.102000.json','["放曠還來荆棘林，倒騎牛自醉吟吟。", "誰嫌煙雨鬧蓑笠，祇箇虛空不掛針。"]'),
('ae2abb39-1f1e-44bf-aefd-6c19a98e51d6','因覽仰山小釋迦語成唱道二首  其一','釋正覺','宋','宋诗','song-poetry','','[]','脫盡諸緣空不空，杳無邊表喻難同。',64,'全唐诗/poet.song.102000.json','["脫盡諸緣空不空，杳無邊表喻難同。", "須知月蚌腸中物，體取雲犀角裏通。", "建化何妨行鳥道，迴途復妙顯家風。", "太平遊子歸來也，雲鬢霜眉內轉功。"]'),
('caffcaa0-7dae-4772-a72a-098f23091cb3','因覽仰山小釋迦語成唱道二首  其二','釋正覺','宋','宋诗','song-poetry','','[]','一念全超曠劫初，玉人端坐白牛車。',32,'全唐诗/poet.song.102000.json','["一念全超曠劫初，玉人端坐白牛車。", "往來歷盡傍參妙，回首途中物物渠。"]'),
('fb52e04e-2d33-43e4-91a5-3f12ed46d18c','禮三祖智鑑禪師塔','釋正覺','宋','宋诗','song-poetry','','[]','道無揀擇，水深山嶷。',56,'全唐诗/poet.song.102000.json','["道無揀擇，水深山嶷。", "祖無出沒，月寒天碧。", "不萌枝上覺華春，無影樹頭靈鳥宅。", "天柱巍峩兮星河瀉清，石牛哮吼兮洞雲生白。"]'),
('b1f46520-c751-402b-b60c-da6159e2b432','禮四祖大醫禪師塔','釋正覺','宋','宋诗','song-poetry','','[]','祖道已傳，黄梅妙齡。',52,'全唐诗/poet.song.102000.json','["祖道已傳，黄梅妙齡。", "幻泡忽滅，白浄無形。", "真相堂堂照膏火，教音默默鳴風鈴。", "老松掛月寒方夜，凍鶴巢雲夢未醒。"]'),
('4e01b6ad-df83-4027-8970-d5ce05a9e4f5','禮五祖大滿禪師塔','釋正覺','宋','宋诗','song-poetry','','[]','黄梅果熟，白藕花開。',52,'全唐诗/poet.song.102000.json','["黄梅果熟，白藕花開。", "問唯佛性，種異凡胎。", "衣傳南嶺人將去，松老西山我再來。", "兩借皮囊成底事，一壺風月湛無埃。"]'),
('ad19513a-ad0c-4c01-97d8-d030d05067c5','禮投子青禪師塔','釋正覺','宋','宋诗','song-poetry','','[]','塔藏玉骨，雲抱山腰。',72,'全唐诗/poet.song.102000.json','["塔藏玉骨，雲抱山腰。", "跡塵外泯，道光內昭。", "度金針之玉線，續鳳絃之鸞膠。", "壺春在而花芳枯木，夜鶴鳴而月浸孤巢。", "家風清淡兮石牛飲水，兒孫秀拔兮天柱摩霄。"]'),
('084a2ab5-4188-4b46-8e6f-2c9584ed2ff1','贊芙蓉師祖真','釋正覺','宋','宋诗','song-poetry','','[]','鳳眼鶴形，宗門偉匠。',56,'全唐诗/poet.song.102000.json','["鳳眼鶴形，宗門偉匠。", "量外提撕，聲前敲唱。", "據令兮長劍倚天，應機兮明珠在掌。", "太虛有月兮老兔含霜，大海無風兮華鯨吹浪。"]'),
('45259cfd-00ac-403b-b9e1-275f378cddf6','六代祖師畫像贊 初祖達磨禪師','釋正覺','宋','宋诗','song-poetry','','[]','西付不了，東行相討。',56,'全唐诗/poet.song.102000.json','["西付不了，東行相討。", "大乘氣遥，少林春早。", "九年面壁，求人而急。", "三拜髓傳，得嗣而賢。", "蘆華明月夜船轉，水遠天低秋色連。"]'),
('b4ada3fe-57bc-45e9-8ab1-cfeb7a68fe81','六代祖師畫像贊 二祖大祖禪師','釋正覺','宋','宋诗','song-poetry','','[]','立雪齊腰，求法斷臂。',58,'全唐诗/poet.song.102000.json','["立雪齊腰，求法斷臂。", "有志忘諸軀，無心契諸己。", "了了常知，其知密微。", "妙不借口，的自傳衣。", "全功歸父底時節，拈轉虛空絕所依。"]'),
('94b9b2b3-4c09-4dc6-a7ea-3f3ad5f8d5bf','六代祖師畫像贊 三祖監智禪師','釋正覺','宋','宋诗','song-poetry','','[]','道無揀擇，宗非促延。',58,'全唐诗/poet.song.102000.json','["道無揀擇，宗非促延。", "死生外著，清白家傳。", "覓罪性空，廓然大同。", "妙盡亡能境，機回却借功。", "虛明自照靡心識，海月靈犀夜魄通。"]'),
('2920e948-9315-4421-b691-83627af115d9','六代祖師畫像贊 四祖大醫禪師','釋正覺','宋','宋诗','song-poetry','','[]','授屈眴衣，秉毗盧印。',66,'全唐诗/poet.song.102000.json','["授屈眴衣，秉毗盧印。", "師坐西山，名稱東震。", "蜂服之粉兮春蜜之滋，蚌腸之珠兮夜蟾之孕。", "遠氣呈祥，靈枝發旁。", "牛頭接得融居士，華鳥不來庵外忙。"]'),
('e29de89c-853c-4195-9082-c816cc4a5541','六代祖師畫像贊 五祖大滿禪師','釋正覺','宋','宋诗','song-poetry','','[]','奇女之兒，雙峯之嗣。',68,'全唐诗/poet.song.102000.json','["奇女之兒，雙峯之嗣。", "傳衣世稱乎妙齡，栽松我愧乎頹齒。", "前後兩身，古今一心。", "孤鸞風舞玻璃鏡，長鯨月輾珊瑚林。", "鉢盂狤獠人將去，幾夜舂坊無碓音。"]'),
('a6daff06-0ccc-48a2-977d-dc25186d9ed8','六代祖師畫像贊 六祖大監禪師','釋正覺','宋','宋诗','song-poetry','','[]','廣南樵夫，淮西行者。',104,'全唐诗/poet.song.102000.json','["廣南樵夫，淮西行者。", "明珠走盤，黄金出冶。", "透影像兮凡聖罔得同塵，續光明兮家世自然不夜。", "衆星之拱斗之魁，百川之趨海之下。", "棄鉢袋而逃，提不起而懇招。", "非風旛之摇，示即物之情超。", "葉落歸根兮來時無口，百千三昧兮九牛一毛。"]'),
('4709ebc6-3ca4-4b2f-9c17-551328bdc3c3','雪竇宗長老茲寫師像以授天童知事壁龕而掛之乞語書其上','釋正覺','宋','宋诗','song-poetry','','[]','妙藏絕鄰，畢竟無身也清虛之理真。',132,'全唐诗/poet.song.102000.json','["妙藏絕鄰，畢竟無身也清虛之理真。", "幽靈獨神，須臾返色也自照之智親。", "雲寒有雪意，天遠連秋津。", "緣起佛種，覺生幻塵。", "語細音柔，丹山鳳鶵之韻。", "目深眉重，檀林師子之顰。", "借位途中賓主，借功門裏君臣。", "洞水逆流，望雲巖而半肯。", "曹山顛酒，知清稅未全貧。", "曲木床頭握麈尾，心傳一句付其人。"]'),
('697ff0c8-3e72-4636-94b5-b4a9bdb67d5a','大寧悟長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','眼睛活，髑髏乾，妙在離微轉處看。',64,'全唐诗/poet.song.102000.json','["眼睛活，髑髏乾，妙在離微轉處看。", "魚潛水而秋痕愈碧，鶴卧松而月夢猶寒。", "應呼之神居谷，隨色之珠走盤。", "影響黏誰眉得用，斲泥餘地鼻無漫。"]'),
('1f532218-fff3-448f-99aa-c05579bc5d5c','萬壽暉長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','空而無痕，綿綿體之若存。',102,'全唐诗/poet.song.102000.json','["空而無痕，綿綿體之若存。", "卓而莫羣，恰恰用之不勤。", "光明破夜月，淡泞出山雲。", "無得而得，不聞而聞。", "少林之傳默默，靈山之笑欣欣。", "龍雷相送魚燒尾，豹霧俄披虎炳文。", "齊物飄飄兮流夢似隨蝴蝶去，亡機蕩蕩兮清閒還與白鷗分。"]'),
('998406c4-adf2-4abf-b5ef-352d1dc4bd9e','保福萃長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','少食棗而齒黄，老飽鹽而癭亡。',66,'全唐诗/poet.song.102000.json','["少食棗而齒黄，老飽鹽而癭亡。", "兔分月魄入犀角，蜂採華滋歸蜜房。", "源深流長，體明用光。", "巍巍堂堂，煒煒煌煌。", "檀篆香消默無語，烏藤相伴倚繩床。"]'),
('c93e6146-5cb0-415c-9cae-67ca3a27901d','清潭榮長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','家山水兮，靜忘處所。',116,'全唐诗/poet.song.102000.json','["家山水兮，靜忘處所。", "友魚鳥兮，動忘爾汝。", "默默之得誰傳，的的之宗自舉。", "冰壺春未回，而痕垢無些。", "玉林月已上，而清光有許。", "湛存此箇宗乘，肯壞人家男女。", "黄梅之鉢笑夜偷，少室之衣疑浪與。", "方徹地區，圓該天宇。", "神發幽而空谷應呼，聲出礙而霜鐘忽杵。"]'),
('57e16457-1540-497d-a483-5887bfddf338','光孝恭長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','問者不親，傳者不真。',108,'全唐诗/poet.song.102000.json','["問者不親，傳者不真。", "默成之性，空照而神。", "湛存而無像，幽靈而絕鄰。", "赫爐冶而鑄其器，吹風烟而造其春。", "建立諸幻，發明至淳。", "匠手之揮斤刃利，蠅泥之去鼻端塵。", "其斲有信，其受難人。", "偃蹇之松兮獨扶疏於雪試，臲卼之石兮幾破碎於雷瞋。"]'),
('07b51ebc-b893-4b9a-85d7-ed2e2d8bc145','能仁翼長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','行脚句親，住山迹陳。',96,'全唐诗/poet.song.102000.json','["行脚句親，住山迹陳。", "默有餘味，言還失真。", "金發響而出礙，玉雕文以喪純。", "胸中器宇，眉底精神。", "虎生三日食牛氣，海闊萬里吞舟鱗。", "性得全提鼻，心傳不挂唇。", "白雪家庭兮獨立腰齊之士，紅蕉棋局兮嘗觀柯爛之人。"]'),
('2713a6e5-13bf-4380-8fc9-3db3b175d9a2','南明慧長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','髮之白兮蒼山雪寒，眼之冷兮遠水秋還。',79,'全唐诗/poet.song.102000.json','["髮之白兮蒼山雪寒，眼之冷兮遠水秋還。", "機自轉兮夜斗有柄，氣自清兮星河無瀾。", "谷應聲而亡像，珠受色而不瘢。", "瀛海潮落兮平且浄，天宇雲收兮虛更寬。", "萬化起滅兮，默見其端。"]'),
('e0faaba8-db84-4a96-b2a1-91a117835cf1','祖印漸長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','面孔誰傳，身心自然。',70,'全唐诗/poet.song.102000.json','["面孔誰傳，身心自然。", "鑑含萬像，海吞百川。", "錦機動而綵絲度，玉線透而金針聯。", "說法借口，嚇人空拳。", "平等莫移兮任鶴長而鳧短，縱橫從變兮爻坤斷而乾連。"]'),
('d8fc8fb2-e04c-4129-85ac-d23e60408f39','浄居照長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','真乘無門兮佛佛道同，面壁有句兮祖祖心空。',68,'全唐诗/poet.song.102000.json','["真乘無門兮佛佛道同，面壁有句兮祖祖心空。", "靜居方外，智入環中。", "借功明寂默，借伴入樊籠。", "十方周匝，三世混融。", "剎剎塵塵齊說法，見聞互換自相通。"]'),
('d501f0be-b518-49b3-adf4-cb2813da356e','報願慧長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','水秋而清，月寒而明。',90,'全唐诗/poet.song.102000.json','["水秋而清，月寒而明。", "萬機休罷，三際齊平。", "塵消却到法身住，幻起還從佛口生。", "長天之覆，大地之擎。", "諸祖與之同道，衆彙與之同行。", "龜毛拂而握豎，兔角杖而膝橫。", "更無一物借來底，招手憨僧作證成。"]'),
('a6b40b71-31be-474b-8587-a179c9f1f5fb','能仁仁長老寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','大圓鏡性，平等智心。',76,'全唐诗/poet.song.102000.json','["大圓鏡性，平等智心。", "老兔卧寒兮清炯炯明月之窟，長鯨𩥇海兮光漾漾珊瑚之林。", "千里雪翻波渺渺，百川潮漲水深深。", "鵬摶鯤，蛻殻子。", "和鶴鳴陰隨應還，游刃相逢有賞音。"]'),
('a5c00e0d-b597-474c-98b3-1bb06ab3ba07','惠首座寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','衰颯儀容，僶俛頹慵。',48,'全唐诗/poet.song.102000.json','["衰颯儀容，僶俛頹慵。", "玲瓏巖寺，夭矯雲松。", "艷冷晚秋菊，韻清霜曉鐘。", "剎剎塵塵三昧事，知音何處不相逢。"]'),
('6b3cb74f-c983-4a40-be06-876b6cd1581c','璋監寺寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','杳杳冥冥，寒雁影沒而秋遠煙青。',230,'全唐诗/poet.song.102000.json','["杳杳冥冥，寒雁影沒而秋遠煙青。", "寂寂惺惺，老蠶繭就而風高葉零。", "天機靜時活，道環虛處靈。", "瀛之涵，崧之鎮。", "乾之健，坤之寧。", "海運鵬摶，氣宇揚揚而吞舟魚蛻。", "霧披豹變，文章炳炳而嘯風虎猛。", "少林之燈未續兮，洛陽人腰齊雪庭。", "黄梅之衣欲傳兮，狤獠祖步移碓程。", "物不當情而冰凌脚快，鱗或燒尾兮電火氣腥。", "諸塵崝嶸乎影響，三昧遊戲於眺聆。", "跛跛挈挈也其行自信，哆哆和和也其言不輕。", "家法冷淡，子孫寧馨。", "心歲寒而松柏試雪，色清白兮河漢含星。", "鳴陰之鶴癯而壽，巢蓮之龜小而齡。", "棋局未散，柯爛樵丁。"]'),
('25889c01-b5a9-40ee-8bdc-8909d34d1866','參頭智舒與衆行者寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','背鮐齒鯢，皮雞髮鶴。',138,'全唐诗/poet.song.102000.json','["背鮐齒鯢，皮雞髮鶴。", "西北出家，東南行脚。", "選佛到空覺覺空，爲人除藥病病藥。", "夕壑雲生，秋潭月落。", "偏正機輪，方圓枘鑿。", "蝴蝶之春夢栩栩而物齊，白鷗之野盟飄飄而閒樂。", "妙觸無當，沖應何作。", "劍之揮空而彼此不痕，珠之受影而自他相若。", "氣韻巖稄，音旨拗斡。", "跛跛挈挈兮有底迂疏，哆哆和和兮不空罥索。"]'),
('2ae00f7f-f4a1-4c15-959d-c7d11462b6ac','湯壽鄉察推寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','形儀潦倒，氣貌寒槁。',66,'全唐诗/poet.song.102000.json','["形儀潦倒，氣貌寒槁。", "野雲自閒，巖樹誰老。", "性元靜而妙存，體本真而空了。", "幻世應諸緣，荒田不揀草。", "風烟望斷兮鴻影冥冥，天水相連兮秋容渺渺。"]'),
('736ad720-82bb-4df6-8137-d77c622cef39','錢郎中寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','勝浄明心，混融古今。',86,'全唐诗/poet.song.102000.json','["勝浄明心，混融古今。", "河漢之氣清秋闊，牛斗之光寒夜深。", "機歷歷兮錦梭吐緒，道綿綿兮玉線聯針。", "月漾珊瑚海，春回薝蔔林。", "法法變通手段，塵塵出礙胸襟。", "明鏡誰嫌差別像，空山自答合同音。"]'),
('c0f708ce-9869-4c34-998d-c1cd44cb2648','張漢鄉寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','頂覆白雪，眼橫碧波。',62,'全唐诗/poet.song.102000.json','["頂覆白雪，眼橫碧波。", "清霜濡斗柄，古壁掛龍梭。", "少林之華未老，曹溪之鏡非磨。", "所得幾何，家傳不多。", "飽諳雲水三條篾，釣盡江湖一片蓑。"]'),
('9e97458a-f78d-4fdf-99c3-e4d4667a504f','張監稅寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','幽討厥初，湛存若虛。',88,'全唐诗/poet.song.102000.json','["幽討厥初，湛存若虛。", "體明無盡，氣清有餘。", "太行之雪壓屋，黄河之冰載車。", "豹霧變文之虎，龍雷燒尾之魚。", "風烟濡膩，草木光舒。", "根根塵塵了了，法法念念如如。", "舂坊行者得衣鉢，可信心傳不在書。"]'),
('eb420c86-e67c-490c-be0c-f5b8481ea9f6','智宣直歲寫師像求贊','釋正覺','宋','宋诗','song-poetry','','[]','霜顱雪髭，壑眼巖眉。',48,'全唐诗/poet.song.102000.json','["霜顱雪髭，壑眼巖眉。", "崑崙源我據，渾沌鑿誰持。", "雁行沒處秋天闊，華氣繁時春日遲。", "諸塵出礙，妙觸無疵。"]'),
('a6321525-5ffe-43d4-a44f-e6af4fee6590','禪人并化主寫真求贊  其一','釋正覺','宋','宋诗','song-poetry','','[]','雲橫其肩，雪覆其顛。',146,'全唐诗/poet.song.102000.json','["雲橫其肩，雪覆其顛。", "空空養慧，兀兀忘緣。", "月射珊瑚兮海發光而不夜，松生琥珀兮根擁膏而有年。", "性惟平等，道法自然。", "鈐鎚之在握，杖拂之當拳。", "豹霧披梓樹之野，龍雷吼桃華之川。", "雲水叢林秋與老成之氣韻，溪山草木春曾醞釀於風煙。", "兒孫之力，學佛祖之家傳。", "針線之關，度龕燈之焰聯。", "向道龍門無宿客，而今龜鶴盡成仙。"]'),
('84f7f39e-2c87-4029-92ab-2f399153ac60','禪人并化主寫真求贊  其二','釋正覺','宋','宋诗','song-poetry','','[]','氣清水秋，骨寒木槁。',56,'全唐诗/poet.song.102000.json','["氣清水秋，骨寒木槁。", "青眼柳春深，白頭山雪早。", "具大人相也空落不驚，有大力量也風吹便倒。", "箇些妙處難傳，向道畫工草草。"]'),
('25aa17ce-bb1d-4e90-8fb4-9cc41ce33c70','禪人并化主寫真求贊  其三','釋正覺','宋','宋诗','song-poetry','','[]','松節老剛，巖稜早霜。',52,'全唐诗/poet.song.102000.json','["松節老剛，巖稜早霜。", "鷗閒沙漠漠，雁沒煙蒼蒼。", "爻象乾連坤斷，形器規圓矩方。", "鬧市相逢聊舉似，東家杓短西家長。"]'),
('a6f422e8-269b-40c8-8da5-9513a272c5e7','禪人并化主寫真求贊  其四','釋正覺','宋','宋诗','song-poetry','','[]','淵默湛存，道超見聞。',66,'全唐诗/poet.song.102000.json','["淵默湛存，道超見聞。", "真照本有，妙盡新勳。", "虛谷之神兮大千界滿，明月之影兮百億身分。", "無住也浮萍流水，自由也飛鳥行雲。", "得之有據，用之不勤。"]'),
('a077e10c-712d-4ab5-8b2e-37d75ae79a4e','禪人并化主寫真求贊  其五','釋正覺','宋','宋诗','song-poetry','','[]','口闊鼻隆，神靜心空。',64,'全唐诗/poet.song.102000.json','["口闊鼻隆，神靜心空。", "雪蘆岸稜遠，水天秋色同。", "夜寒北斗垂金柄，月落西山藏玉弓。", "真機宛轉，幻住圓融。", "古佛自然交露柱，翻手覆手看變通。"]'),
('58165048-c525-4140-b234-efc9c317cb2b','禪人并化主寫真求贊  其六','釋正覺','宋','宋诗','song-poetry','','[]','巖壑之間，草木之陽春。',78,'全唐诗/poet.song.102000.json','["巖壑之間，草木之陽春。", "江湖之上，風煙之精神。", "髮鬚野雪，眉目秋津。", "淵默入寒蟾之窟，圓明養老蚌之珍。", "步步入塵，門門出身。", "莫愁指端兮焦尾之曲，可意鈎上兮赤稍之鱗。"]'),
('1c2b3a10-b37a-4614-a2a9-15e5f24db8bf','禪人并化主寫真求贊  其七','釋正覺','宋','宋诗','song-poetry','','[]','身閒類莫收，心靜情不流。',56,'全唐诗/poet.song.102000.json','["身閒類莫收，心靜情不流。", "片月自炯炯，孤雲長悠悠。", "顛毛衰白高山雪，眉目寒清古澗秋。", "把似春風些子妙，施於草木十方周。"]'),
('eb478309-75b9-4869-96c3-aec66b04d619','禪人并化主寫真求贊  其八','釋正覺','宋','宋诗','song-poetry','','[]','太行盤紆，黄河泄舒。',66,'全唐诗/poet.song.102000.json','["太行盤紆，黄河泄舒。", "肝膽明潔，胸膺廓虛。", "清風未生齒頰，白雪已上眉鬚。", "少林之默無他說，黄梅之舂不識書。", "徹見本來人面目，名言安敢妄分疏。"]'),
('53dbbbc4-0868-411f-9a9e-65af76bf5ffb','禪人并化主寫真求贊  其九','釋正覺','宋','宋诗','song-poetry','','[]','識浪瀝乾，肚皮束寬。',50,'全唐诗/poet.song.102000.json','["識浪瀝乾，肚皮束寬。", "口翻瀾而海闊，髮垂雪而山寒。", "妙傳家法髑髏眼，巧幻神通赤肉團。", "相隨來也，搥鑿無瘢。"]'),
('c2fa24f9-8dd7-47a5-b9cd-b897453fbc06','禪人并化主寫真求贊  其一○','釋正覺','宋','宋诗','song-poetry','','[]','山覆雪兮一顛白，水深秋兮兩眼青。',82,'全唐诗/poet.song.102000.json','["山覆雪兮一顛白，水深秋兮兩眼青。", "卦爻初作象，皮骨自成形。", "混沌已前之樸，陰陽未判之靈。", "道傳不出世佛，義備勿開題經。", "應兮雲月，用也雷霆。", "有守而涵海鎮嶽，無羈而斷梗流萍。"]'),
('8b204674-4012-40aa-9459-250311a00b1e','禪人并化主寫真求贊  其一一','釋正覺','宋','宋诗','song-poetry','','[]','癡坐頹然，山空壑乾。',88,'全唐诗/poet.song.102000.json','["癡坐頹然，山空壑乾。", "離微出入，偏正往還。", "千年琥珀之松兮鶴巢夢冷，半夜珊瑚之月兮鯨𩥇波寒。", "全功及盡，借路何難。", "轉步而回叢林也津津和氣，放口而說河漢也浩浩翻瀾。", "道逢作者，誰敢相謾。"]'),
('b455f53c-e8d4-45e7-9735-c5060a1e29ce','禪人并化主寫真求贊  其一二','釋正覺','宋','宋诗','song-poetry','','[]','妙傳乎真，轉側而神。',54,'全唐诗/poet.song.102000.json','["妙傳乎真，轉側而神。", "赤脚劫空歸去路，白頭借伴却來人。", "無心分物我，何處著根塵。", "煙柳鶯華鬧浩浩，太平時節大家春。"]'),
('d3e2bc4c-7d03-4e7e-a1a4-badd12f950f4','禪人并化主寫真求贊  其一三','釋正覺','宋','宋诗','song-poetry','','[]','炯炯寒瞳，絲絲衰鬢。',76,'全唐诗/poet.song.102000.json','["炯炯寒瞳，絲絲衰鬢。", "丘壑之姿，煙霞之韻。", "據坐而心空，森羅而海印。", "中虛也乾而成離，內動也艮而變震。", "雲行而用閑，電掣而機迅。", "狤獠人不惹塵埃，黄梅祖親傳屈眴。"]'),
('4026e083-c24b-4af6-ae58-35df39c2898d','禪人并化主寫真求贊  其一四','釋正覺','宋','宋诗','song-poetry','','[]','兀兀心傳，了了忘緣。',78,'全唐诗/poet.song.102000.json','["兀兀心傳，了了忘緣。", "葉零白露，雲散青天。", "玉轂兔推而洗開夜色，銀籠鶴出而飛度寒煙。", "借功明位，借伴入廛。", "應無爽而理之平等，用不勤而道之自然。", "相逢識者，便與開拳。"]'),
('6870036e-a1c3-4fa0-a819-2255acc0f00c','禪人并化主寫真求贊  其一五','釋正覺','宋','宋诗','song-poetry','','[]','頂雪抗春，目寒射人。',52,'全唐诗/poet.song.102000.json','["頂雪抗春，目寒射人。", "蓑裹江湖雨，斗浮河漢津。", "拙忘機兮抱甕，妙不傳兮斲輪。", "谷鳥巖華自聲色，十方普現剎塵身。"]'),
('62cd17a2-a470-482a-aae7-98c731460028','禪人并化主寫真求贊  其一六','釋正覺','宋','宋诗','song-poetry','','[]','氣貌稜稜，眉目溫溫。',68,'全唐诗/poet.song.102000.json','["氣貌稜稜，眉目溫溫。", "一脈之分派發崑崙之源，百川之吞潮落珊瑚之根。", "風煙清遠秋之痕，草木秀拔春之恩。", "古壁之梭兮蟄龍之骨，寒潭之璧兮夜月之魂。"]'),
('49e798ca-3f2b-435a-9fdf-9e54258bcd1e','禪人并化主寫真求贊  其一七','釋正覺','宋','宋诗','song-poetry','','[]','老髮衰髭，頂雪頷絲。',74,'全唐诗/poet.song.102000.json','["老髮衰髭，頂雪頷絲。", "方頭似鑿，鈍口如椎。", "相逢閒受用，慣喫落便宜。", "蒲鞋價賤陳尊宿，漿水錢還王老師。", "法不當情兮平等得定慧之學，心無所住兮自然見離微之時。"]'),
('7c60c098-31f9-4148-bf7d-6e6b7d6ebebd','禪人并化主寫真求贊  其一八','釋正覺','宋','宋诗','song-poetry','','[]','松石歲寒，雲月高閑。',62,'全唐诗/poet.song.102000.json','["松石歲寒，雲月高閑。", "野雪髮鬚上，秋波眉睫間。", "用持智柄，靜入道環。", "覺心了了，幻事斑斑。", "草木精神兮風流自得，叢林氣像兮春信誰慳。"]'),
('f2fb6eda-bc67-44c8-ad9c-a4b7ddcf1f02','禪人并化主寫真求贊  其一九','釋正覺','宋','宋诗','song-poetry','','[]','雪浸髮根，秋生眼稜。',52,'全唐诗/poet.song.102000.json','["雪浸髮根，秋生眼稜。", "明月泉頭客，清風樓上僧。", "潮翻麈尾兮蹴踏龍象，風旋羊角兮變化鯤鵬。", "主盟佛事，最得人憎。"]'),
('d6274cc1-98f3-4d0a-b811-578b92807387','禪人并化主寫真求贊  其二○','釋正覺','宋','宋诗','song-poetry','','[]','三河野人，兩浙社賓。',38,'全唐诗/poet.song.102000.json','["三河野人，兩浙社賓。", "湛存該理智，妙觸出根塵。", "烏藤行脚叢林事，鈯斧住山雲水身。"]'),
('34bdd4ce-8234-43e4-817a-f5c1b48ffcf5','禪人并化主寫真求贊  其二一','釋正覺','宋','宋诗','song-poetry','','[]','枯木形骸，野雲蹤跡。',50,'全唐诗/poet.song.102000.json','["枯木形骸，野雲蹤跡。", "照兮夜色月摩，默也潭空秋入。", "三千界，露半身。", "九萬里，成一息。", "隨類應緣，何翅百億。"]'),
('eb4c02dd-6b51-438a-a377-f318cfb17478','禪人并化主寫真求贊  其二二','釋正覺','宋','宋诗','song-poetry','','[]','巖巖山有秋痕，淡淡雲無宿根。',44,'全唐诗/poet.song.102000.json','["巖巖山有秋痕，淡淡雲無宿根。", "入極一默之底，出成三昧之門。", "用不勤，湛若存，澄弗清兮攪不渾。"]'),
('ad3211b2-f2ce-475b-ba45-b7747c67385a','禪人并化主寫真求贊  其二三','釋正覺','宋','宋诗','song-poetry','','[]','漆黑眸子，梔黄面皮。',73,'全唐诗/poet.song.102000.json','["漆黑眸子，梔黄面皮。", "智靜霽月相照，身閒野雲不羈。", "該抹把手陳尊宿，細膩點頭王老師。", "針兮線兮明聯暗綴，音兮律兮自拍獨吹。", "你道是誰，芙蓉之孫兮丹出之兒。"]'),
('001c4d4c-0dfc-4c41-8118-5a1830a3ed1f','禪人并化主寫真求贊  其二四','釋正覺','宋','宋诗','song-poetry','','[]','稜稜之山早雪，淵淵之水先秋。',42,'全唐诗/poet.song.102000.json','["稜稜之山早雪，淵淵之水先秋。", "靜也虛谷之應，動也閑雲之流。", "自憐方外專默，誰與環中至遊。"]'),
('3f1d6188-0dde-479e-b81e-c748d622879b','禪人并化主寫真求贊  其二五','釋正覺','宋','宋诗','song-poetry','','[]','雲山之姿，水月之像。',54,'全唐诗/poet.song.102000.json','["雲山之姿，水月之像。", "大海之容，太虛之量。", "受也的的無心，應也頭頭離相。", "隨緣有照兮妙而不痕，徹底亡依兮空而不蕩。"]'),
('fbba9ef3-9ea1-41c7-aaaf-0e80ffb4c04a','禪人并化主寫真求贊  其二六','釋正覺','宋','宋诗','song-poetry','','[]','默有心傳，休將相觀。',52,'全唐诗/poet.song.102000.json','["默有心傳，休將相觀。", "煙巢鶴夢，月窟蟾寒。", "靜裏萬緣藏鼻孔，笑中百事見眉端。", "而今鬚髮點半白，向道叢林歷百難。"]'),
('42d82a72-aea1-4708-9696-a1b3d4f41746','禪人并化主寫真求贊  其二七','釋正覺','宋','宋诗','song-poetry','','[]','只是箇人，到處分身。',64,'全唐诗/poet.song.102000.json','["只是箇人，到處分身。", "萬水中間月，百華頭上春。", "不外一法，不受諸塵。", "生處熟也疏處親，默時說也靜時神。", "鉢盂著飯飽還喜，拄杖入拳饑放嗔。"]'),
('721fa636-294b-402d-bfc4-266e8fb0683e','禪人并化主寫真求贊  其二八','釋正覺','宋','宋诗','song-poetry','','[]','一相無相，虛空等量。',45,'全唐诗/poet.song.102000.json','["一相無相，虛空等量。", "一身多身，物像俱春。", "動也出岫之雲，靜也居谷之神。", "現形說法也，剎剎塵塵。"]'),
('9122858e-f50d-4265-b0a9-eed25ac6a237','禪人并化主寫真求贊  其二九','釋正覺','宋','宋诗','song-poetry','','[]','看看，變態毫端。',40,'全唐诗/poet.song.102000.json','["看看，變態毫端。", "春風不泮顛毛雪，秋色自摩眸子寒。", "笑添面孔兩眉展，參飽肚皮三篾寬。"]'),
('e376d3c0-4c48-462a-884f-67502f85de83','禪人并化主寫真求贊  其三○','釋正覺','宋','宋诗','song-poetry','','[]','坐曲木床，握烏藤杖。',40,'全唐诗/poet.song.102000.json','["坐曲木床，握烏藤杖。", "鑄佛祖之楷模，活叢林之氣像。", "你莫來虎口撩鬚，誰更敢蛇頭揩癢。"]'),
('f99d5a4e-2d58-45e9-a1ae-5d38d1da0d1b','禪人并化主寫真求贊  其三一','釋正覺','宋','宋诗','song-poetry','','[]','山寒带雪痕，春信入華根。',35,'全唐诗/poet.song.102000.json','["山寒带雪痕，春信入華根。", "造化豈無柄，區分自有門。", "出出沒沒也，俱承此恩。"]'),
('3a3f9de9-0fe0-49df-997e-9945f06cc713','禪人并化主寫真求贊  其三二','釋正覺','宋','宋诗','song-poetry','','[]','髑髏歷乾，鼻孔覺寬。',43,'全唐诗/poet.song.102000.json','["髑髏歷乾，鼻孔覺寬。", "廓空三際，不立毫端。", "面目風霜殺，身心水月寒。", "情塵浄盡兮，萬像齊觀。"]'),
('0980f7d1-da94-4115-809a-7493f6692bec','禪人并化主寫真求贊  其三三','釋正覺','宋','宋诗','song-poetry','','[]','寒肩自高，饑眼較大。',54,'全唐诗/poet.song.102000.json','["寒肩自高，饑眼較大。", "烏藤瘦握拳，曲木默據座。", "無言而獨靈，有唱而誰和。", "秋摩水色兮清絕瘢痕，春入華枝兮妙亡程課。"]'),
('5b27bdc0-76c5-435a-b1bf-4209b2684d22','禪人并化主寫真求贊  其三四','釋正覺','宋','宋诗','song-poetry','','[]','衰髮半白，笑面微紅。',48,'全唐诗/poet.song.102000.json','["衰髮半白，笑面微紅。", "野水秋無像，叢林春有功。", "華繁粉夢蝶，天遠沒飛鴻。", "借問分身幾許，相隨南北西東。"]'),
('263e3b68-b3b6-4624-967a-52abee14b71f','禪人并化主寫真求贊  其三五','釋正覺','宋','宋诗','song-poetry','','[]','舌頭肉一臠，口唇皮兩片。',52,'全唐诗/poet.song.102000.json','["舌頭肉一臠，口唇皮兩片。", "有時說道談禪，忽地轟雷掣電。", "萬機影銷，一色功轉。", "本來無物鏡非臺，胡漢不痕何所見。"]'),
('65f09cc2-a395-4e71-b9ea-ba278241523d','禪人并化主寫真求贊  其三六','釋正覺','宋','宋诗','song-poetry','','[]','風觀癡甚，形骸老生。',60,'全唐诗/poet.song.102000.json','["風觀癡甚，形骸老生。", "眉稜陰覺重，鼻息靜還清。", "二儀未兆，一點圓明。", "霜洗斗牛濕，秋晴河漢橫。", "莫將毫忽痕空性，向道環中長太平。"]'),
('9b708c3c-c74f-4711-bdb5-43f75c4f70f1','禪人并化主寫真求贊  其三七','釋正覺','宋','宋诗','song-poetry','','[]','身心山野，面目草灰。',52,'全唐诗/poet.song.102000.json','["身心山野，面目草灰。", "默說一句，明暗全該。", "機流電天上之火，動發陽地中之雷。", "變化窮通有許事，向道俱從恁麽來。"]'),
('e26c5508-b92a-44be-9035-d814d9833070','禪人并化主寫真求贊  其三八','釋正覺','宋','宋诗','song-poetry','','[]','靜據胡床，久而愈芳。',64,'全唐诗/poet.song.102000.json','["靜據胡床，久而愈芳。", "默亡痕黑白，貧不覺蒼黄。", "住無相兮龜之藏，行無章兮鳥之翔。", "月爛爛而魚吞光，華菲菲而蜂採香。", "相隨來也，觸處堂堂。"]'),
('9c5e4791-486c-4334-bab4-33675faf5deb','禪人并化主寫真求贊  其三九','釋正覺','宋','宋诗','song-poetry','','[]','眉下眼深，額上骨隆。',48,'全唐诗/poet.song.102000.json','["眉下眼深，額上骨隆。", "說禪口窄，受道心空。", "閑閑無伎倆，默默有家風。", "片月濯磨秋更白，百華點染春能工。"]'),
('1701e28a-2cf3-406a-beca-c582f4e7bf2a','禪人并化主寫真求贊  其四○','釋正覺','宋','宋诗','song-poetry','','[]','暗而明，虛而盈。',62,'全唐诗/poet.song.102000.json','["暗而明，虛而盈。", "水天秋色共，月晝夜潮平。", "無在不在，無生不生。", "諸塵隨起倒，萬化得縱橫。", "默默大全兮壁挂閑口，堂堂正受兮誰黏惡名。"]'),
('c025075b-9d40-4d96-a258-f7cc439c35b1','禪人并化主寫真求贊  其四一','釋正覺','宋','宋诗','song-poetry','','[]','這樣師僧，面目可憎。',62,'全唐诗/poet.song.102000.json','["這樣師僧，面目可憎。", "名摸還不似，藏覆又何曾。", "虛空闊無工夫挂劍，滄海深有伎倆挑燈。", "抖擻頭陀備，玲瓏道者稜。", "入閩借問，何如箇能。"]'),
('f4cf51a7-75e6-44cd-b60b-95faaca4b52a','禪人并化主寫真求贊  其四二','釋正覺','宋','宋诗','song-poetry','','[]','心閑不被身礙，飯飽仍嫌口多。',40,'全唐诗/poet.song.102000.json','["心閑不被身礙，飯飽仍嫌口多。", "妙應群機活卓卓，默傳一句圓陀陀。", "呈似了也，還相識麽。"]'),
('ab5a5431-07ff-41ec-9a6b-307e06575677','禪人并化主寫真求贊  其四三','釋正覺','宋','宋诗','song-poetry','','[]','鼻筒直，眼眶深。',42,'全唐诗/poet.song.102000.json','["鼻筒直，眼眶深。", "默時自覺失却口，妙處誰會相傳心。", "便與麽，只如今，影中辨取兮戶挂凋林。"]'),
('697ee2fe-d059-489a-93b2-e59ac3154a8e','禪人并化主寫真求贊  其四四','釋正覺','宋','宋诗','song-poetry','','[]','這箇儀形，叢林飯丁。',72,'全唐诗/poet.song.102000.json','["這箇儀形，叢林飯丁。", "春山有雪髮衰白，秋水無風眼冷青。", "妙明田地，浄潔門庭。", "萬緣不倚活卓卓，一事不著空靈靈。", "把手與藥兮誰尋本草，問津指源兮自得圖經。"]'),
('2bf65b2f-c806-4c87-9daf-c02720866f9b','禪人并化主寫真求贊  其四五','釋正覺','宋','宋诗','song-poetry','','[]','形儀淡如，胸腹空虛。',58,'全唐诗/poet.song.102000.json','["形儀淡如，胸腹空虛。", "懶不學佛，鈍不知書，靜應諸緣而無外，默容萬像而有餘。", "齊物而夢蝶，樂性而觀魚。", "渠正是我兮我不是渠。"]'),
('f07016f6-762d-4c46-8133-7bd857bfbdac','禪人并化主寫真求贊  其四六','釋正覺','宋','宋诗','song-poetry','','[]','靈靈一物，名模不得。',54,'全唐诗/poet.song.102000.json','["靈靈一物，名模不得。", "長鯨居滄海之淵，老兔卧明月之窟。", "已展不縮，拗直作曲。", "只麽贏時會也無，不須喝彩兮盤中雙六。"]'),
('816721d4-8ae0-4bc8-8a56-beabe03c21fb','禪人并化主寫真求贊  其四七','釋正覺','宋','宋诗','song-poetry','','[]','似則不是，是則不似。',56,'全唐诗/poet.song.102000.json','["似則不是，是則不似。", "動兮行雲，靜兮止水。", "能隨緣，不墮類。", "百草頭上老僧，二儀已前自己。", "莫將此箇形骸，枉挂他人唇齒。"]'),
('35b708b5-6538-4891-a986-dd1be694c904','禪人并化主寫真求贊  其四八','釋正覺','宋','宋诗','song-poetry','','[]','靜掩雙皮，喜揚兩眉。',42,'全唐诗/poet.song.102000.json','["靜掩雙皮，喜揚兩眉。", "秋容清水色，春信鬧華枝。", "跛跛挈挈，憨憨癡癡，摩觸家風兮鼻孔纍垂。"]'),
('51e7874c-911d-4e60-a6ed-1bae57600470','禪人并化主寫真求贊  其四九','釋正覺','宋','宋诗','song-poetry','','[]','聞名不如見面，都盧是箇一件。',50,'全唐诗/poet.song.102000.json','["聞名不如見面，都盧是箇一件。", "風埃鬧處常閒，行市貴時却賤。", "圓珠不撥轉，精金久磨煉。", "觸犯機鋒兮青天流電。"]'),
('9ae596cf-fbe6-4a67-b70f-617ed0e9e0f6','禪人并化主寫真求贊  其五○','釋正覺','宋','宋诗','song-poetry','','[]','鬚髮老如，眉目清亮。',48,'全唐诗/poet.song.102000.json','["鬚髮老如，眉目清亮。", "秋生野水之中，雪照寒山之上。", "湛海之心，吞川之量。", "頭頭不爽機宜，處處相投穩當。"]'),
('e076d6ff-1b0b-4b80-8bb0-e4699aed55c4','禪人并化主寫真求贊  其五一','釋正覺','宋','宋诗','song-poetry','','[]','依樣畫胡盧，相逢識也無。',28,'全唐诗/poet.song.102000.json','["依樣畫胡盧，相逢識也無。", "蹉過了豐城埋劍，覷得破合浦還珠。"]'),
('d68be73f-7d54-4b0c-8694-4356b32d7be6','禪人并化主寫真求贊  其五二','釋正覺','宋','宋诗','song-poetry','','[]','髮白寒山有雪，眼深秋井澄波。',88,'全唐诗/poet.song.102000.json','["髮白寒山有雪，眼深秋井澄波。", "混沌鑿那亡大道，崑崙源自發長河。", "一笑十方三世事，不妨隨處薩婆訶。", "山高早雪，水深先秋。", "功勳極處退一步，黑白前時贏一籌。", "相隨來也還知否，南北東西得自由。"]'),
('aec7a6c6-003a-41a3-a787-e6ca2c20f2b0','禪人并化主寫真求贊  其五三','釋正覺','宋','宋诗','song-poetry','','[]','身兮芭蕉，口兮葛藤。',45,'全唐诗/poet.song.102000.json','["身兮芭蕉，口兮葛藤。", "雪乞人天飯，光傳佛祖燈。", "機活作春像，念冷摩風稜。", "金針玉線兮，誰我繩繩。"]'),
('df0aa1ac-7b48-4ed7-977e-b4175d65f6fb','禪人并化主寫真求贊  其五四','釋正覺','宋','宋诗','song-poetry','','[]','髮作殘雪之白，目带深秋之寒。',56,'全唐诗/poet.song.102000.json','["髮作殘雪之白，目带深秋之寒。", "春山未暖，野水無瀾。", "家風摩鼻孔，好事上眉端。", "三世因緣兮半身而應，十方剎海兮一吸而乾。"]'),
('62882b21-d7a1-43d7-b993-1c225c137f01','禪人并化主寫真求贊  其五五','釋正覺','宋','宋诗','song-poetry','','[]','寒坐無言，孤藤在拳。',48,'全唐诗/poet.song.102000.json','["寒坐無言，孤藤在拳。", "片心羣像外，一句萬機前。", "身閑眼活，盤滑珠旋。", "虛空故無壁落礙，解了十方三世緣。"]'),
('3e2c74ea-e48e-41cb-8374-6e8dfcfe91b2','禪人并化主寫真求贊  其五六','釋正覺','宋','宋诗','song-poetry','','[]','道隨緣而不變，源赴汲而不枯。',48,'全唐诗/poet.song.102000.json','["道隨緣而不變，源赴汲而不枯。", "禪悅之食兮飽其腹，法空之座兮跏其趺。", "青原自喜有麟角，黄檗誰嫌捋虎鬚。"]'),
('c0424e1d-06aa-40f5-8695-4070b0090156','禪人并化主寫真求贊  其五七','釋正覺','宋','宋诗','song-poetry','','[]','野水秋清，寒蟾夜明。',64,'全唐诗/poet.song.102000.json','["野水秋清，寒蟾夜明。", "氣像能虛白，家風自混成。", "鼻快筒直，眼瞋角生。", "太空同體而豁落，萬像同用而崢嶸。", "人間有飯飽皮袋，默默憨憨謝太平。"]'),
('416d804a-972e-4eda-a77a-7669382cad3c','禪人并化主寫真求贊  其五八','釋正覺','宋','宋诗','song-poetry','','[]','老態垂垂，歲月浸欺。',50,'全唐诗/poet.song.102000.json','["老態垂垂，歲月浸欺。", "半頭生白髮，瘦骨裹黄皮。", "情閑用而活，句妙默而知。", "河闊斗寒雲靜夜，天無四壁風披披。"]'),
('87df327d-6b63-4f3f-9b4a-c7aefc99b95b','禪人并化主寫真求贊  其五九','釋正覺','宋','宋诗','song-poetry','','[]','眉垂而楊，口默而方。',48,'全唐诗/poet.song.102000.json','["眉垂而楊，口默而方。", "了見源底，浄極發光。", "月魂排夜色，斗氣濯秋霜。", "誰嫌眼上瞋生角，我道機前影不章。"]'),
('f2fefd48-7080-46f3-abb0-cbcf29340933','禪人并化主寫真求贊  其六○','釋正覺','宋','宋诗','song-poetry','','[]','面孔何如，雪髮霜鬚。',48,'全唐诗/poet.song.102000.json','["面孔何如，雪髮霜鬚。", "秋明月窟，春發冰壺。", "妙盡還移步，功忘聊放鋤。", "拈來隨處成宗要，向道斯人德不孤。"]'),
('72e7f315-2271-4a48-b42c-e7522b6b7a78','禪人并化主寫真求贊  其六一','釋正覺','宋','宋诗','song-poetry','','[]','白髮顱上，青瞳眉底。',48,'全唐诗/poet.song.102000.json','["白髮顱上，青瞳眉底。", "雪點疏林，秋明野水。", "萬像自相投，一靈還不倚。", "默默一塵入正受，歷歷諸塵三昧起。"]'),
('114c80b9-1a8f-46ab-b413-817783f9b4d4','禪人并化主寫真求贊  其六二','釋正覺','宋','宋诗','song-poetry','','[]','浄而純中無一塵，純而浄中有萬應。',41,'全唐诗/poet.song.102000.json','["浄而純中無一塵，純而浄中有萬應。", "眼睛明，鼻孔正。", "更將折筯攪滄溟，令彼龍魚知水爲命。"]'),
('d77c194a-0efd-47f4-9ad6-f9346c8b28db','禪人并化主寫真求贊  其六三','釋正覺','宋','宋诗','song-poetry','','[]','瀛涵崧鎮，深兮高兮。',53,'全唐诗/poet.song.102000.json','["瀛涵崧鎮，深兮高兮。", "默默之得，類之不齊。", "一鼻直，兩眉低。", "影像爾能半露，語言誰得全提。", "少林九年兮，癡坐凄凄。"]'),
('c0305bf2-db4c-4bdf-b64a-48da06d1345f','禪人并化主寫真求贊  其六四','釋正覺','宋','宋诗','song-poetry','','[]','白髮星星，骨癯氣清。',52,'全唐诗/poet.song.102000.json','["白髮星星，骨癯氣清。", "雪浸山嵂屼，秋在水渟泓。", "流琥珀兮澗松老，射珊瑚而波月明。", "影落大千去也，何妨觸處崢嶸。"]'),
('e0a26a67-eb80-44d6-ab07-80c57ddd330b','禪人并化主寫真求贊  其六五','釋正覺','宋','宋诗','song-poetry','','[]','月犀得暈，霧豹養文。',48,'全唐诗/poet.song.102000.json','["月犀得暈，霧豹養文。", "有通有變，或合或分。", "夜寒河濯斗，山潤石生雲。", "妙湛體前明歷歷，從交天下樂忻忻。"]'),
('c1836b15-181d-488d-9390-eaa66f861291','禪人并化主寫真求贊  其六六','釋正覺','宋','宋诗','song-poetry','','[]','不寒不枯而秋頹，不浄不垢而春來。',88,'全唐诗/poet.song.102000.json','["不寒不枯而秋頹，不浄不垢而春來。", "神虛而應，機發而回。", "分身慈氏，合掌善財。", "彈指作聲兮樓閣門開。", "身心清恬，面目冷嚴。", "煙巢寒翠棲鳥夢，風漪綠浄遊魚潛。", "蕩蕩兮眺聽自妙，閒閒兮聲色不黏。"]'),
('d5ac86db-97d4-4769-817a-51d00bddff18','禪人并化主寫真求贊  其六七','釋正覺','宋','宋诗','song-poetry','','[]','看看，氣味歷艱難。',53,'全唐诗/poet.song.102000.json','["看看，氣味歷艱難。", "百城心膽老，三篾肚皮寬。", "秋晚長河淡，霜清北斗寒。", "哆哆和和兮休嫌冷語，點點閃閃兮定遭熱謾。"]'),
('1babae48-92ef-4f50-b0e3-bbf5662978a7','禪人并化主寫真求贊  其六八','釋正覺','宋','宋诗','song-poetry','','[]','霜縑寫病姿，寒木得春遲。',62,'全唐诗/poet.song.102000.json','["霜縑寫病姿，寒木得春遲。", "山居自肯束三篾，塵立每煩顰兩眉。", "牛頭不懶，虎頭不癡，箇事十成還自知。", "飯塞饑腸衣補破，不妨唧溜出家兒。"]'),
('b37fc688-bd46-45ba-ada9-ab1fb8e64bd3','禪人并化主寫真求贊  其六九','釋正覺','宋','宋诗','song-poetry','','[]','癯山早寒，老木先槁。',52,'全唐诗/poet.song.102000.json','["癯山早寒，老木先槁。", "心潛三界空，念動一塵眇。", "太虛誰與增添，萬像何曾欠少。", "止猶谷神唯自知，肯把閒身相攪擾。"]'),
('b6844fca-b4af-40e9-ab4a-ffa922b0322b','禪人并化主寫真求贊  其七○','釋正覺','宋','宋诗','song-poetry','','[]','無像而像，有許模樣。',50,'全唐诗/poet.song.102000.json','["無像而像，有許模樣。", "不真而真，只箇形神。", "豁清也千巖萬壑而秋，光麗也諸塵百草而春。", "恁麽來兮，處處相親。"]'),
('173a0f7c-846e-4fc0-a211-28cdaf9df3d4','禪人并化主寫真求贊  其七一','釋正覺','宋','宋诗','song-poetry','','[]','默默而知，靈靈者誰。',49,'全唐诗/poet.song.102000.json','["默默而知，靈靈者誰。", "無像而獨存鼻孔，有句處不挂唇皮。", "夜冷星河闊，霜清斗柄垂。", "從緣應世也，恰恰相隨。"]'),
('8583a299-a116-4f04-9e79-905c509b8c0b','禪人并化主寫真求贊  其七二','釋正覺','宋','宋诗','song-poetry','','[]','山林眉目，水月身心。',46,'全唐诗/poet.song.102000.json','["山林眉目，水月身心。", "雪何早而古巖稜，秋似先而寒潭深。", "機頭錦緒，線尾金針。", "誰云道大兮自有知音。"]'),
('4944feb3-9a73-464b-bbb7-c736a5904cc6','禪人并化主寫真求贊  其七三','釋正覺','宋','宋诗','song-poetry','','[]','神靜氣清，心空眼明。',54,'全唐诗/poet.song.102000.json','["神靜氣清，心空眼明。", "諸塵中豁落，萬像裏崢嶸。", "去而隨，來而迎。", "三世豎，十方橫。", "風吹便倒須相信，恰恰誰曾與物爭。"]'),
('9043c34a-588f-4cf5-92f5-83f017feef99','禪人并化主寫真求贊  其七四','釋正覺','宋','宋诗','song-poetry','','[]','鬚髮衰白，雪點寒林。',50,'全唐诗/poet.song.102000.json','["鬚髮衰白，雪點寒林。", "眉目冷青，秋生古澗。", "應之有餘，用之何限。", "風浪不管兮閑似浮鷗，水天相連兮遠隨歸雁。"]'),
('7c28742a-b12b-444f-b856-cd5b7ec3beb9','禪人并化主寫真求贊  其七五','釋正覺','宋','宋诗','song-poetry','','[]','拙口默默，閒身寥寥。',45,'全唐诗/poet.song.102000.json','["拙口默默，閒身寥寥。", "去住妙提其印，死生誰與同條。", "捋鬚黄檗，奪杖芭蕉。", "十方三世兮，一句全超。"]'),
('e044e93a-8cc1-466b-9d57-83bbd5b3060e','禪人并化主寫真求贊  其七六','釋正覺','宋','宋诗','song-poetry','','[]','傳之失真，體之而神。',44,'全唐诗/poet.song.102000.json','["傳之失真，體之而神。", "明白智圓而有照，清虛理極而無身。", "心萌法法，影落塵塵，一段精光華上春。"]'),
('f84eb47b-3048-4127-89ab-ccba57260c65','禪人并化主寫真求贊  其七七','釋正覺','宋','宋诗','song-poetry','','[]','是真是假，誰相描畫。',105,'全唐诗/poet.song.102000.json','["是真是假，誰相描畫。", "似我似誰，莫入思惟。", "地方成矩，天圓自規。", "三界更無些法剩，一身還與十方宜。", "眉目炯炯，鬚髮蒼蒼。", "疏林霑野雪，古澗湛秋光。", "錦縫誰分梭路細，針關初透線芒長。", "鶴夢未曉，鳥行無章。", "平買平賣兮，還他當行。"]'),
('53d27cbc-ac84-407c-aa1f-becb108e3225','禪人并化主寫真求贊  其七八','釋正覺','宋','宋诗','song-poetry','','[]','深默而耀，至虛而靈。',62,'全唐诗/poet.song.102000.json','["深默而耀，至虛而靈。", "我亡黑白，誰爲丹青。", "一點落機紐，萬緣分化形。", "月下水而明潔，雲出岫而輕盈。", "善應無方果如此，這回隨處立門庭。"]'),
('2a79001d-8eb7-4766-aa33-b56c0bf839f7','禪人并化主寫真求贊  其七九','釋正覺','宋','宋诗','song-poetry','','[]','兀兀之姿，拙鈍之師。',61,'全唐诗/poet.song.102000.json','["兀兀之姿，拙鈍之師。", "靜而亡像，動不知時。", "有口要挂壁，無機不度絲。", "秋氣清而星河淡淡，天宇闊而夜斗垂垂。", "是箇面目兮，與你相隨。"]'),
('be856b82-3d31-4390-9873-d48a5632bc6c','禪人并化主寫真求贊  其八○','釋正覺','宋','宋诗','song-poetry','','[]','氣清山秋，用光月浮。',44,'全唐诗/poet.song.102000.json','["氣清山秋，用光月浮。", "一無所寄，六不得收。", "任騰騰而異類，活鱍鱍而隨流。", "天上天下，雲水自由。"]'),
('a25e1601-b9ed-43c5-9560-1ac8c52f625a','禪人并化主寫真求贊  其八一','釋正覺','宋','宋诗','song-poetry','','[]','孤身雲閒，老髮雪白。',50,'全唐诗/poet.song.102000.json','["孤身雲閒，老髮雪白。", "叢林眼孔清，河漢口門窄。", "應時誰外諸緣，轉處自消一色。", "崢嶸萬像森羅，向道與他平出。"]'),
('7cc1289d-feca-4b74-a337-4042c72b058b','禪人并化主寫真求贊  其八二','釋正覺','宋','宋诗','song-poetry','','[]','赤肉鑿竅，乾骨裹皮。',80,'全唐诗/poet.song.102000.json','["赤肉鑿竅，乾骨裹皮。", "自然無我，你道是誰。", "雙瞳秋點點，兩鬢雪絲絲。", "筇倚床頭不去諸方行脚，口挂壁上欲學古人住持。", "淵默有句，真得無師。", "崖蜂春採薝蔔華，海鳥夢卧珊瑚枝。"]'),
('354d337c-b670-4dbb-8c68-43928fd25956','禪人并化主寫真求贊  其八三','釋正覺','宋','宋诗','song-poetry','','[]','歲寒之姿，衰髮絲絲。',58,'全唐诗/poet.song.102000.json','["歲寒之姿，衰髮絲絲。", "明白之傳，湛存綿綿。", "秋空霽而天連水遠，夜色冷而河橫斗旋。", "平買平賣兮將高就下，中規中矩兮隨方逐圓。"]'),
('4cf4a21a-f17b-4fa8-b6cb-d0c3bb40039e','禪人并化主寫真求贊  其八四','釋正覺','宋','宋诗','song-poetry','','[]','像兮非真，真兮非像。',56,'全唐诗/poet.song.102000.json','["像兮非真，真兮非像。", "妙明四大之前，自出諸緣之上。", "不把一字之心傳，有吞百川之器量。", "隨方普應而不虧，的的夜光而在掌。"]'),
('dfd6a7d4-2b00-4992-97f3-67d00682f72c','禪人并化主寫真求贊  其八五','釋正覺','宋','宋诗','song-poetry','','[]','默默家風，如如規矩。',44,'全唐诗/poet.song.102000.json','["默默家風，如如規矩。", "妙不可以言傳，真不可以相取。", "明白月壺，廓清天宇。", "物我情忘兮誰分爾汝。"]'),
('6301e458-c23f-475b-ab4e-a4b8664c985e','禪人并化主寫真求贊  其八六','釋正覺','宋','宋诗','song-poetry','','[]','智須轉色，浄還發光。',42,'全唐诗/poet.song.102000.json','["智須轉色，浄還發光。", "活眼唯自照，喜眉爲誰揚。", "巍巍堂堂，煒煒煌煌，莫道儂家兮觸事面牆。"]'),
('62eedbeb-e434-4649-8b49-9167a95fd5c8','禪人并化主寫真求贊  其八七','釋正覺','宋','宋诗','song-poetry','','[]','浄智而昭昭，體空而寥寥。',58,'全唐诗/poet.song.102000.json','["浄智而昭昭，體空而寥寥。", "天心河淡月欲下，松頂雪寒春未消。", "三世遷流兮彈指可斷，萬年長久兮一念全超。", "恁麽來也，順風上潮。"]'),
('b2e868e1-0a2e-493d-b2b0-18b736fe2374','禪人并化主寫真求贊  其八八','釋正覺','宋','宋诗','song-poetry','','[]','山之寒兮带雪，水之清兮含月。',42,'全唐诗/poet.song.102000.json','["山之寒兮带雪，水之清兮含月。", "默而靈兮卓卓妙存，靜而應兮塵塵光發，徹見離微兮任出任沒。"]'),
('ce98dc2a-39f6-4c84-81db-50286e29ac76','禪人并化主寫真求贊  其八九','釋正覺','宋','宋诗','song-poetry','','[]','赤肉一團，疏通數竅。',60,'全唐诗/poet.song.102000.json','["赤肉一團，疏通數竅。", "惟色惟聲，乃聽乃眺。", "不借應而即真，不外虛而常照。", "長時默坐亡世機，萬里青天絕飛鳥。", "謂爾畫工，那得其妙。"]'),
('47f8226c-5bd1-4d07-8988-bbc06834910d','禪人并化主寫真求贊  其九○','釋正覺','宋','宋诗','song-poetry','','[]','心得而真，物應而神。',52,'全唐诗/poet.song.102000.json','["心得而真，物應而神。", "幻住三昧，覺了諸塵。", "灑灑落落不共法，浩浩蕩蕩無邊身。", "明明白白隨流月，葉葉華華到處春。"]'),
('212e6325-9337-44c5-997e-0fd3ea4560ce','禪人并化主寫真求贊  其九一','釋正覺','宋','宋诗','song-poetry','','[]','情謂之外兮言路那通，形殻之外兮模畫那同。',62,'全唐诗/poet.song.102000.json','["情謂之外兮言路那通，形殻之外兮模畫那同。", "一方明有月，萬簌嘯而風。", "其應而妙，其用而沖。", "圖星之拱兮周羅而北，流水之向兮曲折而東。"]'),
('552ca626-aee8-4a7b-b9c1-4beb5d4c9123','禪人并化主寫真求贊  其九二','釋正覺','宋','宋诗','song-poetry','','[]','木石形骸，冰雪肝膽。',72,'全唐诗/poet.song.102000.json','["木石形骸，冰雪肝膽。", "一點妙難名，十方機未感。", "寒林摇落兮誰捋老虎之鬚，滄海潮乾兮誰探老驪之頷。", "默默湛存，昭昭元鑒。", "發用也連乾斷坤，緣應也明離暗坎。"]'),
('58ccc84e-66e8-4ba7-8853-ce51419503e3','禪人并化主寫真求贊  其九三','釋正覺','宋','宋诗','song-poetry','','[]','寒箸蒼山之骨，雪壓老松之顛。',88,'全唐诗/poet.song.102000.json','["寒箸蒼山之骨，雪壓老松之顛。", "形氣清而有像，心跡泯而亡緣。", "諸塵不受，一印周旋。", "大大小小兮方方圓圓。", "神觀湛湛，和氣津津。", "玉澗流月，瓊林發春。", "恰恰相融也何此何彼，堂堂不在也奪境奪人。"]'),
('01eff200-d84c-41a2-82e1-09b21b1c4d44','禪人并化主寫真求贊  其九四','釋正覺','宋','宋诗','song-poetry','','[]','心空月高，髮白雪饒。',68,'全唐诗/poet.song.102000.json','["心空月高，髮白雪饒。", "氣吞百川兮其口如海，浪卷萬里兮其舌翻潮。", "一句直指，三乘獨超。", "忽雷破蟄起平地，赤脚踏虹登九霄。", "影草笑無術，爛柯知有樵。"]'),
('63993f2c-079e-41aa-b7b3-fdfba7a14134','禪人并化主寫真求贊  其九五','釋正覺','宋','宋诗','song-poetry','','[]','眉目十分，精神一段。',50,'全唐诗/poet.song.102000.json','["眉目十分，精神一段。", "巖高雪釋遲，木老春來緩。", "古澗明月賓，青山白雲伴。", "借光何處不分身，剎剎塵塵誰解喚。"]'),
('2c27f04a-90c5-4fba-8023-654a287c55b9','禪人并化主寫真求贊  其九六','釋正覺','宋','宋诗','song-poetry','','[]','默默有得，靈靈無依。',50,'全唐诗/poet.song.102000.json','["默默有得，靈靈無依。", "妙窮出沒，照徹離微。", "萬像齊收一印，三昧遍在羣機。", "而今恁麽相隨去，終日如愚不我違。"]'),
('6d5c2654-1a8e-438b-9d5f-4a0810aa3684','禪人并化主寫真求贊  其九七','釋正覺','宋','宋诗','song-poetry','','[]','肅蕭而秋，萬化潛收。',36,'全唐诗/poet.song.102000.json','["肅蕭而秋，萬化潛收。", "英英而春，羣彙舒伸。", "天地之間誰造物，樞機之發是何人。"]'),
('b1bd4c04-c0f6-4b82-aea4-e4beb5898b4e','禪人并化主寫真求贊  其九八','釋正覺','宋','宋诗','song-poetry','','[]','八字眉低，四方口闊。',66,'全唐诗/poet.song.102000.json','["八字眉低，四方口闊。", "髮色松雪寒，目光巖電爍。", "橐籥之空，樞機之活。", "其間勿你安排，裏許是誰造作。", "影草不彰兮妙觸無瘢，沒身不殆兮長生有藥。"]'),
('414e2291-eab6-4afa-be2a-772c10937f27','禪人并化主寫真求贊  其九九','釋正覺','宋','宋诗','song-poetry','','[]','凄然而秋，眼冷心休。',54,'全唐诗/poet.song.102000.json','["凄然而秋，眼冷心休。", "溫然而春，口笑眉伸。", "了了無分別智，恢恢不思議仁。", "亡機返朴，得用還淳。", "圖畫之巧，那有其神。"]'),
('1855607a-58f6-4e63-b99b-fe6ab4d44082','禪人并化主寫真求贊  其一○○','釋正覺','宋','宋诗','song-poetry','','[]','秋入眼角，春生鼻筒。',54,'全唐诗/poet.song.102000.json','["秋入眼角，春生鼻筒。", "鉗鎚堅外，橐籥虛中。", "世機抱甕之拙，道用斲輪之工。", "蜂採華房兮蠟脾釀蜜，犀酣桂轂兮兔鼻流通。"]'),
('01ae6cdb-1285-47f4-b117-49ad5ddedacf','禪人并化主寫真求贊  其一○一','釋正覺','宋','宋诗','song-poetry','','[]','萎萎羸羸，跛跛挈挈。',59,'全唐诗/poet.song.102000.json','["萎萎羸羸，跛跛挈挈。", "用綿綿而雲行，機歷歷而電掣。", "有時緘口銜枚，也學住山束篾。", "生兮不生，滅兮不滅。", "秋水之月兮，春山之雪。"]'),
('9978148d-63b0-4186-98af-c3914f2d510d','禪人并化主寫真求贊  其一○二','釋正覺','宋','宋诗','song-poetry','','[]','身心自然，松石亡年。',42,'全唐诗/poet.song.102000.json','["身心自然，松石亡年。", "春雲閒似鶴，秋水遠連天。", "虛能外應，默守家傳。", "東西南北，一等周旋。"]'),
('d43c4324-ecc0-43d7-9223-569dca1831f1','禪人并化主寫真求贊  其一○三','釋正覺','宋','宋诗','song-poetry','','[]','赤肉一塊，臭膿一袋。',47,'全唐诗/poet.song.102000.json','["赤肉一塊，臭膿一袋。", "何物著乎中，有應發於外。", "妙入羣機兮成三昧，箇時撒手斷崖前，方見渾侖撲不碎。"]'),
('3125c1cf-0fa5-4f85-93ca-1acb3ed81e14','禪人并化主寫真求贊  其一○四','釋正覺','宋','宋诗','song-poetry','','[]','教示無轍迹，贊之絕涯岸。',50,'全唐诗/poet.song.102000.json','["教示無轍迹，贊之絕涯岸。", "纔發名言，便成形段。", "月蘆混處鳴鷗，天水連時沒雁。", "而今對現十成，向道只得一半。"]'),
('2f5594f1-207c-4784-927c-b83923eda565','禪人并化主寫真求贊  其一○五','釋正覺','宋','宋诗','song-poetry','','[]','清白而遊，江湖風月之秋。',54,'全唐诗/poet.song.102000.json','["清白而遊，江湖風月之秋。", "變態而神，雲煙草木之春。", "體之而真，用之而淳。", "非佛非祖而能佛能祖，非天非人而能天能人。"]'),
('f76f092d-dffe-43a5-88ed-dbd207d0c8f1','禪人并化主寫真求贊  其一○六','釋正覺','宋','宋诗','song-poetry','','[]','四大無埃，五藴外來。',66,'全唐诗/poet.song.102000.json','["四大無埃，五藴外來。", "智慧尚歸父，因緣初不媒。", "西山寒月下，東海夜潮回。", "一一根塵妙觸事，千千手眼隨宜開。", "衆生世界了如幻，影像那涴吾靈臺。"]'),
('77167686-6819-4e1a-a1c3-30ad01dd378a','禪人并化主寫真求贊  其一○七','釋正覺','宋','宋诗','song-poetry','','[]','看看，心空骨寒槁木暖，未發髑髏津瀝乾。',45,'全唐诗/poet.song.102000.json','["看看，心空骨寒槁木暖，未發髑髏津瀝乾。", "秋入眼角，春生鼻端。", "相呼相喚知音會，爲我門前倒剎竿。"]'),
('0c6f949e-9bb8-4c05-9950-006a98bfc595','禪人并化主寫真求贊  其一○八','釋正覺','宋','宋诗','song-poetry','','[]','箇是何人，氣清骨貧。',50,'全唐诗/poet.song.102000.json','["箇是何人，氣清骨貧。", "煙霞面目，丘壑精神。", "二儀自然一體，萬像況與同塵。", "床上全威白額虎，鈎頭可意赤稍鱗。"]'),
('e4210e98-2120-4284-99d7-fb29db8b80eb','禪人并化主寫真求贊  其一○九','釋正覺','宋','宋诗','song-poetry','','[]','你是何人，緇衣裹身。',56,'全唐诗/poet.song.102000.json','["你是何人，緇衣裹身。", "靜住天無四壁，機回月带重輪。", "夢蝶境中閒有趣，露蟬胸次浄無塵。", "相隨化事入廛井，百草頭上風煙春。"]'),
('79bc858d-e2df-4af0-bed8-293f9583ce72','禪人并化主寫真求贊  其一一○','釋正覺','宋','宋诗','song-poetry','','[]','貌古而孤，氣清而癯。',46,'全唐诗/poet.song.102000.json','["貌古而孤，氣清而癯。", "秋生林壑，月在江湖。", "見道之體盈而虛，隨世之用有而無。", "佛佛祖祖，只箇規模。"]'),
('a810456c-4dd6-4b4d-a2fe-16ec88fbdcee','禪人并化主寫真求贊  其一一一','釋正覺','宋','宋诗','song-poetry','','[]','靜而純，湛而存。',48,'全唐诗/poet.song.102000.json','["靜而純，湛而存。", "海日珊瑚樹，巖松琥珀根。", "家風傳父祖，事業付兒孫。", "回途妙觸了機用，箇是百千三昧門。"]'),
('206279c8-d2ed-4672-8fca-2e174b77486a','禪人并化主寫真求贊  其一一二','釋正覺','宋','宋诗','song-poetry','','[]','寒林氣清，晚浦潮平。',48,'全唐诗/poet.song.102000.json','["寒林氣清，晚浦潮平。", "自由之像，相隨而名。", "孤藤拳脫略，三篾肚膨亨。", "鬧市誰嫌機用熟，叢林人道飽參生。"]'),
('4c02bbe9-9188-4d8c-a002-d91d757c6504','禪人并化主寫真求贊  其一一三','釋正覺','宋','宋诗','song-poetry','','[]','清白傳家，湛存授手。',48,'全唐诗/poet.song.102000.json','["清白傳家，湛存授手。", "木落風高，水明月晝。", "雙瞳冷用眉，片舌閑摇口。", "宗通也洞水逆流，孝滿也曹山顛酒。"]'),
('f5b20ca5-f04f-40be-a7d9-56407a47a00a','禪人并化主寫真求贊  其一一四','釋正覺','宋','宋诗','song-poetry','','[]','寒雪覆顛，閑雲擁肩。',66,'全唐诗/poet.song.102000.json','["寒雪覆顛，閑雲擁肩。", "動隨爾後，靜住其前。", "百草頭邊老僧句，千華臺上古佛禪。", "法法出礙，心心密傳。", "百戰之瘡兮風雨瘢痒，九野之耕兮泥水領穿。"]'),
('70eaf37a-6c89-4429-bd0d-9d3492e45c79','禪人并化主寫真求贊  其一一五','釋正覺','宋','宋诗','song-poetry','','[]','體之湛存，潮縮海門。',102,'全唐诗/poet.song.102000.json','["體之湛存，潮縮海門。", "用之亡痕，春入華根。", "光明射珊瑚之魂，波瀾派崑崙之源。", "影動非幡，聲揚度垣。", "靜以應繁，沖以待喧。", "騏驥之姿，千里之奔。", "雲夢之量，八九之吞。", "斲輪之工兮擬誰授克家之學，抱甕之朴兮將自灌丈人之園。"]'),
('f5341734-693f-4a0c-8f94-1f5912ddc33b','禪人并化主寫真求贊  其一一六','釋正覺','宋','宋诗','song-poetry','','[]','歲寒之容，高巖雪松。',58,'全唐诗/poet.song.102000.json','["歲寒之容，高巖雪松。", "清白之胸，冷月霜鐘。", "種田博飯，地藏之春農。", "明鏡非臺，黄梅之夜舂。", "百草頭上閑和尚，而今何處不相逢。"]'),
('d169cb1c-4c99-4ab0-a575-36708b07a0bb','禪人并化主寫真求贊  其一一七','釋正覺','宋','宋诗','song-poetry','','[]','本體無生，諸塵幻成。',60,'全唐诗/poet.song.102000.json','["本體無生，諸塵幻成。", "白髮雪漫頂，青瞳秋在泓。", "妙觸出礙，機用超情。", "珠走不留影，谷虛還應聲。", "默默坐寒唯自照，天無四壁月三更。"]'),
('b242453c-bf30-46e3-a2a5-073cd1f31e9a','禪人并化主寫真求贊  其一一八','釋正覺','宋','宋诗','song-poetry','','[]','神定氣平，心空智明。',62,'全唐诗/poet.song.102000.json','["神定氣平，心空智明。", "其機靜而自應，其用虛而不盈。", "寒潭月落，霽夜河橫。", "紹了亡祖位，借功成佛名。", "建立因緣皆爾爾，剎塵世界與衆生。"]'),
('d07f3bdf-18f0-44be-9302-92936c372ddf','禪人并化主寫真求贊  其一一九','釋正覺','宋','宋诗','song-poetry','','[]','蟄梭未飛，肌膚不把。',68,'全唐诗/poet.song.102000.json','["蟄梭未飛，肌膚不把。", "老虎似衰，眼力猶威。", "頭鬚霜雪塢，舌頰風雷機。", "氣爽秋高河漢闊，霽寒夜永斗牛輝。", "陰陽爻象，天地範圍。", "借伴來也，相逢庶幾。"]'),
('e5a95517-1724-4442-89a9-36cbde898900','禪人并化主寫真求贊  其一二○','釋正覺','宋','宋诗','song-poetry','','[]','二儀同根，萬物一源。',64,'全唐诗/poet.song.102000.json','["二儀同根，萬物一源。", "機活靜樞之臼，象成玄牝之門。", "幽而不昏，湛而若存。", "用妙觸而出礙，體至虛而無痕。", "車轍出門而合度，桃李成蹊而不言。"]'),
('7d8bbae6-43ea-44c9-8f0d-d65707bed650','禪人并化主寫真求贊  其一二一','釋正覺','宋','宋诗','song-poetry','','[]','枯木之春，蟠桃之辰。',62,'全唐诗/poet.song.102000.json','["枯木之春，蟠桃之辰。", "自然時節，不費精神。", "啐啄丹山之鳳窟，游躍桃華之龍津。", "一機歷歷，三昧塵塵。", "眼中之物物中眼，身裏出門門裏身。"]'),
('b635418a-55e1-4152-a324-daaa2ec13dd4','禪人并化主寫真求贊  其一二二','釋正覺','宋','宋诗','song-poetry','','[]','疏豁性情，谷虛而不盈。',32,'全唐诗/poet.song.102000.json','["疏豁性情，谷虛而不盈。", "舒散胸膚，冰渙而不凝。", "恁麽來也，觸處相應。"]'),
('f5fadb31-0b62-4833-bd21-e215f892bd08','禪人并化主寫真求贊  其一二三','釋正覺','宋','宋诗','song-poetry','','[]','錦雲晚晴，璧月夜明。',38,'全唐诗/poet.song.102000.json','["錦雲晚晴，璧月夜明。", "妙心無住住，幻事不生生。", "天際冥冥雁字沒，潮痕灧灧鯨波平。"]'),
('1cde34e6-7928-45c1-8671-4ad908374d7a','禪人并化主寫真求贊  其一二四','釋正覺','宋','宋诗','song-poetry','','[]','靜復湛存，潮退珊瑚之根。',40,'全唐诗/poet.song.102000.json','["靜復湛存，潮退珊瑚之根。", "智隨用奔，派發崑崙之源。", "光風草木獻春像，霽夜魚龍吞月魂。"]'),
('7bef07e2-87bd-40d0-b350-0be93d1bdf49','禪人并化主寫真求贊  其一二五','釋正覺','宋','宋诗','song-poetry','','[]','山向嶽奔，川趨海吞。',54,'全唐诗/poet.song.102000.json','["山向嶽奔，川趨海吞。", "船浮水柔有力，雁沒煙冷無痕。", "二三四七，傳持之句。", "百千萬億，變化之門。", "招手授手，知恩報恩。"]'),
('c7db287f-53ac-4631-86da-3b26684c017e','禪人并化主寫真求贊  其一二六','釋正覺','宋','宋诗','song-poetry','','[]','孤節老全，叢林歲寒。',70,'全唐诗/poet.song.102000.json','["孤節老全，叢林歲寒。", "機用千變，時事百難。", "玉經火而愈潤，蓮秀水而常乾。", "牛頭之懶口挂壁，麈尾之辯舌翻瀾。", "觸事出礙兮虛空揮劍，衆影不黏兮明珠走盤。"]'),
('4baa83a9-75db-4d93-a261-d03e36ef544f','禪人并化主寫真求贊  其一二七','釋正覺','宋','宋诗','song-poetry','','[]','老節疏蹤，傲雪之松。',56,'全唐诗/poet.song.102000.json','["老節疏蹤，傲雪之松。", "真智證理，吟雲之龍。", "飽叢林而彭亨肚，善知識而隗磊胸。", "春成萬物兮平等無像，海吞百川兮自然有容。"]'),
('23bc6e19-84fa-4204-ae9e-4fffb20f1227','禪人并化主寫真求贊  其一二八','釋正覺','宋','宋诗','song-poetry','','[]','智靜用沖，道明體空。',56,'全唐诗/poet.song.102000.json','["智靜用沖，道明體空。", "清白轉色，幽微借功。", "一乘句裏那回互，百草頭上還疏通。", "虎頭之顧，牛頭之融。", "且癡且懶，不謀而同。"]'),
('e7a4ee9f-71b4-4d43-a5cf-161e99ffb0f5','禪人并化主寫真求贊  其一二九','釋正覺','宋','宋诗','song-poetry','','[]','江湖之秋，清入雙眸。',46,'全唐诗/poet.song.102000.json','["江湖之秋，清入雙眸。", "草木之春，溫生兩唇。", "髑髏眉底自照眼，赤肉團上無位人。", "門門得用，薄藝隨身。"]'),
('c8788aff-8100-46d5-b717-55c39455fce0','禪人并化主寫真求贊  其一三○','釋正覺','宋','宋诗','song-poetry','','[]','觀身因緣，芭蕉不堅。',52,'全唐诗/poet.song.102000.json','["觀身因緣，芭蕉不堅。", "悟世幻化，木槿之謝。", "舒叢林之氣兮時節長春，分密室之燈兮光明不夜。", "應物現形，見聞閑暇。"]'),
('524afefd-bf4b-4655-9c69-121ca0c6e7e3','禪人并化主寫真求贊  其一三一','釋正覺','宋','宋诗','song-poetry','','[]','節稜稜而老松之孤，心空空兮脩竹之癯。',50,'全唐诗/poet.song.102000.json','["節稜稜而老松之孤，心空空兮脩竹之癯。", "雪霜之氣，丘壑之軀。", "雲水之去就，叢林之典模。", "放開來底，相識也無。"]'),
('9c26d2f6-0392-4f9e-9bca-e51208f39715','禪人并化主寫真求贊  其一三二','釋正覺','宋','宋诗','song-poetry','','[]','餘雲消於霽虛，片月上於秋壺。',60,'全唐诗/poet.song.102000.json','["餘雲消於霽虛，片月上於秋壺。", "光清岩壑，影現江湖。", "類中之異，物中之珠。", "虎生三日食牛氣，馬走千里隨母駒。", "賞音有以，德隣不孤。"]'),
('8bba6a00-b6ed-438c-bb01-630a78a9d914','禪人并化主寫真求贊  其一三三','釋正覺','宋','宋诗','song-poetry','','[]','虛空之身兮遍十方，古佛之心兮踰三光。',58,'全唐诗/poet.song.102000.json','["虛空之身兮遍十方，古佛之心兮踰三光。", "得之而藏，兀然如秋兮百念自凉。", "用之而芳，粲然如春兮萬像成章。", "德形外徼，道在中央。"]'),
('71a8f8dc-422a-4576-932e-126be210d575','禪人并化主寫真求贊  其一三四','釋正覺','宋','宋诗','song-poetry','','[]','剎剎塵塵，隨應現身。',46,'全唐诗/poet.song.102000.json','["剎剎塵塵，隨應現身。", "百川之月，百華之春。", "阿你隨宜手眼快，更誰敢議骨頭貧。", "道交德隣，主主賓賓。"]'),
('1e37f2a8-0f98-4cb4-b02b-99bef5d4f243','禪人并化主寫真求贊  其一三五','釋正覺','宋','宋诗','song-poetry','','[]','三世混融，據本來而合同。',56,'全唐诗/poet.song.102000.json','["三世混融，據本來而合同。", "六門變通，在今日而亡功。", "下錢胡餅案，放手饅頭籠。", "南山起雲兮北山下雨，古佛露柱兮互換家風。"]'),
('1f2b2ea1-e0c7-4cb7-84d5-c14a332ddee8','禪人并化主寫真求贊  其一三六','釋正覺','宋','宋诗','song-poetry','','[]','寒雪一顛，秋雲半肩。',48,'全唐诗/poet.song.102000.json','["寒雪一顛，秋雲半肩。", "淵默曲木，月行霽天。", "轉功能就位，借伴還入廛。", "機用也離虛坎實，變通也坤斷乾連。"]'),
('19c637b5-ad50-4f6c-b00a-9c29bc67828b','禪人并化主寫真求贊  其一三七','釋正覺','宋','宋诗','song-poetry','','[]','無明而明，無生而生。',36,'全唐诗/poet.song.102000.json','["無明而明，無生而生。", "靜樞機活，玄牝象成。", "隨緣百億縱橫用，妙觸門門出礙情。"]'),
('d669e57a-c948-4288-b3bb-6a21b72ff6d0','禪人并化主寫真求贊  其一三八','釋正覺','宋','宋诗','song-poetry','','[]','從身出門，即物契神。',36,'全唐诗/poet.song.102000.json','["從身出門，即物契神。", "一機歷歷，三昧塵塵。", "逢場且了遊戲事，向道非無幻化人。"]'),
('4037daa7-46d9-4a3c-a5c6-51518931b18a','禪人并化主寫真求贊  其一三九','釋正覺','宋','宋诗','song-poetry','','[]','心空觀身，眼冷對塵。',50,'全唐诗/poet.song.102000.json','["心空觀身，眼冷對塵。", "本來無物，幻起成春。", "動若行雲而應，止猶虛谷而神。", "門門隨事得三昧，機用縱橫不倩人。"]'),
('37290344-cd71-4866-831f-ab0dbc58c149','禪人并化主寫真求贊  其一四○','釋正覺','宋','宋诗','song-poetry','','[]','秋山癯而清，秋水瘦而浄。',40,'全唐诗/poet.song.102000.json','["秋山癯而清，秋水瘦而浄。", "萬法自齊觀，一音還普應。", "方圓之器著虛空，隨來隨與無餘剩。"]'),
('e3ef1636-0e1e-4dbb-b54a-d33d211a7d77','禪人并化主寫真求贊  其一四一','釋正覺','宋','宋诗','song-poetry','','[]','寒巖著雪，老木含春。',52,'全唐诗/poet.song.102000.json','["寒巖著雪，老木含春。", "獨靈空劫眼，不礙肉團身。", "枯禪三椽兮自守其默，豁浄四壁兮誰管其貧，森羅萬像兮根根塵塵。"]'),
('a27439a0-ed60-4db8-a324-024f1ce9cb8a','禪人并化主寫真求贊  其一四二','釋正覺','宋','宋诗','song-poetry','','[]','山秋而癯，水秋而浄。',52,'全唐诗/poet.song.102000.json','["山秋而癯，水秋而浄。", "得丘壑偃蹇之姿，賦猿鳥超摇之性。", "離微徹見根，動靜該聽瑩。", "提來萬法上看，更沒一絲頭剩。"]'),
('aab7e682-2b75-419f-8e24-92cd55ec4784','禪人并化主寫真求贊  其一四三','釋正覺','宋','宋诗','song-poetry','','[]','性不疏通，機不捷敏。',42,'全唐诗/poet.song.102000.json','["性不疏通，機不捷敏。", "頹慵陋見聞，急快失容忍。", "一默清秋兮芙蓉華開，萬態浩春兮葛藤蔓引。"]'),
('caab6780-5286-4a7d-a947-86b770488edd','禪人并化主寫真求贊  其一四四','釋正覺','宋','宋诗','song-poetry','','[]','鬚髮滄浪，形容寒瘠。',46,'全唐诗/poet.song.102000.json','["鬚髮滄浪，形容寒瘠。", "春林带雪痕，雲山染秋色。", "光明一點兮蚌有藴於月華，清浄八絃兮鳥不飛而天碧。"]'),
('92903e97-71c9-4201-bdc8-2f4b3525b8ef','禪人并化主寫真求贊  其一四五','釋正覺','宋','宋诗','song-poetry','','[]','其來何從，雲起孤峰。',52,'全唐诗/poet.song.102000.json','["其來何從，雲起孤峰。", "其去何詣，月落寒水。", "而今處處相隨行，的的渾身是眼睛。", "萬像森羅互爲用，不許蠅泥黏鼻孔。"]'),
('a84e4d36-b752-44f6-8c87-469bb07fb829','禪人并化主寫真求贊  其一四六','釋正覺','宋','宋诗','song-poetry','','[]','如珪如璧，雕文喪德。',47,'全唐诗/poet.song.102000.json','["如珪如璧，雕文喪德。", "如雲如石，堅潤是式。", "蒼竹無心歲寒色，老松有傲霜雪力。", "照破諸緣兮，兩眼如漆。"]'),
('bbe5561c-2308-4602-a6b3-d0d4ef18e58c','禪人并化主寫真求贊  其一四七','釋正覺','宋','宋诗','song-poetry','','[]','氣宇豁落，精神蕭散。',50,'全唐诗/poet.song.102000.json','["氣宇豁落，精神蕭散。", "塵劫坐空，世緣居簡。", "閒閒淡淡枯木雲，瀝瀝漉漉通身眼。", "森羅萬像同條，莫道箇人檐板。"]'),
('64540700-0786-4cc6-b5f4-bb3542cfdf46','禪人并化主寫真求贊  其一四八','釋正覺','宋','宋诗','song-poetry','','[]','山寒露風稜，水瘦褪沙痕。',38,'全唐诗/poet.song.102000.json','["山寒露風稜，水瘦褪沙痕。", "劫空須到底，用妙不循根。", "宗派誰傳衣鉢，他家自有兒孫。"]'),
('cf183b4e-adf7-4d02-b8ec-931c5d942309','禪人并化主寫真求贊  其一四九','釋正覺','宋','宋诗','song-poetry','','[]','清若松篁雪，虛明河漢秋。',28,'全唐诗/poet.song.102000.json','["清若松篁雪，虛明河漢秋。", "深心老節歲寒事，穩放胡床默默遊。"]'),
('5d37869b-cff5-4364-9256-0543eef48549','禪人并化主寫真求贊  其一五○','釋正覺','宋','宋诗','song-poetry','','[]','寒山骨瘦，雪林氣清。',48,'全唐诗/poet.song.102000.json','["寒山骨瘦，雪林氣清。", "萬機寖削，一點光明。", "其靈不可像，其妙不可名。", "默倚蒲團坐終日，你道何時不太平。"]'),
('7833f744-fb0e-4369-8caf-bfb5d3b6f373','禪人并化主寫真求贊  其一五一','釋正覺','宋','宋诗','song-poetry','','[]','一片閒心，十方充塞。',58,'全唐诗/poet.song.102000.json','["一片閒心，十方充塞。", "春律行兮發華，秋風歛兮落木。", "誰調誰牧，不傷不觸。", "萬像同放光明，太虛了無稜骨。", "中規矩兮，東西南北。"]'),
('43008001-f281-4406-9822-fa9b53b5b00c','禪人并化主寫真求贊  其一五二','釋正覺','宋','宋诗','song-poetry','','[]','眉目古澗秋，鬚髮寒巖雪。',52,'全唐诗/poet.song.102000.json','["眉目古澗秋，鬚髮寒巖雪。", "去就叢林出身，觸動葛藤生舌。", "揚拂握拳，破關擊節。", "霧變豹而草木光，雷趁蛟而山石裂。"]'),
('ee30d634-4ad4-4b4a-a0fe-f7c226785a7a','禪人并化主寫真求贊  其一五三','釋正覺','宋','宋诗','song-poetry','','[]','輕重之衡，妍媸之鑒。',64,'全唐诗/poet.song.102000.json','["輕重之衡，妍媸之鑒。", "堂堂類而莫齊，的的混而不濫。", "身世閑閑，情田淡淡。", "秋水澄澄，江鷗泛泛。", "一點徹底兮叢林淵源，萬化夤緣兮葛藤枝蔓。"]'),
('e44db142-a50b-4e04-8ade-5474ac26e791','禪人并化主寫真求贊  其一五四','釋正覺','宋','宋诗','song-poetry','','[]','視物眼深，說禪口快。',50,'全唐诗/poet.song.102000.json','["視物眼深，說禪口快。", "一點不著虛空，萬化誰分器界。", "應衆緣而閒六根，入諸塵而住三昧。", "其小無內，其大無外。"]'),
('e7cb2f98-7443-4af9-9b2c-ead95457d104','禪人并化主寫真求贊  其一五五','釋正覺','宋','宋诗','song-poetry','','[]','木老春何晚，山寒秋最先。',50,'全唐诗/poet.song.102000.json','["木老春何晚，山寒秋最先。", "淵默有佳處，湛存天地前。", "靜亡所住，動解隨緣。", "黄蘆淮上東西岸，明月渡頭南北船。"]'),
('e6c6f07f-91f0-4681-9a26-3e65db2d2baf','禪人并化主寫真求贊  其一五六','釋正覺','宋','宋诗','song-poetry','','[]','癯而且老，寒木未春。',56,'全唐诗/poet.song.102000.json','["癯而且老，寒木未春。", "靜而愈明，古潭有月。", "天蒼蒼而無空無缺，雲閑閑而乍出乍沒。", "二儀同根，萬物一體，莫向諸緣分彼此。"]'),
('ac190855-205e-4b94-a14c-6f0393d7efdc','禪人并化主寫真求贊  其一五七','釋正覺','宋','宋诗','song-poetry','','[]','眼深眉長，口闊面黄。',54,'全唐诗/poet.song.102000.json','["眼深眉長，口闊面黄。", "秋月破夜色，古澗含秋光。", "念萌自得出沒像，功轉不落偏正方。", "拈起能來應機用，者回觸處露堂堂。"]'),
('fb444c21-0179-43da-862a-0fece2a0b48f','禪人并化主寫真求贊  其一五八','釋正覺','宋','宋诗','song-poetry','','[]','默而不凝，照而不流。',52,'全唐诗/poet.song.102000.json','["默而不凝，照而不流。", "關捩虛而活，機輪轉處幽。", "閑雲淡而無雨，野水清而有秋。", "要將平等一如相，著在森羅萬像頭。"]'),
('ddfecb82-b95a-4c07-8474-e1274b12cc8e','禪人并化主寫真求贊  其一五九','釋正覺','宋','宋诗','song-poetry','','[]','山肥擁雲，水明濯月。',48,'全唐诗/poet.song.102000.json','["山肥擁雲，水明濯月。", "動隨偏正往來，靜見離微出沒。", "得萬像之根源，識諸緣之窠窟。", "相隨來也，不遺毫忽。"]'),
('d2677d21-df72-44a5-b4c5-2eed0eb05839','禪人并化主寫真求贊  其一六○','釋正覺','宋','宋诗','song-poetry','','[]','額高聳骨，眼深藏神。',50,'全唐诗/poet.song.102000.json','["額高聳骨，眼深藏神。", "諸緣㳷合，一默真醇。", "自得混成物我，誰能碎折根塵。", "不來而來不見見，會有知音彼上人。"]'),
('63d54d3b-a8ad-4e86-92cc-0e6e3b3452e4','禪人并化主寫真求贊  其一六一','釋正覺','宋','宋诗','song-poetry','','[]','白髮半山雪，青瞳兩眼秋。',40,'全唐诗/poet.song.102000.json','["白髮半山雪，青瞳兩眼秋。", "的的環中意，綿綿方外遊。", "虛空說法何須口，萬像森羅自點頭。"]'),
('e09f5b10-791a-4d37-9050-bff99554e4fd','禪人并化主寫真求贊  其一六二','釋正覺','宋','宋诗','song-poetry','','[]','默默而遊，如如而說。',33,'全唐诗/poet.song.102000.json','["默默而遊，如如而說。", "魚行澗底秋，鶴夢松頭月。", "大智而愚兮，大巧而拙。"]'),
('477dfc91-bde0-44fc-a21b-65349f24d731','禪人并化主寫真求贊  其一六三','釋正覺','宋','宋诗','song-poetry','','[]','顛毛如許白，面孔較些肥。',51,'全唐诗/poet.song.102000.json','["顛毛如許白，面孔較些肥。", "寒松偃蹇兮雪在頂，枯山癯瘠兮春添衣。", "據床握杖，雷吼電飛。", "光痕已露也，是誰見幾。"]'),
('8be493d7-deaf-4265-9296-34cae4c59720','禪人并化主寫真求贊  其一六四','釋正覺','宋','宋诗','song-poetry','','[]','鬚髮老白，眉目窮愁。',43,'全唐诗/poet.song.102000.json','["鬚髮老白，眉目窮愁。", "六窗寒照雪，一點冷摩秋。", "乾處著脚，鬧裏刺頭。", "樞靜機活兮，全放全收。"]'),
('0d24fdff-0561-4ab2-b0ce-fe584e5f5a85','禪人并化主寫真求贊  其一六五','釋正覺','宋','宋诗','song-poetry','','[]','鼻似截筒長，目如點漆光。',50,'全唐诗/poet.song.102000.json','["鼻似截筒長，目如點漆光。", "據床握拄杖，河漢夜來霜。", "雲山蒼蒼，水天茫茫。", "爍迦羅，眼三角。", "舜若多，身十方。"]'),
('d9ad4e8f-ec31-4e58-9c0b-bfe21259b1a8','禪人并化主寫真求贊  其一六六','釋正覺','宋','宋诗','song-poetry','','[]','面目風霜，身心春陽。',40,'全唐诗/poet.song.102000.json','["面目風霜，身心春陽。", "用殺活之手段，整宗祖之紀綱。", "秋生野水魚潛穩，月在寒松鶴夢長。"]'),
('f757c9f6-0138-4e8c-ba5e-3ff5ddb2be9f','禪人并化主寫真求贊  其一六七','釋正覺','宋','宋诗','song-poetry','','[]','機鋒不敏，神觀不清。',49,'全唐诗/poet.song.102000.json','["機鋒不敏，神觀不清。", "一點寒灰後，三乘熱椀鳴。", "歷代祖咽喉把定，十方心手段放行。", "春風剪剪兮，物像英英。"]'),
('6fe0d196-8561-47c2-ab18-093e2e3b0f50','禪人并化主寫真求贊  其一六八','釋正覺','宋','宋诗','song-poetry','','[]','緘默之妙，本光自照。',51,'全唐诗/poet.song.102000.json','["緘默之妙，本光自照。", "鑑物之真，眼裏有筋。", "出氣之快，鼻頭有竅。", "見道之根，德象之要。", "處處相應兮，不餘不少。"]'),
('909c9015-65e8-4955-9771-d27beb6fc143','禪人并化主寫真求贊  其一六九','釋正覺','宋','宋诗','song-poetry','','[]','情態雲閒，身心月寒。',42,'全唐诗/poet.song.102000.json','["情態雲閒，身心月寒。", "鼻孔氣出快，髑髏津瀝乾。", "鱗龍遊躍兮雨翻雷吼，鯤鵬變化兮海運風摶。"]'),
('1c0fb5fd-63e9-4cdc-8bb2-422562dabc7f','禪人并化主寫真求贊  其一七○','釋正覺','宋','宋诗','song-poetry','','[]','妙處難傳，明明像先。',36,'全唐诗/poet.song.102000.json','["妙處難傳，明明像先。", "光凝雪月，秋連水天。", "百億分身隨應事，更嫌何處不周旋。"]'),
('2a31bc92-1da5-411b-a582-60e0c4ee1448','禪人并化主寫真求贊  其一七一','釋正覺','宋','宋诗','song-poetry','','[]','白髮寒巖雪，青眸古澗秋。',44,'全唐诗/poet.song.102000.json','["白髮寒巖雪，青眸古澗秋。", "身心明月磨田地，河漢清霜洗斗牛。", "識金鍮，用錐鈎，萬化區分拄杖頭。"]'),
('25fc3466-2f60-4b52-8c4d-bef3c6703a7b','禪人并化主寫真求贊  其一七二','釋正覺','宋','宋诗','song-poetry','','[]','靜據胡床，閒握柱杖。',36,'全唐诗/poet.song.102000.json','["靜據胡床，閒握柱杖。", "正念絕機絲，起家無伎倆。", "珠旋翡翠盤中，月在珊瑚枝上。"]'),
('374c7e8a-16a4-4679-b538-0a18f8389be5','禪人并化主寫真求贊  其一七三','釋正覺','宋','宋诗','song-poetry','','[]','默時說，說時默。',38,'全唐诗/poet.song.102000.json','["默時說，說時默。", "白雲無定心，青山有奇骨。", "半夜月移兮老兔推，百川潮落兮長鯨沒。"]'),
('9d4d5910-d5a2-42c3-af7c-7868b253beba','禪人并化主寫真求贊  其一七四','釋正覺','宋','宋诗','song-poetry','','[]','箇住山人，平生慣貧。',42,'全唐诗/poet.song.102000.json','["箇住山人，平生慣貧。", "寒枯青嶂骨，閑淡白雲身。", "無影樹頭兮露鶴夢月，不萌枝上兮華蜂採春。"]'),
('66515fce-f400-49af-97f9-0558b4d5e674','禪人并化主寫真求贊  其一七五','釋正覺','宋','宋诗','song-poetry','','[]','是箇人，欠精神。',50,'全唐诗/poet.song.102000.json','["是箇人，欠精神。", "家風青天沒四壁，事業白雲閒一身。", "古澗之津，枯木之春。", "水曲折而歸大海，華次第而趁芳辰。"]'),
('d6db5deb-f6be-4e05-a237-7d994bb63a43','禪人并化主寫真求贊  其一七六','釋正覺','宋','宋诗','song-poetry','','[]','默默而坐，佛祖勘破。',43,'全唐诗/poet.song.102000.json','["默默而坐，佛祖勘破。", "水冷魚潛，天空鳥過。", "半夜失却牛，平明拾得火。", "乍卷乍舒兮，無可不可。"]'),
('d52f8978-0b67-4efb-8ca3-944643261bdb','禪人并化主寫真求贊  其一七七','釋正覺','宋','宋诗','song-poetry','','[]','衲僧頂相，不可近向。',52,'全唐诗/poet.song.102000.json','["衲僧頂相，不可近向。", "俯而九淵之下，仰而重霄之上。", "以法界爲疆，以虛空爲量。", "鬧市裏釋提洹因，百草頭俱胝和尚。"]'),
('ab0cc878-81ec-4073-abbc-636598b42413','禪人并化主寫真求贊  其一七八','釋正覺','宋','宋诗','song-poetry','','[]','阿儂家風，至窮而通。',44,'全唐诗/poet.song.102000.json','["阿儂家風，至窮而通。", "豹變文而霧重，龍退骨而潭空。", "指南畫北，說西道東。", "點頭摇手，佯狂詐聾。"]'),
('ab9a91ba-2c6b-41c1-abf5-2ecc88eb6283','禪人并化主寫真求贊  其一七九','釋正覺','宋','宋诗','song-poetry','','[]','顛毛衰白，眸子寒青。',40,'全唐诗/poet.song.102000.json','["顛毛衰白，眸子寒青。", "閑口能吞佛，虛空解講經。", "古鑑出匣，太阿發硎，放得無依用得靈。"]'),
('189b8b3a-1a1f-4354-967e-6bcd00523d68','禪人并化主寫真求贊  其一八○','釋正覺','宋','宋诗','song-poetry','','[]','應現般般，初無異端。',48,'全唐诗/poet.song.102000.json','["應現般般，初無異端。", "春晝華麗，月明水寒。", "界方四稜榻地，珠圓一向走盤。", "呈似識與不識，請君急著眼看。"]'),
('de9fdeab-4842-4476-9ec1-ee185d755d16','禪人并化主寫真求贊  其一八一','釋正覺','宋','宋诗','song-poetry','','[]','深深沉沉，心不見心。',52,'全唐诗/poet.song.102000.json','["深深沉沉，心不見心。", "理亡出沒，妙超古今。", "錦機絲度密無縫，玉澗水流寒有音。", "友約寒山拾得子，拍手一笑舒胸襟。"]'),
('95069c84-8076-49e4-8489-d59c5f1787fc','禪人并化主寫真求贊  其一八二','釋正覺','宋','宋诗','song-poetry','','[]','動若出山雲，止如居谷神。',54,'全唐诗/poet.song.102000.json','["動若出山雲，止如居谷神。", "無心千種用，有應十方真。", "通氣相煩鼻孔，說禪不挂口唇。", "誰知默默坐中意，長養曇華劫外春。"]'),
('a8d9fe1e-a644-4cb8-a1d9-3751df5cf085','禪人并化主寫真求贊  其一八三','釋正覺','宋','宋诗','song-poetry','','[]','靜而神，默而真。',36,'全唐诗/poet.song.102000.json','["靜而神，默而真。", "方寸絕四壁，大千成一塵。", "拈來百草頭邊看，浩蕩華華葉葉春。"]'),
('c0022a5c-bbf4-4dbc-88bf-6b0638af0daa','禪人并化主寫真求贊  其一八四','釋正覺','宋','宋诗','song-poetry','','[]','貌悴情枯，雲閒月孤。',49,'全唐诗/poet.song.102000.json','["貌悴情枯，雲閒月孤。", "諸根影像有，百念肺腸無。", "毒蛇頭少人揩癢，猛虎口是誰捋鬚。", "有時變態兮，電卷雷驅。"]'),
('53a9f4f4-2dbc-44c6-b8bf-0bbc51f93922','禪人并化主寫真求贊  其一八五','釋正覺','宋','宋诗','song-poetry','','[]','默默工夫，心田自鋤。',52,'全唐诗/poet.song.102000.json','["默默工夫，心田自鋤。", "醭生唇上滿，泥斲鼻頭餘。", "少林何曾說話，曹溪不識文書。", "誰言伎倆渾無巧，自信家風也不疏。"]'),
('6e84c690-18ce-4eb0-a4c9-6ddd225b6983','禪人并化主寫真求贊  其一八六','釋正覺','宋','宋诗','song-poetry','','[]','湛而不渾，妙而長存。',36,'全唐诗/poet.song.102000.json','["湛而不渾，妙而長存。", "秋水何色，野雲無根。", "半夜天空河漢浄，老兔濯濯明月魂。"]'),
('6a693447-2524-4ec2-9003-4b4bf32e9344','禪人并化主寫真求贊  其一八七','釋正覺','宋','宋诗','song-poetry','','[]','寫出箇僧，冷淡無能。',52,'全唐诗/poet.song.102000.json','["寫出箇僧，冷淡無能。", "默耕田地，力鋤葛藤。", "入海泥牛絕消息，度河月兔有光稜。", "携去塵中成化事，更嫌何處不相應。"]'),
('fb0470de-d89b-4b11-ba97-2f4d1ac3d917','禪人并化主寫真求贊  其一八八','釋正覺','宋','宋诗','song-poetry','','[]','默守枯寒，心心見端。',36,'全唐诗/poet.song.102000.json','["默守枯寒，心心見端。", "瑠璃井秋光湛湛，珊瑚枝月影團團。", "髑髏活兮，妄識瀝乾。"]'),
('dc0792c7-06d4-4efa-a8f9-669920d05e39','禪人并化主寫真求贊  其一八九','釋正覺','宋','宋诗','song-poetry','','[]','靜而無像，動而無功。',38,'全唐诗/poet.song.102000.json','["靜而無像，動而無功。", "湛兮秋下水，應也樹頭風。", "到處隨緣成佛事，超情只箇是神通。"]'),
('a97a78f9-4b17-483d-8237-c6d2f6d7de32','禪人并化主寫真求贊  其一九○','釋正覺','宋','宋诗','song-poetry','','[]','視之其夷，聽之曰希。',54,'全唐诗/poet.song.102000.json','["視之其夷，聽之曰希。", "真聲真色，何是何非。", "春山潤而雲起，秋水澄而月歸。", "見聞斷痕而外分變化，功勳轉處而內盡玄微。"]'),
('04a1c850-321c-4a56-abeb-8e282055e7d8','禪人并化主寫真求贊  其一九一','釋正覺','宋','宋诗','song-poetry','','[]','兩眼碧，一面黄。',41,'全唐诗/poet.song.102000.json','["兩眼碧，一面黄。", "舌頭不掉，鼻孔難藏。", "老兔靜弄魄，靈犀通得光。", "歷歷機感兮，何用思量。"]'),
('22487503-6dfd-4db0-99fc-461703a829d0','禪人并化主寫真求贊  其一九二','釋正覺','宋','宋诗','song-poetry','','[]','披風兮崇丘，玩月兮方舟。',32,'全唐诗/poet.song.102000.json','["披風兮崇丘，玩月兮方舟。", "一身不羈兮太平時節，八紘無礙兮清白誰儔。"]'),
('99eb9df4-0c0c-4f5b-bb66-88dcd4fad5c9','禪人并化主寫真求贊  其一九三','釋正覺','宋','宋诗','song-poetry','','[]','閒雲之動，野水之流。',35,'全唐诗/poet.song.102000.json','["閒雲之動，野水之流。", "體萬像之平等，了一身而自由。", "機輪無滯兮，鑿枘相投。"]'),
('26443932-9740-4235-9474-f61b7629319a','禪人并化主寫真求贊  其一九四','釋正覺','宋','宋诗','song-poetry','','[]','五葉之華，三斤之麻，外無稜角兮中無孽芽。',66,'全唐诗/poet.song.102000.json','["五葉之華，三斤之麻，外無稜角兮中無孽芽。", "箭石不是虎，酒弓不是蛇，千里之失兮毫釐之差。", "得非思議兮自謂一曲之士，望絕涯畛兮人稱大方之家。"]'),
('4bc558a6-5386-4c0f-a7d5-7025748a8c6e','禪人并化主寫真求贊  其一九五','釋正覺','宋','宋诗','song-poetry','','[]','默默之語，如如絕慮。',40,'全唐诗/poet.song.102000.json','["默默之語，如如絕慮。", "野水有秋，閒雲無雨。", "十方三世兮無我安排，六道四生兮非吾行伍。"]'),
('1a243931-170a-43fa-b61c-3edb3a205aa7','禪人并化主寫真求贊  其一九六','釋正覺','宋','宋诗','song-poetry','','[]','智極而藏，靜極而光。',46,'全唐诗/poet.song.102000.json','["智極而藏，靜極而光。", "蕉雷之展，葵日之芳。", "占寶器而蠻眼碧，理華須而蜂股黄。", "中規中矩兮乍圓乍方。"]'),
('d838e256-16ae-4584-9c86-4708a849793b','禪人并化主寫真求贊  其一九七','釋正覺','宋','宋诗','song-poetry','','[]','一亙清虛，十分明白。',48,'全唐诗/poet.song.102000.json','["一亙清虛，十分明白。", "借兮是功，轉兮非色。", "天蓋地擎兮體之有餘，雷轟電掣兮用之不測，情未生時如何隔。"]'),
('5c3a0661-ee24-4ffe-8cf2-5d962985dead','禪人并化主寫真求贊  其一九八','釋正覺','宋','宋诗','song-poetry','','[]','洞見其顔，拈却案山。',64,'全唐诗/poet.song.102000.json','["洞見其顔，拈却案山。", "影流心鑑，智入道環。", "師曠不聞而其聲自普，離朱不辨而其色非慳。", "一點自然兮妙超過去現在，十方平等兮全該內外中間。"]'),
('c0cb9b1f-5e3d-489c-924a-eb54fc63488e','禪人并化主寫真求贊  其一九九','釋正覺','宋','宋诗','song-poetry','','[]','邈之不真，傳之不神。',70,'全唐诗/poet.song.102000.json','["邈之不真，傳之不神。", "得而無得，親而無親。", "體離微徹照之智，本蓋載生成之仁。", "出一二三之數量，等千百億之分身。", "用彌光也物中之眼，氣專柔也主中之賓。"]'),
('4095a397-d58d-47d9-8b58-72c1b63ab4a1','禪人并化主寫真求贊  其二○○','釋正覺','宋','宋诗','song-poetry','','[]','澄潭之月，蒼山之雪。',46,'全唐诗/poet.song.102000.json','["澄潭之月，蒼山之雪。", "清白家風，靈明事業。", "秋空浄無痕，野雲閑不徹。", "如今借問旁觀，且道看何行列。"]'),
('f7f84dfe-de50-42ea-a2ca-d9f09d342a2b','禪人并化主寫真求贊  其二○一','釋正覺','宋','宋诗','song-poetry','','[]','體之象先，得之自然。',44,'全唐诗/poet.song.102000.json','["體之象先，得之自然。", "心空有以，道大誰傳。", "蟾在珊瑚之樹，蚌藴明珠之淵，彈指分身兮三千大千。"]'),
('3915ba19-c53b-4933-893e-7279df569882','禪人并化主寫真求贊  其二○二','釋正覺','宋','宋诗','song-poetry','','[]','漆點兩眼，雪絲半頭。',40,'全唐诗/poet.song.102000.json','["漆點兩眼，雪絲半頭。", "嗒然亡耦，轉處還幽。", "一等高閑兮餘雲歛霽，十方清白兮片月摩秋。"]'),
('c4ca678f-7f3e-4a16-b052-6c9a51e63969','禪人并化主寫真求贊  其二○三','釋正覺','宋','宋诗','song-poetry','','[]','青山之主兮體本平等，白雲之賓兮用能自然。',38,'全唐诗/poet.song.102000.json','["青山之主兮體本平等，白雲之賓兮用能自然。", "應有餘兮神不可測，得其簡兮妙不可傳。"]'),
('f66743e0-e1f7-4dca-aa6c-09acc7b85076','禪人并化主寫真求贊  其二○四','釋正覺','宋','宋诗','song-poetry','','[]','秋山骨瘦，秋水神清。',38,'全唐诗/poet.song.102000.json','["秋山骨瘦，秋水神清。", "岩松寒更翠，澗月夜還明。", "靈然曲木坐不語，四海九州俱太平。"]'),
('4f0cf18e-26bc-47f2-925e-9a5ee150258a','禪人并化主寫真求贊  其二○五','釋正覺','宋','宋诗','song-poetry','','[]','面目古怪，氣宇深清。',50,'全唐诗/poet.song.102000.json','["面目古怪，氣宇深清。", "澗月夜白，松雪寒明。", "舜若之身兮誰前誰後，首羅之眼兮不縱不橫。", "相隨來也，流水浮萍。"]'),
('c307783c-d86a-4d6f-8f87-3ee0ed953543','禪人并化主寫真求贊  其二○六','釋正覺','宋','宋诗','song-poetry','','[]','天蒼蒼而雲閒，水深深而月寒。',28,'全唐诗/poet.song.102000.json','["天蒼蒼而雲閒，水深深而月寒。", "妙一點之自得，縱四辯以奚殫。"]'),
('a942dd83-2644-44f2-8e06-85026f76b357','禪人并化主寫真求贊  其二○七','釋正覺','宋','宋诗','song-poetry','','[]','鬚髮垂白，面皮淡黄。',60,'全唐诗/poet.song.102000.json','["鬚髮垂白，面皮淡黄。", "茶醒睡眼，飯塞饑腸。", "情田閑自廓，心地浄而光。", "雲歛山川雨，月明河漢霜。", "門門得用亡機械，箇事十成誰覆藏。"]'),
('098bc669-5845-4190-995b-d5e4b29dab4b','禪人并化主寫真求贊  其二○八','釋正覺','宋','宋诗','song-poetry','','[]','髮白而老，面黄仍病。',68,'全唐诗/poet.song.102000.json','["髮白而老，面黄仍病。", "窮地水火風之根，得見聞覺知之柄。", "一氣專柔，諸塵善應。", "魏臭而良，橘陳而令。", "盡大地藥了調和之治方，滿虛空身識起滅之緣性。"]'),
('bd228e66-7cac-420a-aaea-e3e17cae198c','禪人并化主寫真求贊  其二○九','釋正覺','宋','宋诗','song-poetry','','[]','靜而不紛，野而不文。',26,'全唐诗/poet.song.102000.json','["靜而不紛，野而不文。", "丘壑身心麋鹿共，江湖風月白鷗分。"]'),
('07b95996-c937-4f74-908e-3c3087b5dba7','禪人并化主寫真求贊  其二一○','釋正覺','宋','宋诗','song-poetry','','[]','全心之相，全相之心。',57,'全唐诗/poet.song.102000.json','["全心之相，全相之心。", "寫成這箇，聊應而今。", "天蒼蒼兮白鳥沒，水深深兮紅鱗沉。", "月鈎雲餌，玉線金針。", "一般料理兮，妙出威音。"]'),
('3daa1b57-b576-4f88-9fad-5375792a5393','禪人并化主寫真求贊  其二一一','釋正覺','宋','宋诗','song-poetry','','[]','是兮不是，別兮不別。',70,'全唐诗/poet.song.102000.json','["是兮不是，別兮不別。", "水冷涵秋，山寒带雪。", "傳家之印兮中間無文，常用之針兮兩頭無穴。", "遊世之身雲月閒，說禪之口河漢决。", "自然隨順因緣，向道不乖時節。"]'),
('f538a277-b67d-47f0-ba52-829dcf6bceb4','禪人并化主寫真求贊  其二一二','釋正覺','宋','宋诗','song-poetry','','[]','髮之白兮高峯早雪，目之青兮古澗先秋。',40,'全唐诗/poet.song.102000.json','["髮之白兮高峯早雪，目之青兮古澗先秋。", "月炯炯兮自有光通犀角，草蒼蒼兮誰能硬按牛頭。"]'),
('b0534f26-c698-4a04-beeb-1c6c4ed01b71','禪人并化主寫真求贊  其二一三','釋正覺','宋','宋诗','song-poetry','','[]','額顱高，眼孔深。',54,'全唐诗/poet.song.102000.json','["額顱高，眼孔深。", "畫工不識，誰是知音。", "江湖爛爛兮月還有魄，丘壑閑閑兮雲自無心。", "幾處相逢不會喚，蓑衣篛笠賣黄金。"]'),
('05fdac9e-56e2-4126-b050-30608cfdb7ee','禪人并化主寫真求贊  其二一四','釋正覺','宋','宋诗','song-poetry','','[]','器宇廓落，形像乾枯。',58,'全唐诗/poet.song.102000.json','["器宇廓落，形像乾枯。", "一點徹靈府，萬年空劫壺。", "青原門下識麟角，黄檗床頭捋虎鬚。", "死中還活兮活中還死，無中却有兮有中却無。"]'),
('a1613a12-a17f-4922-9d87-16e7604408ff','禪人并化主寫真求贊  其二一五','釋正覺','宋','宋诗','song-poetry','','[]','天庭寬而祖宗光，地閣闊而兒孫昌。',56,'全唐诗/poet.song.102000.json','["天庭寬而祖宗光，地閣闊而兒孫昌。", "中間鼻孔自家底，出氣通快渾不妨。", "坤六短，乾三長。", "飽叢林漢休雌黄，今年蠶食兩葉桑。"]'),
('37d91a59-dba0-4785-9237-ab849f7faaea','禪人并化主寫真求贊  其二一六','釋正覺','宋','宋诗','song-poetry','','[]','目瞳秋炯炯，顛髮雪毿毿。',50,'全唐诗/poet.song.102000.json','["目瞳秋炯炯，顛髮雪毿毿。", "飯塞肚皮飽，茶湔舌頰甘。", "齪家有彩，機事無堪。", "白牯釐奴却知有，而今贏得放癡憨。"]'),
('5ad080a6-233b-48fd-89b3-e4359897e26f','禪人并化主寫真求贊  其二一七','釋正覺','宋','宋诗','song-poetry','','[]','毗盧之口鬧嘈嘈，普賢之身閑飄飄。',42,'全唐诗/poet.song.102000.json','["毗盧之口鬧嘈嘈，普賢之身閑飄飄。", "理無不備，事不相饒。", "小舟點點浮煙水，柔柳垂垂映竹橋。"]'),
('f78a9794-8b97-49ed-afdf-b176d72b3934','禪人并化主寫真求贊  其二一八','釋正覺','宋','宋诗','song-poetry','','[]','何須魁斗之名高，不在山川之氣豪。',36,'全唐诗/poet.song.102000.json','["何須魁斗之名高，不在山川之氣豪。", "有口挂壁，亡牛奏刀。", "縱橫佛用，分付兒曹。"]'),
('b53f4661-5fac-491d-816f-e5c445ba67da','禪人并化主寫真求贊  其二一九','釋正覺','宋','宋诗','song-poetry','','[]','雲水性調，叢林氣高。',36,'全唐诗/poet.song.102000.json','["雲水性調，叢林氣高。", "肚皮束篾，版齒生毛。", "十方身虛空樣放，二升米拄杖頭挑。"]'),
('fa511a6b-5935-4d70-8398-519f80dad7a4','禪人并化主寫真求贊  其二二○','釋正覺','宋','宋诗','song-poetry','','[]','蒲寒柳衰，融懶顧癡。',74,'全唐诗/poet.song.102000.json','["蒲寒柳衰，融懶顧癡。", "坐穩實踰劫，心空佛是誰。", "明而了妙，微而入離。", "天清河漢闊，露冷斗杓垂。", "借伴而來應供，分身在處成規。", "百草頭邊春浩蕩，黄鶯之語對華枝。"]'),
('cd5cac90-a91d-4a29-95fe-2181892f0c7c','禪人并化主寫真求贊  其二二一','釋正覺','宋','宋诗','song-poetry','','[]','巖壑之骨窪而隆，煙霞之氣溫而融。',47,'全唐诗/poet.song.102000.json','["巖壑之骨窪而隆，煙霞之氣溫而融。", "其默而通，其應而沖。", "流雲出谷，霽月行空。", "十方三世兮，南北西東。"]'),
('83b9f25c-db29-4cbc-adb4-170e6855be55','禪人并化主寫真求贊  其二二二','釋正覺','宋','宋诗','song-poetry','','[]','清白之標，莊嚴匪銷。',52,'全唐诗/poet.song.102000.json','["清白之標，莊嚴匪銷。", "袁安卧雪，許由棄瓢。", "不萌枝上春苒苒，無影樹下秋寥寥。", "借伴入廛來買賣，相逢莫怪不相饒。"]'),
('4ecf3135-3859-47a4-884f-2274c6719583','禪人并化主寫真求贊  其二二三','釋正覺','宋','宋诗','song-poetry','','[]','眉目岩岩，身心靜恬。',60,'全唐诗/poet.song.102000.json','["眉目岩岩，身心靜恬。", "萬機自息，一默誰參。", "虛空兮霽雲卷谷，清白兮夜月濯潭。", "春入叢林兮謾道化工百億，神遊浩劫兮底意真超二三。"]'),
('a5f6c3c1-aa2d-44e7-8bc5-23477139a991','禪人并化主寫真求贊  其二二四','釋正覺','宋','宋诗','song-poetry','','[]','鼻直口闊，目深眉低。',52,'全唐诗/poet.song.102000.json','["鼻直口闊，目深眉低。", "燈連少室，派接曹溪。", "恰恰混不得，堂堂類不齊。", "把手共語，出力相携。", "春風浩浩，秋風凄凄。"]'),
('f5079e15-99ad-47cc-8bbb-02a2a73fd363','禪人并化主寫真求贊  其二二五','釋正覺','宋','宋诗','song-poetry','','[]','髮白面黄，鼻直口方。',64,'全唐诗/poet.song.102000.json','["髮白面黄，鼻直口方。", "雲水精神老，叢林氣味長。", "青蛇露時星爛爛，白鳥沒處煙蒼蒼。", "印空有據，印泥成章。", "家家門前柏樹子，豈獨趙州能對揚。"]'),
('5f5248b2-d909-4d58-83b4-cbbf95b020d0','禪人并化主寫真求贊  其二二六','釋正覺','宋','宋诗','song-poetry','','[]','兩眼深秀，雙眉下垂。',98,'全唐诗/poet.song.102000.json','["兩眼深秀，雙眉下垂。", "面目嚴冷，身心古錐。", "雲水盤遊，尋常夢於行脚。", "叢林寂默，三十年之住持。", "窮河漢於崑崙之椒，淵源親到。", "拈斗杓於混沌之外，佛祖猶疑。", "變通不倦，施設隨宜。", "向道剎塵機用穩，却嫌石火電光遲。"]'),
('38b7abf4-c949-4665-b6fd-2e8e9430d82d','禪人并化主寫真求贊  其二二七','釋正覺','宋','宋诗','song-poetry','','[]','髮雪衰白而春晝長，目光寒碧而秋波揚。',72,'全唐诗/poet.song.102000.json','["髮雪衰白而春晝長，目光寒碧而秋波揚。", "采華之滋而蜜蜂忙，齊物之夢而蝴蝶狂。", "體空影響，機動陰陽。", "玉燭靜調天事業，薰風披拂水文章。", "諸塵三昧，分身十方。"]'),
('89f4dde7-edab-4f7e-ac48-8fba450f47c7','禪人并化主寫真求贊  其二二八','釋正覺','宋','宋诗','song-poetry','','[]','眼橫鼻直，氣清骨寒。',92,'全唐诗/poet.song.102000.json','["眼橫鼻直，氣清骨寒。", "手眼外應金篦快，身心內照玉壺寬。", "機絲交織兮春華蔟蔟，與物齊平兮夢蝶團團。", "性習林泉，身心信緣。", "長虹歛雨，照雪倚天。", "頭頭物物隨宜說，剎剎塵塵各住禪。", "妙觸出礙，幻成自然。"]'),
('d9933498-3839-466f-96da-a1f7d01be430','禪人并化主寫真求贊  其二二九','釋正覺','宋','宋诗','song-poetry','','[]','無言而言，默徹其源。',48,'全唐诗/poet.song.102000.json','["無言而言，默徹其源。", "無用而用，虛含其動。", "理窟之窮通，智機之變弄。", "夕陽洲渚白鷗盟，韶晝園林蝴蝶夢。"]'),
('2985dd83-64ec-4881-b735-a0322e2e4dfa','禪人并化主寫真求贊  其二三○','釋正覺','宋','宋诗','song-poetry','','[]','功轉密藏，尋蹤跡以無方。',52,'全唐诗/poet.song.102000.json','["功轉密藏，尋蹤跡以無方。", "影現益彰，歷因緣而有常。", "身分塵剎普，舌拄梵天長。", "心心不觸菩提用，法法無依般若光。"]'),
('00a4c510-f0be-4b97-ad6e-8e098b087543','禪人并化主寫真求贊  其二三一','釋正覺','宋','宋诗','song-poetry','','[]','冥冥而覺，全真絕學。',86,'全唐诗/poet.song.102000.json','["冥冥而覺，全真絕學。", "海口自吞，駟舌須縮。", "圜混有光兮老蚌之胎，空同無物兮枯龜之殻。", "箇事而窮通，作家不啐啄。", "語出科模，用無稜角。", "叢林笑相看面也萎萎羸羸，三棒打不回頭也齷齷齪齪。"]'),
('379389a2-3c9e-444c-9641-6327feaabb3e','禪人并化主寫真求贊  其二三二','釋正覺','宋','宋诗','song-poetry','','[]','精神矍爍，化工模邈。',48,'全唐诗/poet.song.102000.json','["精神矍爍，化工模邈。", "我轉一機，誰持六鑒。", "是非生奪璧之謀，黑白戰爛柯之著。", "霽闊而河橫，潭空而月落。"]'),
('d98d6535-870c-429d-b275-769d857a5c65','禪人并化主寫真求贊  其二三三','釋正覺','宋','宋诗','song-poetry','','[]','性得淵源，窮通自然。',52,'全唐诗/poet.song.102000.json','["性得淵源，窮通自然。", "潭寒龍蛻骨，松老鶴成仙。", "無心白雲出岫，有應明月浮川。", "相逢借伴人間世，遊戲塵塵三昧緣。"]'),
('30be7463-7b09-43e9-9c6d-ac3d526359d9','禪人并化主寫真求贊  其二三四','釋正覺','宋','宋诗','song-poetry','','[]','髮鬚衰白而霜雪益深，肌膚蒼老而松桂剝皴。',40,'全唐诗/poet.song.102000.json','["髮鬚衰白而霜雪益深，肌膚蒼老而松桂剝皴。", "四十餘年而窮通一默，百千三昧而遊戲諸塵。"]'),
('1423cab5-cdfd-4324-b95c-12e02b803bd0','禪人并化主寫真求贊  其二三五','釋正覺','宋','宋诗','song-poetry','','[]','片月在水，孤雲出山。',50,'全唐诗/poet.song.102000.json','["片月在水，孤雲出山。", "其靜而應，其動而閒。", "體中不欲全露，用處只窺一斑。", "重重樓閣門開也，彌勒不須輕手彈。"]'),
('4fe9f479-326c-4ce5-acb8-6926a48f7bc8','禪人并化主寫真求贊  其二三六','釋正覺','宋','宋诗','song-poetry','','[]','岩岩之骨兮山癯，靡靡之姿兮水腴。',56,'全唐诗/poet.song.102000.json','["岩岩之骨兮山癯，靡靡之姿兮水腴。", "心無住而乃久，德有鄰而不孤。", "虛空說法，頑石聽徒。", "互換證明還了了，何煩佛祖費工夫。"]'),
('97c139d1-d6d8-4f0d-aaf7-96d3d171479b','禪人并化主寫真求贊  其二三七','釋正覺','宋','宋诗','song-poetry','','[]','鬚髮衰殘，空山雪寒。',72,'全唐诗/poet.song.102000.json','["鬚髮衰殘，空山雪寒。", "眉目清淡，野水秋還。", "一念萬年了塵劫，十方三世同正觀。", "翡翠天晴而清虛廓徹，珊瑚海月而光焰波瀾。", "現形說法應機感，笑指俱胝百草端。"]'),
('73395804-4d67-440e-9fc2-782fe750c31a','禪人并化主寫真求贊  其二三八','釋正覺','宋','宋诗','song-poetry','','[]','劫外遊神，環中契真。',62,'全唐诗/poet.song.102000.json','["劫外遊神，環中契真。", "幽靈自照，絕學爲鄰。", "碧瑠璃海半夜月，赤珊瑚樹長年春。", "專柔一氣，和光同塵。", "心心不觸衲僧事，物物無私國土身。"]'),
('2d68e70d-549c-4b03-9343-e4b78eee9206','禪人并化主寫真求贊  其二三九','釋正覺','宋','宋诗','song-poetry','','[]','靜之不昏，湛而若存。',80,'全唐诗/poet.song.102000.json','["靜之不昏，湛而若存。", "動之不渾，用而亡痕。", "入見離微之根，出遊幻化之門。", "赤水之求故罔象而珠得，庖丁之伎乃亡牛而刃奔。", "百川碧漲，三月紅繁。", "海不失於潮信，華自得於春恩。"]'),
('9eea8b4e-2db2-4859-8c8e-c8a96c508daa','禪人并化主寫真求贊  其二四○','釋正覺','宋','宋诗','song-poetry','','[]','白雲無根，青山有棱。',52,'全唐诗/poet.song.102000.json','["白雲無根，青山有棱。", "自得一句，妙出三乘。", "和氣而春回百草，光明而焰續千燈。", "淵默心傳諸佛體，家風獨許少林曾。"]'),
('462ce9bb-cf17-4534-83c4-f3fc2ae9326d','禪人并化主寫真求贊  其二四一','釋正覺','宋','宋诗','song-poetry','','[]','默而非緘，辨而罔談。',52,'全唐诗/poet.song.102000.json','["默而非緘，辨而罔談。", "須菩提慧空了了，憍尸迦華雨毿毿。", "更與剎塵分手眼，何妨機用見鎚鉗。", "箇人自得，古佛同參。"]'),
('332d4c7f-29e4-44bb-bc32-55d64ebef4df','禪人并化主寫真求贊  其二四二','釋正覺','宋','宋诗','song-poetry','','[]','雲無心而不羈，谷有應而相宜。',56,'全唐诗/poet.song.102000.json','["雲無心而不羈，谷有應而相宜。", "寂住通感，圓明了知。", "性汪洋而海有受，氣突兀而山不移。", "百年身後所須物，問取南陽忠國師。"]'),
('e432aa0b-be5e-4afb-878a-120a07daa72e','禪人并化主寫真求贊  其二四三','釋正覺','宋','宋诗','song-poetry','','[]','衰形老容，瘦竹蒼松。',48,'全唐诗/poet.song.102000.json','["衰形老容，瘦竹蒼松。", "野食丹山鳳，雲吟枯木龍。", "對機何似當臺鏡，扣應恰如隨杵鐘。", "了無一物，還我盧舂。"]'),
('8037474b-7f5c-486b-a435-3101aa07632f','禪人并化主寫真求贊  其二四四','釋正覺','宋','宋诗','song-poetry','','[]','癡鈍之師，枯槁之姿。',48,'全唐诗/poet.song.102000.json','["癡鈍之師，枯槁之姿。", "鼻寒垂涕，眼老生黐。", "玉懷石而矩，珠養蚌而規。", "長短華枝春次第，東西波棹月相隨。"]'),
('4366b11c-51a0-45b3-b723-a1efa2f2da49','禪人并化主寫真求贊  其二四五','釋正覺','宋','宋诗','song-poetry','','[]','雪髮霜髭，古岩阿師。',54,'全唐诗/poet.song.102000.json','["雪髮霜髭，古岩阿師。", "坐寒空劫眼，機活用時眉。", "文殊靠倒維摩詰，帝釋仰贊須菩提。", "如今喫飯下堂去，誰敢等閑欺石梯。"]'),
('f7ef7765-fdab-4b75-bbe6-79f4a744b303','禪人并化主寫真求贊  其二四六','釋正覺','宋','宋诗','song-poetry','','[]','秋生眉睫，雪積顛髮。',54,'全唐诗/poet.song.102000.json','["秋生眉睫，雪積顛髮。", "見偏正之往來，得離微之出沒。", "閒閒霽雨之雲，爛爛濯波之月。", "相隨來也入諸塵，妙觸門門自超越。"]'),
('bfa7e0b6-77fd-4d45-b165-fd68f1126227','禪人并化主寫真求贊  其二四七','釋正覺','宋','宋诗','song-poetry','','[]','遠山之雪兮髮毛衰白，大壑之秋兮眼稜寒碧。',70,'全唐诗/poet.song.102000.json','["遠山之雪兮髮毛衰白，大壑之秋兮眼稜寒碧。", "水雲肝膽兮佛世之燈，叢林事業兮祖宗之脈。", "龍梭錦機，金刀玉尺。", "諸塵三昧兮還我自由，二儀萬像兮與宅平出。"]'),
('0edf1170-4b44-4863-9214-1d5b2ed50349','禪人并化主寫真求贊  其二四八','釋正覺','宋','宋诗','song-poetry','','[]','千年氣溫，琥珀松根。',88,'全唐诗/poet.song.102000.json','["千年氣溫，琥珀松根。", "半夜光吞，珊瑚月魂。", "混沌鑿開，德雲下妙峯之頂。", "崑崙推倒，張騫到盟津之源。", "出岫之雲意閒暇，盈科之水流勢奔。", "諸塵歷歷，三昧門門。", "妙觸應緣還出礙，成家事業付兒孫。"]'),
('58ba108a-65d5-493b-8c41-712b852a7557','禪人并化主寫真求贊  其二四九','釋正覺','宋','宋诗','song-poetry','','[]','天與之形，月皎河橫。',48,'全唐诗/poet.song.102000.json','["天與之形，月皎河橫。", "地與之儀，山高水低。", "華燈連有據，桃李默成蹊。", "十方三世混不得，萬像森羅類莫齊。"]'),
('d43bebfd-2416-4fd8-bf5e-522ebd97be0d','禪人并化主寫真求贊  其二五○','釋正覺','宋','宋诗','song-poetry','','[]','天之空兮星斗寒，海之縮兮潮波還。',48,'全唐诗/poet.song.102000.json','["天之空兮星斗寒，海之縮兮潮波還。", "推月之蟾止三脚，養霧之豹窺一斑。", "拈出門門問相識，知音點頭應不慳。"]'),
('7401df25-d2e5-48cb-97e8-078f51a5635c','禪人并化主寫真求贊  其二五一','釋正覺','宋','宋诗','song-poetry','','[]','真見無形，真得無名。',62,'全唐诗/poet.song.102000.json','["真見無形，真得無名。", "全超影響，妙出塵情。", "夜冷露濡而斗濕，天空霽闊而河橫。", "無住而住，無生而生。", "相隨却到門門底，樓閣關開彈指聲。"]'),
('3dc3c77d-608d-4e94-a4f1-fe43c399d97c','禪人并化主寫真求贊  其二五二','釋正覺','宋','宋诗','song-poetry','','[]','松老有骨，竹癯無肉。',52,'全唐诗/poet.song.102000.json','["松老有骨，竹癯無肉。", "雪髮覆顛，霜眉映目。", "須菩提坐空而談，維摩詰卷辨而默。", "拈來何處不相逢，日面佛兮月面佛。"]'),
('3d3a170c-1bed-4297-8f65-235331b98f92','禪人并化主寫真求贊  其二五三','釋正覺','宋','宋诗','song-poetry','','[]','寒竹癯長，蒼松老剛。',46,'全唐诗/poet.song.102000.json','["寒竹癯長，蒼松老剛。", "身心鐵石，肝膽冰霜。", "秋天湛湛遠連水，賓雁冥冥初沒行。", "却來借伴，隨事成章。"]'),
('8527a65e-8de9-499e-a6ab-932fcd780a46','禪人并化主寫真求贊  其二五四','釋正覺','宋','宋诗','song-poetry','','[]','寫出老僧，形容可憎。',58,'全唐诗/poet.song.102000.json','["寫出老僧，形容可憎。", "秋生眼角，雪點眉稜。", "胸次有丘壑，口頭無葛藤。", "功忘自據菩提座，照盡誰傳般若燈。", "借光施設，恰恰相應。"]'),
('b347b5a2-4c0a-4a40-9faf-43792da66210','禪人并化主寫真求贊  其二五五','釋正覺','宋','宋诗','song-poetry','','[]','天童之師，頂雪頷絲。',50,'全唐诗/poet.song.102000.json','["天童之師，頂雪頷絲。", "三篾住山計，孤藤橫膝時。", "潭寒秋到早，空闊月行遲。", "提起宗家無字印，門門何處不相宜。"]'),
('85352ef4-f288-4e1f-b0fd-1e1a429b3d70','禪人并化主寫真求贊  其二五六','釋正覺','宋','宋诗','song-poetry','','[]','默而藏，妙而光。',44,'全唐诗/poet.song.102000.json','["默而藏，妙而光。", "月之輪窄，斗之柄長。", "扶來草木春濡綠，奪去山川霜落黄。", "相契可處，自然成章。"]'),
('3f0a0f8d-c74b-461c-8e7f-6c861949c4f7','禪人并化主寫真求贊  其二五七','釋正覺','宋','宋诗','song-poetry','','[]','雲水之身，叢林之人。',54,'全唐诗/poet.song.102000.json','["雲水之身，叢林之人。", "眉毛長蓋眼，鼻孔直欺唇。", "等閑西院兩聲錯，急快雲門一路親。", "不肯割城還奪璧，相如肝膽抑强秦。"]'),
('4b8a3646-50fd-4163-979b-9cdd65d99c9c','禪人并化主寫真求贊  其二五八','釋正覺','宋','宋诗','song-poetry','','[]','兀然而然，湛存象先。',68,'全唐诗/poet.song.102000.json','["兀然而然，湛存象先。", "曹溪昧橫畫，少室還默傳。", "體不匿而了了，用不勤而綿綿。", "得麟角兮石頭足，捋虎須兮林際顛。", "壁上如今謾撐起，知音自然聞說禪。"]'),
('436fdf67-2f37-4d7e-9dbc-a28df0e1bcaa','禪人并化主寫真求贊  其二五九','釋正覺','宋','宋诗','song-poetry','','[]','事不在容，智不到宗。',56,'全唐诗/poet.song.102000.json','["事不在容，智不到宗。", "待雲雷而陶壁梭蟄，授衣鉢而盧老逃舂。", "犀通半夜月，鶴夢千年松。", "白髮蒼顔跛挈公，時人相笑老龍鍾。"]'),
('4288f793-6901-4c1f-9b94-2d0002edda9d','禪人并化主寫真求贊  其二六○','釋正覺','宋','宋诗','song-poetry','','[]','槁木之形，谷神之靈。',42,'全唐诗/poet.song.102000.json','["槁木之形，谷神之靈。", "水冷看秋色，天空垂曉星。", "一點心明兮非臺之鏡，大千卷出兮破塵之經。"]'),
('bbd9d6fc-d406-44d1-9e21-670808ea00eb','禪人并化主寫真求贊  其二六一','釋正覺','宋','宋诗','song-poetry','','[]','源養而淵，燈傳未殘。',58,'全唐诗/poet.song.102000.json','["源養而淵，燈傳未殘。", "照分光燄，流演波瀾。", "暫時還落薄，客事豈艱難。", "春上燒瘢，綠生草端。", "無心爲潤雲行麓，有應不留珠走盤。"]'),
('9ab7a926-251c-482c-90e0-d72d18263af5','禪人并化主寫真求贊  其二六二','釋正覺','宋','宋诗','song-poetry','','[]','非思量處，無住而住。',64,'全唐诗/poet.song.102000.json','["非思量處，無住而住。", "離名象時，不爲而爲。", "香象定中渡，寒蟾照復移。", "世間了了虛空相，人事叢叢混沌眉。", "飽參底句如何舉，飯罷摩挲篾肚皮。"]'),
('8a08b128-f1e6-4750-8256-13c061911d25','禪人并化主寫真求贊  其二六三','釋正覺','宋','宋诗','song-poetry','','[]','出入離微，偏正之機。',58,'全唐诗/poet.song.102000.json','["出入離微，偏正之機。", "變通動靜，殺活之柄。", "飛流電火兮持林際之威權，函蓋乾坤兮得雲門之號令。", "相隨百草頭邊，恰恰初無欠剩。"]'),
('cb50c3b1-050d-4c25-ae39-d11ca08334d7','禪人并化主寫真求贊  其二六四','釋正覺','宋','宋诗','song-poetry','','[]','了心非相，了相是心。',52,'全唐诗/poet.song.102000.json','["了心非相，了相是心。", "皋禽夢寒琥珀樹，海月光射珊瑚林。", "影摇風竹，響發秋碪。", "萬像森羅俱演說，寶陀巖上有知音。"]'),
('00199ec9-1237-4e75-b889-16b27ff49245','禪人并化主寫真求贊  其二六五','釋正覺','宋','宋诗','song-poetry','','[]','寒淡相依，清白住持。',60,'全唐诗/poet.song.102000.json','["寒淡相依，清白住持。", "秋橫兩目，雪覆雙眉。", "老兔推月河漢闊，賓雁沒煙星斗垂。", "窮通有自，機用輸誰。", "消得而今一瞬，不須別喚沙彌。"]'),
('a05d39bc-3adc-4207-a8e9-085a5f6cb1cb','禪人并化主寫真求贊  其二六六','釋正覺','宋','宋诗','song-poetry','','[]','默默神澄，棱棱氣清。',94,'全唐诗/poet.song.102000.json','["默默神澄，棱棱氣清。", "河漢之月耿耿而不夜，蒹葭之風凄凄而有聲。", "相逢便說無生話，萬像森羅作證明。", "佛燈未寒，祖華未殘。", "其傳今到你，其事素來難。", "座須諸法空爲句，經在微塵破處看。", "而今呈似，莫道相謾。"]'),
('86a00e4f-4269-4360-af29-39bc0f57f6c8','禪人并化主寫真求贊  其二六七','釋正覺','宋','宋诗','song-poetry','','[]','妙出名象，非心非相。',48,'全唐诗/poet.song.102000.json','["妙出名象，非心非相。", "混融古今，是相是心。", "髮白曉霜厚，眼寒秋水深。", "寄語山形拄杖子，大家相伴做叢林。"]'),
('b9b9fc52-737a-47ab-9dd5-c2860cb08222','禪人并化主寫真求贊  其二六八','釋正覺','宋','宋诗','song-poetry','','[]','識得本真，不隨生滅。',20,'全唐诗/poet.song.102000.json','["識得本真，不隨生滅。", "霽雲磨空，秋波濯月。"]'),
('e777f053-816c-4d4c-b3df-a6826d723d2a','禪人并化主寫真求贊  其二六九','釋正覺','宋','宋诗','song-poetry','','[]','頭上有骨，眼底無肉。',42,'全唐诗/poet.song.102000.json','["頭上有骨，眼底無肉。", "分影月隨流，閒心雲出谷。", "萬緣圓應兮廓周大千，一點靈虛兮默照幽獨。"]'),
('b592be29-a1a4-4ba4-a7b5-7bdbed907a75','禪人并化主寫真求贊  其二七○','釋正覺','宋','宋诗','song-poetry','','[]','眼冷眉長，鼻直氣快。',42,'全唐诗/poet.song.102000.json','["眼冷眉長，鼻直氣快。", "彼彼常不輕，門門觀自在。", "寂光而無中，妙用而無外。", "誰怕肉團礙世界。"]'),
('17310ea7-85aa-42d8-a6a9-ded57b609b3b','禪人并化主寫真求贊  其二七一','釋正覺','宋','宋诗','song-poetry','','[]','智明而藏，浄極而光。',50,'全唐诗/poet.song.102000.json','["智明而藏，浄極而光。", "四大蛇非蟄，六窗猴不忙。", "因緣仍善應，機用更優長。", "覿面相逢出思議，自然隨處露堂堂。"]'),
('26ab84ba-114d-4193-b94e-53eeb90240fd','禪人并化主寫真求贊  其二七二','釋正覺','宋','宋诗','song-poetry','','[]','默而耀，虛而照。',44,'全唐诗/poet.song.102000.json','["默而耀，虛而照。", "借用不慳，合體無兆。", "石牛卧而青山寒，木馬嘶而明月曉。", "有底般人，相逢恰好。"]'),
('e790ed1e-c779-41f2-ad8e-60ff5e913061','禪人并化主寫真求贊  其二七三','釋正覺','宋','宋诗','song-poetry','','[]','雪洗寒岩兮山林氣清，秋生煙水兮江湖色明。',52,'全唐诗/poet.song.102000.json','["雪洗寒岩兮山林氣清，秋生煙水兮江湖色明。", "猶浄鏡兮對諸像，似空谷兮隨諸聲。", "遊戲因緣三昧用，自然轉處不留情。"]'),
('fa7a8943-1bdc-43a9-8fe4-9ea24c9a1ff4','禪人并化主寫真求贊  其二七四','釋正覺','宋','宋诗','song-poetry','','[]','眉眼分明，風柳柔青。',52,'全唐诗/poet.song.102000.json','["眉眼分明，風柳柔青。", "心膽純一，野華吐赤。", "了無物礙自由人，還得觀音妙智力。", "連城不割誰肯休，相如却奪秦王璧。"]'),
('69c8e7c6-d39f-4af5-bee6-0d458d5e053e','禪人并化主寫真求贊  其二七五','釋正覺','宋','宋诗','song-poetry','','[]','真非真，假非假。',50,'全唐诗/poet.song.102000.json','["真非真，假非假。", "是影是形，成幻成化。", "根門隨處拽得回，聲色自然騎與跨。", "耕翻海月之泥牛，遊遍春陽之木馬。"]'),
('58f36152-7227-41da-84e5-292dce6c9041','禪人并化主寫真求贊  其二七六','釋正覺','宋','宋诗','song-poetry','','[]','髮際點白，眼眶含青。',48,'全唐诗/poet.song.102000.json','["髮際點白，眼眶含青。", "情枯歷歷，智照靈靈。", "形骸如槁木，蹤跡肖流萍。", "月明四海犀通暈，春在百華蜂採馨。"]'),
('c8bcbd3e-2104-4c93-bb27-127df822eb20','禪人并化主寫真求贊  其二七七','釋正覺','宋','宋诗','song-poetry','','[]','棃杖橫膝，衲衣擁肩。',50,'全唐诗/poet.song.102000.json','["棃杖橫膝，衲衣擁肩。", "默爲佛事，情忘世緣。", "家風空掃四壁，活計冷坐三椽。", "見聞聲色外相討，破曉青山啼杜鵑。"]'),
('3bf2504a-5163-4651-b713-c79eeec9019c','禪人并化主寫真求贊  其二七八','釋正覺','宋','宋诗','song-poetry','','[]','是心絕緣，寒灰不然。',46,'全唐诗/poet.song.102000.json','["是心絕緣，寒灰不然。", "是身無我，芭蕉不堅。", "獨靈兮卓卓，湛存兮綿綿。", "春逐華枝長短，月隨水器方圓。"]'),
('09996c4c-9378-4846-bd4a-2b86f2791366','禪人并化主寫真求贊  其二七九','釋正覺','宋','宋诗','song-poetry','','[]','碧寒眼腦，黧黑面皮。',48,'全唐诗/poet.song.102000.json','["碧寒眼腦，黧黑面皮。", "佛魔銷鑠處，自己住持時。", "針或聯線，機不掛絲。", "風月渡河無夜色，水天連霽有秋姿。"]'),
('2114b463-b954-40a3-b482-d802c5ff4636','禪人并化主寫真求贊  其二八○','釋正覺','宋','宋诗','song-poetry','','[]','畫者不相出脫，轉見面皮醜惡。',56,'全唐诗/poet.song.102000.json','["畫者不相出脫，轉見面皮醜惡。", "蜂採百華春不饑，兔飲長河夜不渴。", "無事而禪，待緣而作。", "一機一警誰與知，百發百中絃銜筈。"]'),
('b2fbfb83-b2b3-4be4-ab76-14d57d803f09','禪人并化主寫真求贊  其二八一','釋正覺','宋','宋诗','song-poetry','','[]','是真非相，是相非真。',52,'全唐诗/poet.song.102000.json','["是真非相，是相非真。", "拈轉四大，不立一塵。", "體合虛空有自己，用周法界無別人。", "一葉落兮天下秋，一華開兮天下春。"]'),
('1a4c87ce-fbd6-47db-ad3e-76dfb30b3aa5','禪人并化主寫真求贊  其二八二','釋正覺','宋','宋诗','song-poetry','','[]','貧眉似促，饑眼覺大。',46,'全唐诗/poet.song.102000.json','["貧眉似促，饑眼覺大。", "口噤禪遊，鼻通氣快。", "心不萌箇處轉機，卦未兆阿誰來買。", "應世隨緣，齪家得彩。"]'),
('5d071f33-5161-4d92-99f5-ef315a7456b3','禪人并化主寫真求贊  其二八三','釋正覺','宋','宋诗','song-poetry','','[]','去就清貧，擔何苦辛。',52,'全唐诗/poet.song.102000.json','["去就清貧，擔何苦辛。", "兀默三椽老，平生五合陳。", "出家意謂了身，住院還相累人。", "野水連天半夜月，叢林和氣十方春。"]'),
('10928185-9d41-460b-a2c0-fe46f75faa98','禪人并化主寫真求贊  其二八四','釋正覺','宋','宋诗','song-poetry','','[]','顛髮山雪，眶瞳水秋。',45,'全唐诗/poet.song.102000.json','["顛髮山雪，眶瞳水秋。", "月白濯河漢，霽寒摩斗牛。", "韶意千華裏，光風百草頭。", "如幻三昧兮，妙得優遊。"]'),
('6e8fe159-d878-42b2-870e-0d014564ef22','禪人并化主寫真求贊  其二八五','釋正覺','宋','宋诗','song-poetry','','[]','默默無思，閒閒不羈。',44,'全唐诗/poet.song.102000.json','["默默無思，閒閒不羈。", "秋濯星河色，風吹月蕩漪。", "二儀前是我，萬像裏名誰。", "似難去取，决定相隨。"]'),
('b1470e28-a2f7-4db3-986d-ec1f7c8bb56c','禪人并化主寫真求贊  其二八六','釋正覺','宋','宋诗','song-poetry','','[]','額高眼深，該抹叢林。',46,'全唐诗/poet.song.102000.json','["額高眼深，該抹叢林。", "人驚大膽，我自無心。", "默轉機梭路，誰投鉢水針。", "覿面相呈了也，擡頭何處相尋。"]'),
('10e38a8a-9fc5-47c8-b154-532011e03f81','禪人并化主寫真求贊  其二八七','釋正覺','宋','宋诗','song-poetry','','[]','鎖口而禪，篾腹而餓。',61,'全唐诗/poet.song.102000.json','["鎖口而禪，篾腹而餓。", "透出劫空心相微，不見秋毫身量大。", "法憙爲食，法空爲座。", "毗耶門戶打開，少室家風覷破。", "言滿天下兮，而無口過。"]'),
('154747cf-1284-49c1-9d45-c3242962967e','禪人并化主寫真求贊  其二八八','釋正覺','宋','宋诗','song-poetry','','[]','據胡床，握麈柄。',66,'全唐诗/poet.song.102000.json','["據胡床，握麈柄。", "句中起倒，機頭偏正。", "真得出思議，妙應亡眺聽。", "徹二儀萬象根源，識諸佛歷代性命。", "曲直逆順兮任縱任橫，長短方圓兮何少何剩。"]'),
('5c53aedf-6aec-44e8-bcae-8e79d2546534','禪人并化主寫真求贊  其二八九','釋正覺','宋','宋诗','song-poetry','','[]','默握犛尾，誰撩虎鬚。',42,'全唐诗/poet.song.102000.json','["默握犛尾，誰撩虎鬚。", "天水連秋色，魁杓夜轉樞。", "應兮鑒像，答兮谷呼。", "森羅萬像，縱橫也俱。"]'),
('4b95ec80-cb7d-43d5-9090-98e4a7f5b296','禪人并化主寫真求贊  其二九○','釋正覺','宋','宋诗','song-poetry','','[]','百般千樣，會歸一相。',52,'全唐诗/poet.song.102000.json','["百般千樣，會歸一相。", "一相無相識也無，廓與虛空等其量。", "河淡秋清，夜寒月亮。", "提携出也來人間，明明歷歷諸緣上。"]'),
('1c5e8ab1-e3b8-4a1d-bcdc-cca8041c7126','禪人并化主寫真求贊  其二九一','釋正覺','宋','宋诗','song-poetry','','[]','性空無根，性水無垠。',48,'全唐诗/poet.song.102000.json','["性空無根，性水無垠。", "應所知量，成其夢身。", "閒閒對萬像，飄飄出諸塵。", "物外有此不名物，人間有此沒事人。"]'),
('612efda5-cd4c-44df-97e0-0e5bb4839617','禪人并化主寫真求贊  其二九二','釋正覺','宋','宋诗','song-poetry','','[]','面皮微紫，眸子深青。',36,'全唐诗/poet.song.102000.json','["面皮微紫，眸子深青。", "默臻閫奧，妙得門庭。", "徹見二儀成一體，明知萬像不他形。"]'),
('35fce840-2b62-44eb-a025-fa05ddbb94d7','禪人并化主寫真求贊  其二九三','釋正覺','宋','宋诗','song-poetry','','[]','幻起有形，智空無名。',36,'全唐诗/poet.song.102000.json','["幻起有形，智空無名。", "秋生月窟，雲變乾城。", "摩娑百戰胝瘢舊，向道而今老太平。"]'),
('7c16f1ad-36e6-4672-8ae7-a78de0bcdda7','禪人并化主寫真求贊  其二九四','釋正覺','宋','宋诗','song-poetry','','[]','皮蒼老松，色暗焦桐。',46,'全唐诗/poet.song.102000.json','["皮蒼老松，色暗焦桐。", "微塵塵破，一印印空。", "大千經卷鐘出礙，三世佛口谷吞風。", "六門了用，雙眉有功。"]'),
('53d3d5c3-bcd0-40b7-8346-99ea1020aa6a','禪人并化主寫真求贊  其二九五','釋正覺','宋','宋诗','song-poetry','','[]','雪顛未乾，秋波更寒。',64,'全唐诗/poet.song.102000.json','["雪顛未乾，秋波更寒。", "雲門舌不短，百丈鼻猶酸。", "心傳一燈自光燄，口翻四海看波瀾。", "間關半世，經歷百難。", "報道頭家休喝彩，而今雙六已居盤。"]'),
('d32be06d-60fe-4c8a-9c76-39033041ee5e','禪人并化主寫真求贊  其二九六','釋正覺','宋','宋诗','song-poetry','','[]','松老皮皴，竹癯節稜。',48,'全唐诗/poet.song.102000.json','["松老皮皴，竹癯節稜。", "髮白遠山雪，心明長夜燈。", "回機歷歷，隨用騰騰。", "因緣妙觸初無礙，箇是玲瓏岩下僧。"]'),
('9dc44a25-128e-4b6a-817a-6c957c0410d2','禪人并化主寫真求贊  其二九七','釋正覺','宋','宋诗','song-poetry','','[]','地水火風，因緣會同。',48,'全唐诗/poet.song.102000.json','["地水火風，因緣會同。", "見聞知覺，門戶疏通。", "隨宜而得用，及盡而亡功。", "明白機輪還自轉，相逢誰識大家翁。"]'),
('83c8bd26-e7a6-4fa7-926e-f3cab42bfe0a','禪人并化主寫真求贊  其二九八','釋正覺','宋','宋诗','song-poetry','','[]','野雪髮鬚，秋山肌膚。',60,'全唐诗/poet.song.102000.json','["野雪髮鬚，秋山肌膚。", "物齊芳蝶夢，情盡露蟬枯。", "跡弭水歸海，光回星轉樞。", "言前薦得猶封殻，喝下承當又觸途。", "天上天下，只箇規模。"]'),
('e2998021-95f6-45e4-be29-41d233510856','禪人并化主寫真求贊  其二九九','釋正覺','宋','宋诗','song-poetry','','[]','靜得其根，動應其門。',48,'全唐诗/poet.song.102000.json','["靜得其根，動應其門。", "家傳從佛祖，機用付兒孫。", "鑿開渾沌，派發崑崙。", "借與煙光成草木，華華葉葉氣溫溫。"]'),
('2ca53194-a0fd-43cf-8a59-5ec367a6108c','禪人并化主寫真求贊  其三○○','釋正覺','宋','宋诗','song-poetry','','[]','髮衰雪白，眼寒秋碧。',52,'全唐诗/poet.song.102000.json','["髮衰雪白，眼寒秋碧。", "壁立千尋，功消一色。", "體得有家風，心傳亡轍跡。", "少林祖師兮豈會唐言，黄梅行者兮不識橫畫。"]'),
('4c56bea6-b75a-4228-805b-312b57516f08','禪人并化主寫真求贊  其三○一','釋正覺','宋','宋诗','song-poetry','','[]','棱眉蒼厖，壑眼碧雙。',52,'全唐诗/poet.song.102000.json','["棱眉蒼厖，壑眼碧雙。", "未開蟄戶，誰識漳江。", "不須狡兔治三窟，自有孤猿應六窗。", "運水般柴呈妙用，兒孫事業更摐摐。"]'),
('08c50944-33f7-40ee-8cae-c6309d1bc977','禪人并化主寫真求贊  其三○二','釋正覺','宋','宋诗','song-poetry','','[]','雪髮霜鬚，風袖煙裾。',62,'全唐诗/poet.song.102000.json','["雪髮霜鬚，風袖煙裾。", "空殻累於可卜，木蠹偶以成書。", "豹霧之虎，龍雷之魚。", "變化復何日，升騰似有初。", "舊時行履故然改，向道而今井覷驢。"]'),
('82bbbdb1-b23e-40c2-a07f-4e87b758b55f','禪人并化主寫真求贊  其三○三','釋正覺','宋','宋诗','song-poetry','','[]','形聲幻爲，聞見智隨。',42,'全唐诗/poet.song.102000.json','["形聲幻爲，聞見智隨。", "自然出礙，平等何疑。", "瑩明而絕累，圓應而無疵。", "而今問你，且道是誰。"]'),
('d6bb18e7-d0bf-485a-ba66-fb33a549bd9b','禪人并化主寫真求贊  其三○四','釋正覺','宋','宋诗','song-poetry','','[]','霜之鬚，雪之顱。',60,'全唐诗/poet.song.102000.json','["霜之鬚，雪之顱。", "竹之腹，松之膚。", "河漢拍天岸，魁杓旋夜樞。", "珊瑚林月長鯨𩥇，琥珀松巢老鶴呼。", "竿頭絲線從君弄，不犯清波意自殊。"]'),
('7c84ead8-9783-4053-848e-d495c4422ef9','禪人并化主寫真求贊  其三○五','釋正覺','宋','宋诗','song-poetry','','[]','本無今有，覺空幻受。',58,'全唐诗/poet.song.102000.json','["本無今有，覺空幻受。", "真相儼然兮威音之前，妙觸出礙兮影響之後。", "功極而轉身，說禪而借口。", "把住也洞水逆流，放行也曹山顛酒。"]'),
('a666647b-7e00-4274-bf75-5879e29ea8c8','禪人并化主寫真求贊  其三○六','釋正覺','宋','宋诗','song-poetry','','[]','形骸槁如，林壑深居。',64,'全唐诗/poet.song.102000.json','["形骸槁如，林壑深居。", "衰髮雪松白，閒情霜竹虛。", "智遊空劫珠胎蚌，妙應因緣井覷驢。", "豹霧之虎，龍雷之魚。", "黄梅衣鉢繩繩信，盧老心傳不識書。"]'),
('6b7225e9-9530-476f-985c-6c8b438609c8','禪人并化主寫真求贊  其三○七','釋正覺','宋','宋诗','song-poetry','','[]','澗月之孤，岩松之癯。',64,'全唐诗/poet.song.102000.json','["澗月之孤，岩松之癯。", "秋生眉目，霜侵髮鬚。", "諸法之相了空寂，妙存之性非有無。", "一塵飛巨海，片雪點紅爐。", "應事頭頭俱出礙，自然妙觸解回途。"]'),
('3847780f-1ad8-43f9-913a-ccf1f113d5fc','禪人并化主寫真求贊  其三○八','釋正覺','宋','宋诗','song-poetry','','[]','兀兀堆堆，髑髏眼開。',36,'全唐诗/poet.song.102000.json','["兀兀堆堆，髑髏眼開。", "全身放下，借伴還來。", "一彈指響流通句，樓閣門門見善財。"]'),
('75c82540-20a0-4e8e-b02a-ead476fb5cbe','禪人并化主寫真求贊  其三○九','釋正覺','宋','宋诗','song-poetry','','[]','瘦骨岩岩，殘毳毿毿。',66,'全唐诗/poet.song.102000.json','["瘦骨岩岩，殘毳毿毿。", "坐寒雲巘，心空月潭。", "虛應亡機而若谷，深禪有口而如鉗。", "槃珠勿遺其色，囊錐不露其尖。", "皇道大平沒棱角，自然雨五而風三。"]'),
('69c29b70-8210-4fe3-abe2-1f4e9986d8b5','禪人并化主寫真求贊  其三一○','釋正覺','宋','宋诗','song-poetry','','[]','老抱孤蹤，歲寒之松。',50,'全唐诗/poet.song.102000.json','["老抱孤蹤，歲寒之松。", "靜含遠韻，霜曉之鐘。", "黄氏之羊起石，陶家之梭化龍。", "剎剎塵塵見身相，門門何處不相逢。"]'),
('a2a7b6f9-bb3f-46e7-863e-99c0b5150286','禪人并化主寫真求贊  其三一一','釋正覺','宋','宋诗','song-poetry','','[]','顛毛之絲，眼角之黐。',66,'全唐诗/poet.song.102000.json','["顛毛之絲，眼角之黐。", "是身頹老，與世支離。", "枯禪心了了，空劫鼻垂垂。", "曉寒霜結，山川薄霽。", "夜月行河漢，遲借伴還來。", "機用妙不銷，彈指知音知。"]'),
('4d19fb41-7ae9-4fcd-a10a-1d16dc3f8488','禪人并化主寫真求贊  其三一二','釋正覺','宋','宋诗','song-poetry','','[]','形衰柳蒲，心老江湖。',38,'全唐诗/poet.song.102000.json','["形衰柳蒲，心老江湖。", "魚潛波路靜，鶴夢月巢孤。", "不損色香三昧手，粉黏雙股理華鬚。"]'),
('35b03dd1-f847-475a-846a-9bccf0e29c44','禪人并化主寫真求贊  其三一三','釋正覺','宋','宋诗','song-poetry','','[]','高岩之雪兮顛毛衰白，遠水之秋兮眼棱寒碧。',66,'全唐诗/poet.song.102000.json','["高岩之雪兮顛毛衰白，遠水之秋兮眼棱寒碧。", "氣清夜永兮月低，斗冷河空兮露泣。", "借伴之機，起家之力。", "二儀萬像兮相與流通，十方三世兮自然平出。"]'),
('f0b3b4d0-f09c-474d-8ec0-cee41a36bb76','禪人并化主寫真求贊  其三一四','釋正覺','宋','宋诗','song-poetry','','[]','至微至精，無像無名。',52,'全唐诗/poet.song.102000.json','["至微至精，無像無名。", "其傳也默而成，其得也虛而盈。", "夜永斗柄轉，秋高河漢橫。", "人來借問正因字，鼠糞無將污我羹。"]'),
('2388900c-eb44-445f-90a0-e34da19fdc21','禪人并化主寫真求贊  其三一五','釋正覺','宋','宋诗','song-poetry','','[]','心空自靈，性了非情。',48,'全唐诗/poet.song.102000.json','["心空自靈，性了非情。", "玉馬寒泉飲，泥牛夜月耕。", "塵塵智起，物物幻成。", "二儀萬像縱橫說，相與今時作證明。"]'),
('4d234832-8093-42be-a619-29f755290236','禪人并化主寫真求贊  其三一六','釋正覺','宋','宋诗','song-poetry','','[]','顛毛衰薄，春山雪作。',84,'全唐诗/poet.song.102000.json','["顛毛衰薄，春山雪作。", "胸襟疏豁，海門潮落。", "眉稜高而眼深，鼻筒直而口闊。", "幽靈絕待兮曾傳祖禰之芳，谷神不死兮似得仙家之藥。", "相逢別峯，彈指開閣。", "憨皮袋截巷攔街，臭骨頭填溝塞壑。"]'),
('ff3bc3ab-5b5a-4778-a98f-1d51054bd276','禪人并化主寫真求贊  其三一七','釋正覺','宋','宋诗','song-poetry','','[]','青天無涯，白雲不羈。',38,'全唐诗/poet.song.102000.json','["青天無涯，白雲不羈。", "流水抱山轉，征人踏月歸。", "應以比丘得度者，箇般形像對來機。"]'),
('cfe08ec1-8da4-4c94-b1df-dbbe0111eb2d','禪人并化主寫真求贊  其三一八','釋正覺','宋','宋诗','song-poetry','','[]','野雲半肩，寒雪一顛。',52,'全唐诗/poet.song.102000.json','["野雲半肩，寒雪一顛。", "海樹珊瑚月，岩松琥珀年。", "眼合覓不見祖，心空初不留禪。", "森羅萬像縱橫說，相與證明輸我然。"]'),
('08b6da1a-4a01-4a59-8cc0-5bbc59e79dc3','禪人并化主寫真求贊  其三一九','釋正覺','宋','宋诗','song-poetry','','[]','內非可形，外還絕稱。',68,'全唐诗/poet.song.102000.json','["內非可形，外還絕稱。", "妙圓一句，通變諸乘。", "混十界心而靜其念，吞三世佛而空其膺。", "真機了了，祖意繩繩。", "偏去正來兮閑閑受用，圓規方矩兮恰恰相應。"]'),
('0c1dce3f-7dcb-4f16-a445-a2b97ced1c23','禪人并化主寫真求贊  其三二○','釋正覺','宋','宋诗','song-poetry','','[]','非默而默，不言而言。',48,'全唐诗/poet.song.102000.json','["非默而默，不言而言。", "鑿混沌朴，决崑崙源。", "萬像總持句，諸塵三昧門。", "法法心心成佛事，華華葉葉受春恩。"]'),
('f171120e-c288-4eaf-a495-c840262eaec0','禪人并化主寫真求贊  其三二一','釋正覺','宋','宋诗','song-poetry','','[]','了了智空，閑閑色融。',40,'全唐诗/poet.song.102000.json','["了了智空，閑閑色融。", "髑髏常干世界，鼻孔摩觸家風。", "湛湛河源翡翠碧，團團海日珊瑚紅。"]'),
('35d67936-1292-44a8-b764-a6c1e3964a86','禪人并化主寫真求贊  其三二二','釋正覺','宋','宋诗','song-poetry','','[]','默默道遊，靈靈破幽。',48,'全唐诗/poet.song.102000.json','["默默道遊，靈靈破幽。", "斗魁光轉夜，河漢氣澄秋。", "入世隨流，門庭甚休。", "青鞋蹈雨俱胝老，放浪風煙百草頭。"]'),
('d2b484c4-afb5-4e6e-b30e-c1506b9eb331','禪人并化主寫真求贊  其三二三','釋正覺','宋','宋诗','song-poetry','','[]','心心無住，了了有據。',48,'全唐诗/poet.song.102000.json','["心心無住，了了有據。", "河漢橫秋，斗柄濡露。", "須菩提坐禪，憍尸迦雨華。", "蚌含明月兔懷胎，勘破少林傳底句。"]'),
('ec4e89f3-1903-4af0-b957-45bf318d5d0e','禪人并化主寫真求贊  其三二四','釋正覺','宋','宋诗','song-poetry','','[]','相承次第，皮肉骨髓。',50,'全唐诗/poet.song.102000.json','["相承次第，皮肉骨髓。", "形分古佛家，氣出阿祖鼻。", "一根源既還，三昧塵全起。", "坦坦蕩蕩平等心，煒煒煌煌自然智。"]'),
('ada8cd78-4b5f-49db-82ed-c28a6635f373','禪人并化主寫真求贊  其三二五','釋正覺','宋','宋诗','song-poetry','','[]','鬚髮老而覆霜，心念浄而發光。',66,'全唐诗/poet.song.102000.json','["鬚髮老而覆霜，心念浄而發光。", "妙照混三世，幽靈空十方。", "口吞諸佛而不爲大，舌拄梵天而不覺長。", "剎塵無間說，鷗鳥不亂行。", "平等是道，自然成章。"]'),
('f9653b1d-c9ec-4d0c-b585-147d8dcd883d','禪人并化主寫真求贊  其三二六','釋正覺','宋','宋诗','song-poetry','','[]','妙明絕思，廓靜無涯。',48,'全唐诗/poet.song.102000.json','["妙明絕思，廓靜無涯。", "智空三際，性融二儀。", "借功光歷歷，借伴老垂垂。", "文彩縱橫成底事，機頭初不掛梭絲。"]'),
('7be8850c-0e73-46c4-bbef-6a87e70c0871','禪人并化主寫真求贊  其三二七','釋正覺','宋','宋诗','song-poetry','','[]','垂老之姿，鬚髮如絲。',48,'全唐诗/poet.song.102000.json','["垂老之姿，鬚髮如絲。", "淵默之味，耳口無疵。", "秋高河影闊，露冷月行遲。", "答呼若谷神之應，對事得珠色之隨。"]'),
('b7cd108f-7531-475c-b6a6-8c76bd8d823d','禪人并化主寫真求贊  其三二八','釋正覺','宋','宋诗','song-poetry','','[]','劫壺廓空，一句圓通。',52,'全唐诗/poet.song.102000.json','["劫壺廓空，一句圓通。", "苔生玉殿，體露金風。", "妙盡不知處，光回還借功。", "鑑像之緣而妙觸非受，谷神之應而隨呼不窮。"]'),
('318c4b68-4a84-4b79-84e6-b339af9f33d7','禪人并化主寫真求贊  其三二九','釋正覺','宋','宋诗','song-poetry','','[]','規圓矩方，鳧短鶴長。',24,'全唐诗/poet.song.102000.json','["規圓矩方，鳧短鶴長。", "落日煙村牧笛，平湖月夜魚榔。"]'),
('7816a584-7d05-477f-9a2a-f3efd357433f','禪人并化主寫真求贊  其三三○','釋正覺','宋','宋诗','song-poetry','','[]','法法平齊，隨高就低。',22,'全唐诗/poet.song.102000.json','["法法平齊，隨高就低。", "南日蜀葵向，北風胡馬嘶。"]'),
('2fddd392-afaa-4655-bcef-a36043f5378d','禪人并化主寫真求贊  其三三一','釋正覺','宋','宋诗','song-poetry','','[]','年齒垂垂，鬚髮絲絲。',62,'全唐诗/poet.song.102000.json','["年齒垂垂，鬚髮絲絲。", "月寒無影樹，春在未萌枝。", "得失折肱塞人馬，輸贏爛柯樵子棋。", "示現威儀而不起滅盡之定，不由心念而自然圓明之知。"]'),
('d8b5a3af-199a-429e-a5f8-f66111337b6f','禪人并化主寫真求贊  其三三二','釋正覺','宋','宋诗','song-poetry','','[]','髮雪毿毿，心老憨憨。',60,'全唐诗/poet.song.102000.json','["髮雪毿毿，心老憨憨。", "指南話北，破二作三。", "守宗風之符節，握佛祖之鎚鉗。", "陶形鑄器模楷妙，迸火流金爐鞴炎。", "光明不斷，燈燈夜龕。"]'),
('8bc64c30-09ec-4b2f-959b-6cbc54397d6a','禪人并化主寫真求贊  其三三三','釋正覺','宋','宋诗','song-poetry','','[]','學絕與鄰，名生實賓。',49,'全唐诗/poet.song.102000.json','["學絕與鄰，名生實賓。", "少年行脚事，老倒住山人。", "拄杖雖無二升米，虛空自有十方身。", "一機歷歷兮，三昧塵塵。"]'),
('316745d8-8f3c-4443-ba5d-47460c5efc80','禪人并化主寫真求贊  其三三四','釋正覺','宋','宋诗','song-poetry','','[]','說得一尺，行得一尺。',52,'全唐诗/poet.song.102000.json','["說得一尺，行得一尺。", "身非肉團，心如牆壁。", "用光眉十方，照世眼雙碧。", "諸塵三昧兮在我自然，萬像森羅兮與渠平出。"]'),
('f12f6444-f4ee-4ac2-ac90-27d190889e7b','禪人并化主寫真求贊  其三三五','釋正覺','宋','宋诗','song-poetry','','[]','巍巍堂堂，智不可量。',58,'全唐诗/poet.song.102000.json','["巍巍堂堂，智不可量。", "煒煒煌煌，靜自然光。", "松老西山雪，河明北斗霜。", "用之而行，舍之而藏。", "深林之晦三眠繭，繞指之柔百煉剛。"]'),
('1aeb4dce-9292-492c-90bf-f6666bada314','禪人并化主寫真求贊  其三三六','釋正覺','宋','宋诗','song-poetry','','[]','癯形老殘，孤節歲寒。',38,'全唐诗/poet.song.102000.json','["癯形老殘，孤節歲寒。", "照頂髑髏眼，隨緣赤肉團。", "六街三市尋人去，相喚門門盡是檀。"]'),
('e11ace08-7e04-4915-9eb2-f72f77a2c7d9','禪人并化主寫真求贊  其三三七','釋正覺','宋','宋诗','song-poetry','','[]','默成用密，智空理得。',26,'全唐诗/poet.song.102000.json','["默成用密，智空理得。", "歷代祖心選同科，三世佛口閑挂壁。"]'),
('28747c79-e31c-4245-ba86-6de4175d2767','禪人并化主寫真求贊  其三三八','釋正覺','宋','宋诗','song-poetry','','[]','老境侵尋，衰殘到今。',26,'全唐诗/poet.song.102000.json','["老境侵尋，衰殘到今。", "霜鬚雪髮春猶淺，壑眼岩眉秋更深。"]'),
('1a9c384d-8317-4e1e-a226-33a7e6f447e3','禪人并化主寫真求贊  其三三九','釋正覺','宋','宋诗','song-poetry','','[]','兀坐澗陰，潭空月沉。',52,'全唐诗/poet.song.102000.json','["兀坐澗陰，潭空月沉。", "三乘乘外，一印印心。", "師子循行師子吼，旃檀圍繞旃檀林。", "諸塵說法諸塵聽，莫道無人爲賞音。"]');
